fn_get_date_filter SQL_SCALAR_FUNCTION CREATE function [dbo].[fn_get_date_filter](
    @date_type_id smallint,
    @entity_type_id smallint = 0
) returns varchar(50) as
/*  Purpose:  Returns date time filter.    Notes:    History:  2012-01-25 bh initial development.  2012-04-03 bh update to use new lookup object: dim_year.  2012-09-24 bh update to use vw_time_lookup derived from dim_year but supports enity types.  2013-05-03 bh update to use formal dim_year table.  2016-02-17 bh when regs/sales in different years for sales time period (0=default).  */
begin
declare @filter varchar(50)
declare @ind_id varchar(100)
declare @sal_id varchar(100)
declare @dcn_id varchar(100)
set @ind_id = (
        select min(entity_id)
        from dim_year
        where entity_name = 'industry'
    )
set @sal_id = (
        select min(entity_id)
        from dim_year
        where entity_name = 'default'
    ) if (
        @entity_type_id = @ind_id
        and (
            select parm_value
            from app_config
            where parm_name = 'current_yr_start_sale'
        ) != (
            select parm_value
            from app_config
            where parm_name = 'current_yr_start_industry'
        )
    )
set @entity_type_id = @sal_id
set @filter = (
        select '(date_id >=' + ltrim(STR(start_date_id)) + ' and date_id <=' + ltrim(STR(end_date_id)) + ')'
        from dim_year
        where date_year_id = @date_type_id
            and entity_id = @entity_type_id
    ) return @filter
end sp_get_kpi SQL_STORED_PROCEDURE CREATE procedure [dcn].[sp_get_kpi] @kpi_id int,
@location_id int,
@debug char(1) = 'n' as begin
declare @sql varchar(1000)
declare @kpi_name varchar(100)
declare @obj varchar(100)
declare @type varchar(100)
declare @filter varchar(100)
declare @metric varchar(500)
declare @geo_value varchar(100) = @location_id
declare @geo_code varchar(100)
declare @geo_filter varchar(100) = 'location_id=<geo_value>'
declare @date_entity int
declare @date_id int
declare @date_filter varchar(100)
declare @order_by varchar(100)
declare @top varchar(100)
declare @metval real -- Get KPI parameters.  select   @kpi_name=kpi_name,  @obj=obj_name,  @type=obj_type,  @metric=metric,  @filter=obj_filter,  @date_id=time_id,@date_entity=time_entity,  @order_by=order_by  from dcn.kpi  where kpi_id = @kpi_id    select @geo_code=location_code  from dim_location  where location_id = @location_id    -- Compute complex KPI (Stored proc).  if (@type = 'S') begin   declare @nparm nvarchar(1000) = N'@metval real output'   declare @nsql nvarchar(1000)= @obj+' '+@geo_value++','+str(@date_id,2)+','+str(@date_entity,2)+',@metric=@metval output'     begin try    exec sp_executesql @nsql,@nparm,@metval=@metval output   end try   begin catch   end catch     set @metval = isnull(@metval,0)      set @sql = '   select '+str(@kpi_id,2)+' kpi_id,'''+@kpi_name+''' kpi_name,'+str(@metval,8,2)+' kpi'     exec sp_utl_exec @sql,@debug   return  end    -- Compuete simple KPI (query)  set @filter = isnull(@filter,'1=1')  set @geo_filter = 'location_id=<geo_value>'  set @geo_filter = replace(@geo_filter,'<geo_value>',@geo_value)  set @date_filter = dbo.fn_get_date_filter(@date_id,@date_entity)  set @date_filter = isnull(@date_filter,'1=1')     if (charindex('<dealer>',@filter) > 0) begin   set @geo_filter = replace(@filter,'<dealer>',''''+@geo_code+'''')   set @filter = '1=1'  end    if (@order_by is not null) begin   set @order_by = ' order by '+@order_by   set @top = 'top 1 '  end  else begin   set @order_by = ''   set @top = ''  end    set @sql = '  select '+@top+str(@kpi_id,2)+' kpi_id,'''+@kpi_name+''' kpi_name,'+@metric+' kpi from '+@obj+' where '+@filter+' and '+@geo_filter+' and '+@date_filter+@order_by    begin try   exec sp_utl_exec @sql,@debug  end try  begin catch   select @kpi_id kpi_id, @kpi_name kpi_name, 0 kpi  end catch  end  
    sp_get_pkg_state SQL_STORED_PROCEDURE CREATE procedure [dcn].[sp_get_pkg_state] @location_id int,
    @dept_id int,
    @user_id varchar(100) as
    /*  Purpose: Load Saved State Data if Present    History:  2024-06-05 ak initial development  */
    begin
set nocount on;
declare @state_cnt int
set @state_cnt = (
        select count(*)
        from dcn.pkg_state
        where location_id = @location_id
            and dept_id = @dept_id
            and insert_user_id = @user_id
    ) if @state_cnt = 0 begin
declare @exec_mgr varchar(max),
    @sales_mgr varchar(max),
    @parts_mgr varchar(max),
    @svc_mgr varchar(max),
    @base_emails varchar(max),
    @user_email varchar(max)
set @user_email = (
        case
            when @user_id like '%@%' then '{"name":"' + @user_id + '","value":"email","type":"0","data":""}'
            else ''
        end
    )
select @exec_mgr = (
        case
            when [Dealer Executive Manager Email] = 'N/A' then null
            else '{"name":"' + [Dealer Executive Manager Email] + '","value":"email","type":"0","data":""}'
        end
    ),
    @sales_mgr = (
        case
            when [Sales Manager Email] = 'N/A' then null
            else '{"name":"' + [Sales Manager Email] + '","value":"email","type":"0","data":""}'
        end
    ),
    @parts_mgr = (
        case
            when [Parts Manager Email] = 'N/A' then null
            else '{"name":"' + [Parts Manager Email] + '","value":"email","type":"0","data":""}'
        end
    ),
    @svc_mgr = (
        case
            when [Service Manager Email] = 'N/A' then null
            else '{"name":"' + [Service Manager Email] + '","value":"email","type":"0","data":""}'
        end
    )
from [ICTA_IDEAS_DWX].[dbo].[personnel_dlr] a
    join dim_location b on a.[Dealer Code] = b.location_code
where b.location_id = @location_id if @dept_id = 1 begin
select @base_emails = concat(
        '[',
(
            case
                when @user_email <> '' then @user_email + ','
                else ''
            end
        ),
        string_agg(x.email, ','),
        ']'
    )
from (
        select @exec_mgr email
        union
        select @sales_mgr
    ) x
end
else if @dept_id = 2 begin
select @base_emails = concat(
        '[',
(
            case
                when @user_email <> '' then @user_email + ','
                else ''
            end
        ),
        string_agg(x.email, ','),
        ']'
    )
from (
        select @exec_mgr email
        union
        select @parts_mgr
        union
        select @svc_mgr
    ) x
end
select '[{"value":""}]' pkg,
    '[{"value":""}]' kpi_pkg,
    @base_emails track_pkg,
    '{"value":""}' form_data
end
else begin
select pkg,
    kpi_pkg,
    track_pkg,
    form_data
from dcn.pkg_state
where location_id = @location_id
    and dept_id = @dept_id
    and insert_user_id = @user_id
end
end sp_get_report_default SQL_STORED_PROCEDURE CREATE procedure [dcn].[sp_get_report_default] @location_id int = null,
@dept_id int,
@user_id varchar(100),
@update_flag int as
/*  Purpose: Get report defaults.    History:  2022-01-28 bh initial development.  2024-05-31 ak update for new dealer visit design  */
begin
set nocount on;
/*  select report_ids  from dcn.report_default a  where a.dept_id = @dept_id and a.insert_user_id = @user_id  for json auto  */
if @update_flag = 0 begin with user_default as (
    select @user_id insert_user_id,
        @dept_id dept_id,
        @location_id location_id
)
select isnull(b.report_ids, isnull(c.report_ids, d.report_ids)) report_ids
from user_default a
    left join dcn.pkg_state b on a.dept_id = b.dept_id
    and a.insert_user_id = b.insert_user_id
    and a.location_id = b.location_id
    left join dcn.report_default c on a.dept_id = c.dept_id
    and a.insert_user_id = c.insert_user_id
    left join dcn.report_default d on a.dept_id = d.dept_id
    and d.insert_user_id = 'global' for json auto
end
else if @update_flag = 1 begin with user_default as (
    select @user_id insert_user_id,
        @dept_id dept_id
)
select isnull(c.report_ids, d.report_ids) report_ids
from user_default a
    left join dcn.report_default c on a.dept_id = c.dept_id
    and a.insert_user_id = c.insert_user_id
    left join dcn.report_default d on a.dept_id = d.dept_id
    and d.insert_user_id = 'global' for json auto
end
end sp_get_report_kpi SQL_STORED_PROCEDURE create procedure [dcn].[sp_get_report_kpi] @location_id int,
@dept_id int,
@user_id varchar(100) as
/*  Purpose: Get report KPIs.    History:  2021-09-22 bh initial development.  2023-07-13 bh update to use new KPI structure.  */
begin
set nocount on
select b.report_id,
    cast(a.kpi as smallint) status_id
from dcn.report_kpi a
    join dbo.rpt_report b on a.kpi_id = b.parm9
    and b.report_group = 'DealerContact'
    and a.location_id = @location_id
    and a.dept_id = @dept_id
end sp_kpi_017 SQL_STORED_PROCEDURE create procedure [dcn].[sp_kpi_017] @location_id int,
@time_id int,
@time_entity_id int,
@metric real = null output as begin -- YTD CSI Documentation Average (m93)  set nocount on  declare @ms real, @m0 real, @m1 real, @m2 real, @m3 real    /*  declare @res table(score real, m90 real, m91 real, m92 real, m93 real)  insert into @res(score,m90,m91,m92,m93) exec sp_utl_get_csi_metrics @location_id, @time_id  */    exec sp_utl_get_csi_metrics @location_id, @time_id, @ms output, @m0 output, @m1 output, @m2 output, @m3 output    select @metric=@m3   end  
