sp_kpi_033 SQL_STORED_PROCEDURE create procedure [dcn].[sp_kpi_033] @location_id int,
@time_id int,
@time_entity_id int,
@metric real = null output as begin
declare @d1 int,
    @d2 int,
    @m real
select @d1 = start_date_id,
    @d2 = end_date_id
from dim_year
where entity_id = @time_entity_id
    and date_year_id = @time_id
select @m =(
        case
            when isnull(m2, 0) = 0 then 0
            else m1 / dbo.fn_div(m2)
        end
    )
from (
        select sum(a.total_part_amount) m1
        from fact_part a
        where a.date_id between @d1 and @d2
            and location_id = @location_id
    ) a
    cross join (
        select sum(a.amount) m2
        from fact_objective a
        where a.date_id between @d1 and @d2
            and location_id = @location_id
    ) b
set @metric = isnull(@m, 0)
end sp_kpi_052 SQL_STORED_PROCEDURE -------------------------------------------------  create   procedure [dcn].[sp_kpi_052]   @location_id int,  @time_id int,  @time_entity_id int,  @metric real=null output  as   begin  -- Cross Sell (N-Series): if dealer has sold under 50% of what is sold in their market – FLAG.  set nocount on  declare @d1 int, @d2 int,@m real  declare @limit real = 0.5    select @d1 = start_date_id, @d2 = end_date_id  from dim_year   where entity_id = @time_entity_id and date_year_id = @time_id    IF OBJECT_ID('tempdb..##k052s1') IS NULL begin   select msa mkt,sum(units) u   into ##k052s1   from vw_fact_sale_customer a join geo_geo b on a.geo_id = b.geo_id   where date_id between @d1 and @d2   group by msa  end;    with cte as (  select b.location_id,sum(case when a.location_id = b.location_id then units else 0 end) u,max(msa) mkt  from fact_sale a join geo_geo b on a.geo_id = b.geo_id  where date_id between @d1 and @d2 and b.location_id = @location_id  group by b.location_id)    select @m = -1  from ##k052s1 a join cte b on a.mkt = b.mkt  where  ((1.0*b.u) / a.u) < @limit    --select isnull(@m,0) m  set @metric = isnull(@m,0)  end  
sp_kpi_053 SQL_STORED_PROCEDURE -------------------------------------------------  create   procedure [dcn].[sp_kpi_053]   @location_id int,  @time_id int,  @time_entity_id int,  @metric real=null output  as   begin  -- Registration Comparison: below District average registration penetration %.  set nocount on  declare @d1 int, @d2 int,@m real    select @d1 = start_date_id, @d2 = end_date_id  from dim_year   where entity_id = @time_entity_id and date_year_id = @time_id    IF OBJECT_ID('tempdb..##k053t1') IS NULL begin   select b.district,   100.0*sum(case when make_id in (1,2,7) then units else 0 end) / dbo.fn_div(sum(units)) rate   into ##k053t1   from fact_industry a join geo_geo b on a.geo_id = b.geo_id   where a.date_id between @d1 and @d2 and b.location_id > 0   group by b.district  end;    with cte as (  select b.location_id,district,  100.0*sum(case when make_id in (1,2,7) then units else 0 end) / dbo.fn_div(sum(units)) rate  from fact_industry a join geo_geo b on a.geo_id = b.geo_id  where date_id between @d1 and @d2 and b.location_id = @location_id  group by b.location_id,district)     select @m = -1  from ##k053t1 a join cte b on a.district = b.district  where b.rate  < a.rate    --select isnull(@m,0) m  set @metric = isnull(@m,0)  end  
sp_kpi_057 SQL_STORED_PROCEDURE -------------------------------------------------  create   procedure [dcn].[sp_kpi_057]   @location_id int,  @time_id int,  @time_entity_id int,  @metric real=null output  as   begin  -- Warranty Analysis: High % of OLH vs Reg Hours for Warranty Analysis -% Target TBD.  set nocount on  declare @m real  declare @limit real = 0.5    select @m =  (case when (1.0*sum(cast(olh_hour as int))/dbo.fn_div(sum(cast(regular_labor_hour as int)))) > @limit then -1 else 0 end)   from dwx.service_wty_analysis a join dim_location b on a.dealer  = b.location_code and b.location_id = @location_id    --select isnull(@m,0) m  set @metric = isnull(@m,0)  end  
sp_kpi_058 SQL_STORED_PROCEDURE -------------------------------------------------  create   procedure [dcn].[sp_kpi_058]   @location_id int,  @time_id int,  @time_entity_id int,  @metric real=null output  as   begin  -- Open Campaigns: Under x%  - What % is TBD.  set nocount on  declare @m real  declare @limit int = 30    select @m =(case when 100-max([%_completion]) > @limit then -1 else 0 end)  from dwx.service_open_camp a join dim_location b on a.dealer  = b.location_code and b.location_id = @location_id    --select isnull(@m,0) m  set @metric = isnull(@m,0)  end  
sp_kpi_061 SQL_STORED_PROCEDURE -------------------------------------------------  create procedure [dcn].[sp_kpi_061]   @location_id int,  @time_id int,  @time_entity_id int,  @metric real=null output  as   begin  -- Open TAL cases – if any over 3 months Old.  set nocount on  declare @m real  declare @limit int = 3    select @m =max(case when datediff(month,open_date,getdate()) > @limit then -1 else 0 end)  from dwx.service_open_tal a join dim_location b on a.dealer = b.location_code and b.location_id = @location_id    --select isnull(@m,0) m  set @metric = isnull(@m,0)  end  
sp_load_dcn_action_kpi SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_load_dcn_action_kpi] @debug char(1) = 'n' as
/*  Purpose: Load Dealer Contact (DCN) Action Item KPIs.    Notes:    History:  2023-07-22 bh initial implementation.  2025-02-18 bh update related to DCN (aka Dealer Visit) changes.  2025-03-04 bh update for minor improvement and issue with cursor.  */
begin
declare @sp_name varchar(100) = object_name(@@procid),
    @loc_id int,
    @pkg_id int,
    @dist varchar(1000),
    @items varchar(4000),
    @kpi_id int,
    @kpi_name varchar(100),
    @n int if (@debug = 'y') begin print @sp_name + ': debug not supported - existing.' return
end -- Loop through packages.  declare c0 cursor for  select b.pkg_id,b.location_id,b.items,a.distribution  from dcn.track a join pkg.contact_pkg b on a.pkg_id = b.pkg_id  where getdate() <= a.end_date  order by 1    open c0  fetch next from c0 into @pkg_id,@loc_id,@items,@dist  while (@@fetch_status = 0)  begin   -- Check if package has KPIs.   select @n=count(*)   from openjson(@items, '$')   with (n varchar(100) '$.name',       v varchar(1000) '$.value',     t varchar(100) '$.type',     d varchar(100) '$.data',     i varchar(100) '$.id')   where t=6     --select @pkg_id,@loc_id,@dist   -- Compute/save KPI.   if (isnull(@n,0) > 0) begin    exec dcn.sp_save_action_item_kpi @loc_id,@pkg_id,@items   end      fetch next from c0 into @pkg_id,@loc_id,@items,@dist  end     -- Cleanup.  close c0  deallocate c0  end  
sp_load_dcn_action_track SQL_STORED_PROCEDURE create procedure [dbo].[sp_load_dcn_action_track] @debug char(1) = 'n' as
/*  Purpose: Email Dealer Contact (DCN) Action Item KPIs.    Notes:    History:  2023-10-24 bh initial implementation.  2025-02-18 bh update related to DCN (aka Dealer Visit) changes.  2025-03-03 bh update for email format changes.  */
begin
declare -- Admin vars.  @sp_name varchar(100) = object_name(@@procid),  @msg varchar(2000),    -- Loc vars.  @loc_id int,  @loc_name varchar(100),    -- Pkg/KPI vars.  @pkg_id int,  @pkg_date smalldatetime,  @action_name varchar(100),  @kpi_id int,  @kpi_name varchar(100),  @kpi real,  @kpi_format varchar(10),  @date_id int,    -- Email vars.  @subject varchar(500),  @body varchar(4000),  @recip varchar(1000),  @test varchar(1000)    set nocount on    -- Check for test email.  set @test=(select parm_value from app_config where parm_name = 'dcn_test_email')    -- Loop through packages.  declare c0 cursor for  select b.pkg_id,b.pkg_date,a.distribution  from dcn.track a join pkg.contact_pkg b on a.pkg_id = b.pkg_id  where getdate() <= a.end_date and len(a.distribution) > 0  --and a.pkg_id = 930  order by 1    open c0  fetch next from c0 into @pkg_id,@pkg_date,@recip  while (@@fetch_status = 0)  begin   -- Get final distribution list.   set @recip = (case when len(@test) > 1 then @test else @recip end)   set @recip = replace(replace(@recip,', ,',';'),',',';')     -- Get KPIs for pkg.   drop table if exists ##kpi     set @date_id = (select max(date_id) from dcn.action_item_kpi where pkg_id = @pkg_id)      select    a.location_id,   c.location_name+' ('+c.location_code+')' loc_name ,   ai.action_id,   ai.action_name,   a.kpi_id,   b.kpi_name,   case    when kpi_unit = 'p' then 'P1'   when kpi_unit = 'i' then 'N0'   else 'N1'   end kpi_format,   a.kps   into ##kpi   from    dcn.action_item ai   join   dcn.action_item_kpi a on ai.action_id = a.action_id   join    dcn.kpi b on a.kpi_id = b.kpi_id   join   dim_location c on a.location_id = c.location_id   where a.pkg_id = @pkg_id and a.date_id = @date_id     if ((select count(*) from ##kpi) = 0) begin    --select '****'+str(@pkg_id)    fetch next from c0 into @pkg_id,@pkg_date,@recip    continue   end     --select * from ##kpi     -- Get location.   select top 1 @loc_id=location_id, @loc_name=loc_name from ##kpi     -- Build email msg per action item/kpi.   --declare @nl char(2) = CHAR(13) + CHAR(10)   declare @nl varchar(100) = '<br/>'   declare @bold1 varchar(100) = '<strong>', @bold2 varchar(100) = '</strong>'   set @subject = 'IDEAS Dealer Visit KPI Tracking for '+@loc_name   declare @date varchar(100) = format(@pkg_date,'MMMM dd, yyyy')   set @body = 'Following up from our visit '+@date +', this email provides an update of how KPIs discussed at our meeting have evolved from the date of the meeting through today.'+@nl   declare @cur_ai varchar(100) = ''      declare @par1 varchar(500) = @nl+@bold1+'We discussed improving <ai>.'+@nl+@bold2   declare @par2 varchar(500) = 'Your KPI <kpi> stood at <kpi1> from the date of the Dealer Visit and stands today at <kpi2>.'+@nl   declare @par3 varchar(500) = @nl+'Let’s work together to keep improving these metrics and continuing progress on our KPIs with <loc>. Ref # '+ltrim(str(@pkg_id))   declare @k1 real, @k2 real, @s1 varchar(1000), @s2 varchar(1000), @ks varchar(1000)      declare c1 cursor for   select action_name,kpi_id,kpi_name,kps,kpi_format   from ##kpi   order by action_name,kpi_name     open c1   fetch next from c1 into @action_name,@kpi_id,@kpi_name,@ks,@kpi_format   while (@@fetch_status = 0)   begin    if (@cur_ai <> @action_name) begin     set @cur_ai = @action_name     set @body = @body + replace(@par1,'<ai>',@cur_ai)    end      select @k1=isnull(kpi,0)    from dcn.action_item_kpi_min    where pkg_id = @pkg_id and kpi_id = @kpi_id      select @k2=isnull(kpi,0)    from dcn.action_item_kpi_max    where pkg_id = @pkg_id and kpi_id = @kpi_id      set @s1 = format(@k1,@kpi_format)    set @s2 = format(@k2,@kpi_format)      if (@kpi_name = 'custom') begin     set @s1 = 'See Note'     set @s2 = @ks    end      declare @k varchar(500) = replace(@par2,'<kpi>',@kpi_name)    set @k = replace(@k,'<kpi1>',@s1)    set @k = replace(@k,'<kpi2>',@s2)      set @body = @body + @k      fetch next from c1 into @action_name,@kpi_id,@kpi_name,@ks,@kpi_format   end   close c1   deallocate c1     set @body = @body + replace(@par3,'<loc>',@loc_name)     -- Send email.   if (@debug='n') begin    exec msdb.dbo.sp_send_dbmail     @profile_name = 'online',    @recipients = @recip,    @subject = @subject,    @body = @body,    @body_format = 'html'      set @msg = 'DCN: dbmail=pid='+ltrim(str(@pkg_id))+', sub='+@subject+', body='+@body+', rec='+@recip    insert into app_log(process_name,msg) values(@sp_name,@msg)      update a set     update_date = getdate()    from dcn.track a    where a.pkg_id = @pkg_id   end   else  begin    select @pkg_id kpi_id,@pkg_date pkg_date,@loc_name loc,@subject [subject],@body body,@recip recip   end      fetch next from c0 into @pkg_id,@pkg_date,@recip  end     -- Cleanup.  close c0  deallocate c0  end  
    sp_load_dcn_main SQL_STORED_PROCEDURE create procedure [dbo].[sp_load_dcn_main] @debug char(1) = 'n' as
    /*  Purpose: Main load process for Load Dealer Contact (DCN) KPIs.    Notes:    History:  2023-10-25 Initial development.  */
    begin
declare @sql varchar(4000)
set nocount on --exec sp_load_dcn_report_kpi @debug  exec sp_load_dcn_action_kpi @debug  exec sp_load_dcn_action_track @debug    end  
    sp_load_dcn_report_kpi SQL_STORED_PROCEDURE create procedure [dbo].[sp_load_dcn_report_kpi] @debug char(1) = 'n' as
    /*  Purpose: Load Dealer Contact (DCN) Report KPIs.    Notes:    History:  2021-10-27 Initial development.  2023-11-17 New implementation using table based KPIs (dcn.kpi).  2026-03-31 taw added logging for app_load_log  */
    begin
declare @sp_name varchar(100) = object_name(@@procid)
declare @sql varchar(4000)
declare @loc_id int,
    @loc_name varchar(100)
declare @kpi_id int,
    @dept_id int
set nocount on
set ansi_warnings off
DECLARE @start_date VARCHAR(100),
    @process_name VARCHAR(100),
    @src_table VARCHAR(100),
    @dst_table VARCHAR(100),
    @msg VARCHAR(4000);
SET @start_date = CONVERT(VARCHAR(100), GETDATE(), 120);
SET @process_name = OBJECT_NAME(@@PROCID);
SET @src_table = '[ICTA_IDEAS_App].[dcn].[report_kpi]';
SET @dst_table = '[ICTA_IDEAS_App].[dcn].[report_kpi]';
-- START LOG  EXEC dbo.sp_load_log     @dst_table = @dst_table,    @src_table = @src_table,    @start_date = @start_date,    @process_name = @process_name,    @msg = 'START',    @debug = 'n';    if (@debug='y') begin    print @sp_name+': debug not supported - existing.'    return   end     declare c1 cursor for   select location_id,location_name   from dim_location   where date_close is null and location_type=0 and location_id > 0     declare c2 scroll cursor for   select kpi_id,dept_id   from dcn.kpi   where kpi_type='r' and metric is not null     truncate table dcn.report_kpi     drop table if exists ##kpi     create table ##kpi(kpi_id int, kpi_name varchar(100), kpi real)     open c1   open c2     -- Process each location.   fetch next from c1 into @loc_id,@loc_name   while (@@fetch_status = 0)   begin    -- Process each KPI for location    fetch first from c2 into @kpi_id,@dept_id    while (@@fetch_status = 0)    begin     insert into ##kpi(kpi_id,kpi_name,kpi) exec dcn.sp_get_kpi @kpi_id,@loc_id       insert into dcn.report_kpi(location_id,dept_id,kpi_id,kpi)     select @loc_id,@dept_id,@kpi_id,kpi     from ##kpi       truncate table ##kpi         fetch next from c2 into @kpi_id,@dept_id    end    fetch next from c1 into @loc_id,@loc_name   end      -- Cleanup.   close c2   deallocate c2     close c1   deallocate c1     -- SUCCESS LOG  EXEC dbo.sp_load_log     @dst_table = @dst_table,    @src_table = @src_table,    @start_date = @start_date,    @process_name = @process_name,    @msg = 'SUCCESS',    @debug = 'n';    end  
sp_load_dspm_monthlyreport SQL_STORED_PROCEDURE CREATE PROCEDURE [dbo].[sp_load_dspm_monthlyreport] @debug char(1) = 'n' AS
/*  - Purpose: Develop a time-sequenced performance report for District Service & Parts Managers (DSPMs),    capturing monthly KPI scores and visualizing trends over time.    This initiative enables historical tracking, performance benchmarking, and strategic insight into DSPM effectiveness across districts.    - Historic Table Creation  - Table(s): [ICTA_IDEAS_App].[dbo].[dspm_monthlyreport] and [ICTC_IDEAS_App].[dbo].[dspm_monthlyreport]  - Purpose: Archive monthly DSPM KPI scores for longitudinal analysis    Notes:    History:  2025-11-20 taw initial development.  2026-03-31 taw added logging for app_load_log    */
BEGIN
SET NOCOUNT ON;
DECLARE @report_year int = YEAR(GETDATE());
DECLARE @report_month int = MONTH(GETDATE());
DECLARE @sql varchar(max)
DECLARE @date_filter VARCHAR(500);
DECLARE @date_id INT;
DECLARE @country varchar(3) = (
        select parm_value
        from app_config
        where parm_name = 'country'
    ) -- Get date_id   SELECT     @date_id = [date_id]   FROM [ICTA_IDEAS_App].[dbo].[dim_date]   WHERE [date_year] = @report_year and [date_month] = @report_month     -- Build dynamic filter string   SET @date_filter = 'date_id = ' + CAST(@date_id AS VARCHAR(10));     DECLARE @dlr_data_final_tbl varchar(max) = concat('##dlr_final_data_',replace(newid(),'-','_'))   DECLARE @dlr_rank_tbl varchar(max) = concat('##dlr_rank_',replace(newid(),'-','_'))   DECLARE @dlr_data_csi_tbl varchar(max) = concat('##dlr_data_csi_',replace(newid(),'-','_'))   DECLARE @dlr_data_training1_tbl varchar(max) = concat('##dlr_data_training_',replace(newid(),'-','_'))   DECLARE @dlr_data_fvpart_tbl varchar(max) = concat('##dlr_data_fvpart_',replace(newid(),'-','_'))   DECLARE @dlr_data_training2_tbl varchar(max) = concat('##dlr_data_training2_',replace(newid(),'-','_'))   DECLARE @dlr_data_partincentive_tbl varchar(max) = concat('##dlr_data_partincentive_',replace(newid(),'-','_'))   DECLARE @dlr_data_icdata_tbl varchar(max) = concat('##dlr_data_icdata_',replace(newid(),'-','_'))   DECLARE @dlr_data_downtime_tbl varchar(max) = concat('##dlr_data_downtime_',replace(newid(),'-','_'))   DECLARE @dlr_data_dealervisit_tbl varchar(max) = concat('##dlr_data_dealervisit_',replace(newid(),'-','_'))     -- LOGGING VARIABLES   DECLARE   @start_date VARCHAR(100),  @process_name VARCHAR(100),  @src_table VARCHAR(100),  @dst_table VARCHAR(100),  @msg VARCHAR(4000),  @dst_cnt INT;   SET @start_date = CONVERT(VARCHAR(100), GETDATE(), 120);  SET @process_name = OBJECT_NAME(@@PROCID);  SET @dst_table = '[dbo].[dspm_monthlyreport]'   -- Build dynamic SQL to count rows in destination table   SET @sql = N'SELECT @cnt = COUNT(*) FROM ' + QUOTENAME(@dst_table) + ';';     EXEC sp_executesql       @sql,      N'@cnt INT OUTPUT',      @cnt = @dst_cnt OUTPUT;    insert into app_load_log(process_name,msg,src_table,dst_table,dst_cnt,src_cnt,incr_cnt,start_date)  values(@process_name, 'Started','',@dst_table,@dst_cnt,0,0,@start_date)   -- END LOGGING VARIABLES     ---------------------------------------------------------------------------   -- DROP TEMP TABLES   ---------------------------------------------------------------------------   exec sp_utl_drop_table @dlr_data_final_tbl,@debug   exec sp_utl_drop_table @dlr_rank_tbl,@debug   exec sp_utl_drop_table @dlr_data_csi_tbl,@debug   exec sp_utl_drop_table @dlr_data_training1_tbl,@debug   exec sp_utl_drop_table @dlr_data_fvpart_tbl,@debug   exec sp_utl_drop_table @dlr_data_training2_tbl,@debug   exec sp_utl_drop_table @dlr_data_PartIncentive_tbl,@debug   exec sp_utl_drop_table @dlr_data_icdata_tbl,@debug   exec sp_utl_drop_table @dlr_data_downtime_tbl,@debug   exec sp_utl_drop_table @dlr_data_dealervisit_tbl,@debug     ---------------------------------------------------------------------------   -- BUILD TEMP TABLES (Part 1)   ---------------------------------------------------------------------------     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for total_csi   ---------------------------------------------------------------------------   SELECT     a.location_id,    AVG(dbo.fn_div_list(m02,m03,m05,m06,m13)) AS csi_cst_trt,    AVG(dbo.fn_div_list(m08,m12,NULL,NULL,NULL)) AS csi_rpr_exp,    AVG(dbo.fn_div_list(m01,m10,m11,NULL,NULL)) AS csi_sch_tim,    AVG(dbo.fn_div_list(m04,m07,NULL,NULL,NULL)) AS csi_doc_chg   INTO '+ @dlr_data_csi_tbl +'   FROM fact_csi_part a   JOIN dim_location b ON a.location_id = b.location_id   WHERE '+@date_filter+'   GROUP BY a.location_id;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for training   ---------------------------------------------------------------------------   SELECT     dealer,    (ISNULL(CAST(pcn_tech_cert AS FLOAT),0) + ISNULL(CAST(pcn_tech_handson AS FLOAT),0)) / 2 AS tech_train,    (ISNULL(CAST(pcn_parts_cert AS FLOAT),0) + ISNULL(CAST(pcn_partsmgr_cert AS FLOAT),0) +    ISNULL(CAST(pcn_partsrep_cert AS FLOAT),0) + ISNULL(CAST(pcn_serv_cert AS FLOAT),0) +    ISNULL(CAST(pcn_servadv_cert AS FLOAT),0) + ISNULL(CAST(pcn_servmgr_cert AS FLOAT),0) +    ISNULL(CAST(pcn_wtyadmin_cert AS FLOAT),0)) / 7 AS non_tech_train   INTO '+ @dlr_data_training1_tbl +'   FROM dwx.service_training a   JOIN dim_location b ON a.dealer = b.location_code   WHERE '+@date_filter+';'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for fv_to_part   ---------------------------------------------------------------------------   SELECT     a.location_id,    SUM(fleetvalue_amount) / SUM(total_part_amount) AS fv_to_part   INTO '+ @dlr_data_fvpart_tbl +'   FROM fact_part a   JOIN dim_location b ON a.location_id = b.location_id   WHERE '+@date_filter+'   GROUP BY a.location_id;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for more training   ---------------------------------------------------------------------------   SELECT    CONCAT(a.region,'' '',a.district,'' '',LastName) dspm_name,    iregion AS region,    iregion + idistrict AS district1,    SUM(CASE WHEN c.completion_flag = ''Y'' THEN 1.0 ELSE 0.0 END) AS completed_courses,    COUNT(c.course_no) * 1.0 AS total_courses   INTO '+ @dlr_data_training2_tbl +'   FROM dcn.district_mgr a   LEFT JOIN [ICTA_IDEAS_DWX].[dbo].[act_train_personnel] b ON a.email = b.user_email   LEFT JOIN [ICTA_IDEAS_DWX].[dbo].[act_train_learning] c ON b.user_id = c.user_id   WHERE a.role = ''District Service & Parts Manager'' AND country = '''+@country+'''   GROUP BY CONCAT(a.region,'' '',a.district,'' '',LastName), iregion, iregion + idistrict;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for Part Incentives    ---------------------------------------------------------------------------   SELECT     c.date_month,    b.location_id,    COUNT(a.rec_id) AS qty   INTO '+ @dlr_data_partincentive_tbl +'   FROM [ICTA_IDEAS_DWX].[dbo].part_incentives a   JOIN dim_location b ON a.[Primary Dealer Code] = b.location_code   JOIN dim_date c ON (SELECT MAX(date_id) FROM [ICTA_IDEAS_DWX].[dbo].part_incentives) = c.date_id   WHERE a.[Payment Code] = ''NPI''   AND a.[Payment Reference] IN (    ''FVWIPER25'',''FVDEF'',''FVDPF'',''FVTIRE25'',''FVBRAKES'',''FVWHEELSIM'',    ''MPITECH'',''MPIADV'',''FVDEF1'',''FVDPF1'',''FVTIRE1'',''FVBRAKES1'',''FVWHEELSIM1'',    ''FVOILSLS'',''MPTI'',''CHECKIN''    )   AND a.date_id >= (SELECT MIN(date_id) FROM dim_date WHERE date_year = YEAR(GETDATE()))   GROUP BY b.location_id, c.date_month;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   --build TEMP TABLE for LEFT JOIN for IC Case Info (primary contact and complaint description)   ---------------------------------------------------------------------------   SELECT     a.location_id,    1.0 * SUM(CASE     WHEN brand_flag = 1 AND LEN(complaint_description) > 1 AND     (primary_contact_email IS NOT NULL OR primary_contact_phone IS NOT NULL)    THEN 1 ELSE 0 END) /     SUM(CASE WHEN brand_flag = 1 THEN 1 ELSE 0 END) AS case_info   INTO '+ @dlr_data_icdata_tbl+'   FROM dwx.svc_cases a    JOIN dwx.svc_case_metrics b ON a.case_id = b.case_id   WHERE '+@date_filter+'   AND a.location_id > 0   AND a.location_id IN (    SELECT DISTINCT b.location_id    FROM [ICTA_IDEAS_DWX].[dbo].[personnel_dlr] a    JOIN dbo.dim_location b ON a.[dealer code] = b.location_code    WHERE a.[isuzu connect] = ''yes'' AND b.date_close IS NULL    )   GROUP BY a.location_id   HAVING SUM(CASE WHEN brand_flag = 1 THEN 1 ELSE 0 END) > 0;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for Downtime: Inactive 30+ Day    ---------------------------------------------------------------------------   SELECT     a.location_id,    1.0 * SUM(CASE     WHEN brand_flag = 1 AND dt_status_id = 0 AND DATEDIFF(DAY, update_date, GETDATE()) >= 30     THEN 1 ELSE 0 END) AS inactive   INTO '+ @dlr_data_downtime_tbl +'   FROM dim_location a   JOIN dwx.vehicle_downtime_hst b ON a.location_id = b.location_id AND b.country = '''+@country+'''   WHERE a.date_close IS NULL   GROUP BY a.location_id;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- build TEMP TABLE for LEFT JOIN for Completed Dealer Visit    ---------------------------------------------------------------------------   SELECT     a.location_id,    MONTH(GETDATE()) AS ytd_months,    SUM(CASE WHEN MONTH(pkg_date) = 1 THEN 1 ELSE 0 END) AS jan_visits,    SUM(CASE WHEN MONTH(pkg_date) = 2 THEN 1 ELSE 0 END) AS feb_visits,    SUM(CASE WHEN MONTH(pkg_date) = 3 THEN 1 ELSE 0 END) AS mar_visits,    SUM(CASE WHEN MONTH(pkg_date) = 4 THEN 1 ELSE 0 END) AS apr_visits,    SUM(CASE WHEN MONTH(pkg_date) = 5 THEN 1 ELSE 0 END) AS may_visits,    SUM(CASE WHEN MONTH(pkg_date) = 6 THEN 1 ELSE 0 END) AS jun_visits,    SUM(CASE WHEN MONTH(pkg_date) = 7 THEN 1 ELSE 0 END) AS jul_visits,    SUM(CASE WHEN MONTH(pkg_date) = 8 THEN 1 ELSE 0 END) AS aug_visits,    SUM(CASE WHEN MONTH(pkg_date) = 9 THEN 1 ELSE 0 END) AS sep_visits,    SUM(CASE WHEN MONTH(pkg_date) = 10 THEN 1 ELSE 0 END) AS oct_visits,    SUM(CASE WHEN MONTH(pkg_date) = 11 THEN 1 ELSE 0 END) AS nov_visits,    SUM(CASE WHEN MONTH(pkg_date) = 12 THEN 1 ELSE 0 END) AS dec_visits,    1.0 * COUNT(*) / MONTH(GETDATE()) AS dealer_visits   INTO '+ @dlr_data_dealervisit_tbl +'   FROM dim_location a   LEFT JOIN pkg.contact_pkg b ON a.location_id = b.location_id AND YEAR(b.pkg_date) = YEAR(GETDATE())   WHERE dept_id = 2   GROUP BY a.location_id;'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- Generate Metrics on a Dealer Level into '+@dlr_data_final_tbl+'   ---------------------------------------------------------------------------   select    a.location_id,    f.dspm_name,    CONCAT(trim(a.region),a.district2) as district1,    a.region,    isnull(j.dealer_visits,0) dealer_visits,    isnull(j.jan_visits,0) jan_visits,    isnull(j.feb_visits,0) feb_visits,    isnull(j.mar_visits,0) mar_visits,    isnull(j.apr_visits,0) apr_visits,    isnull(j.may_visits,0) may_visits,    isnull(j.jun_visits,0) jun_visits,    isnull(j.jul_visits,0) jul_visits,    isnull(j.aug_visits,0) aug_visits,    isnull(j.sep_visits,0) sep_visits,    isnull(j.oct_visits,0) oct_visits,    isnull(j.nov_visits,0) nov_visits,    isnull(j.dec_visits,0) dec_visits,    isnull(i.inactive,0) inactive,    h.case_info case_info,     avg(dbo.fn_div_list(b.csi_cst_trt,b.csi_doc_chg,b.csi_rpr_exp,b.csi_sch_tim,null)) total_csi,    isnull(sum(d.tech_train),0) tech_train,    isnull(sum(d.non_tech_train),0) non_tech_train,    isnull(e.fv_to_part,0) fv_to_part,    isnull(sum(g.qty),0) nat_incentive_count,    isnull(sum(g.date_month),0)*2 nat_incentive_bm,    (case when isnull(sum(g.qty),0) > isnull(sum(g.date_month),0)*2 then 1 else 0 end)*1.0 nat_incentive,    f.total_courses,    f.completed_courses,    isnull(sum(f.completed_courses),0.0)/(case when sum(f.total_courses) > 0.0 then sum(f.total_courses) else 1.0 end)*100 dspm_train   into '+ @dlr_data_final_tbl +'   from dim_location a    left join '+@dlr_data_csi_tbl+' b on a.location_id = b.location_id   left join '+@dlr_data_training1_tbl+' d on a.location_code = d.dealer   left join '+@dlr_data_fvpart_tbl+' e on a.location_id = e.location_id   left join '+@dlr_data_training2_tbl+' f on a.region = f.region and CONCAT(trim(a.region),a.district2) = f.district1   left join '+@dlr_data_PartIncentive_tbl+' g on a.location_id = g.location_id   left join '+@dlr_data_icdata_tbl+' h on a.location_id = h.location_id   left join '+@dlr_data_downtime_tbl+' i on a.location_id = i.location_id   left join '+@dlr_data_dealervisit_tbl+' j on a.location_id = j.location_id    where a.date_close is null and a.location_id <> 0   group by a.location_id ,f.dspm_name ,CONCAT(trim(a.region),a.district2) ,a.region    ,f.total_courses ,f.completed_courses ,h.case_info ,i.inactive ,j.dealer_visits    ,jan_visits ,feb_visits ,mar_visits ,apr_visits ,may_visits ,jun_visits    ,jul_visits ,aug_visits ,sep_visits ,oct_visits ,nov_visits ,dec_visits    ,fv_to_part'     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- Generate National Values as Ratio of Max Values into '+@dlr_rank_tbl+'   ---------------------------------------------------------------------------   select     location_id,    dspm_name,    region,    district1,    jan_visits,    feb_visits,    mar_visits,    apr_visits,    may_visits,    jun_visits,    jul_visits,    aug_visits,    sep_visits,    oct_visits,    nov_visits,    dec_visits,    dealer_visits,     dealer_visits / (select (case when max(dealer_visits) > 0 then max(dealer_visits) else 1 end)      from '+ @dlr_data_final_tbl +') nat_dealer_visits_rank,    inactive,     (case      when inactive >= 10 then 0.0     when inactive = 9 then 0.1     when inactive = 8 then 0.2     when inactive = 7 then 0.3     when inactive = 6 then 0.4     when inactive = 5 then 0.5     when inactive = 4 then 0.6     when inactive = 3 then 0.7     when inactive = 2 then 0.8     when inactive = 1 then 0.9     when inactive = 0 then 1.0     else 0.0     end ) nat_inactive_rank,    case_info,     case_info / (select (case when max(case_info) > 0 then max(case_info) else 1 end)      from '+ @dlr_data_final_tbl +'     where case_info is not null) nat_case_info_rank,    total_csi,    total_csi / (select (case when max(total_csi) > 0 then max(total_csi) else 1 end)      from '+ @dlr_data_final_tbl +') csi_nat_rank,    tech_train,    tech_train / (select (case when max(tech_train) > 0 then max(tech_train) else 1 end)      from '+ @dlr_data_final_tbl +') tech_train_nat_rank,    non_tech_train,    non_tech_train / (select (case when max(non_tech_train) > 0 then max(non_tech_train) else 1 end)      from '+ @dlr_data_final_tbl +') non_tech_train_nat_rank,    fv_to_part,    (case     when fv_to_part <= 0.015 then 0.00     when fv_to_part > 0.015 and fv_to_part <= .03 then 0.1     when fv_to_part > 0.03 and fv_to_part <= .045 then 0.2     when fv_to_part > 0.045 and fv_to_part <= .06 then 0.3     when fv_to_part > 0.06 and fv_to_part <= .075 then 0.4     when fv_to_part > 0.075 and fv_to_part <= .09 then 0.5     when fv_to_part > 0.09 and fv_to_part <= .105 then 0.6     when fv_to_part > 0.105 and fv_to_part <= .12 then 0.7     when fv_to_part > 0.12 and fv_to_part <= .135 then 0.8     when fv_to_part > 0.135 and fv_to_part < .15 then 0.9     when fv_to_part >= 0.15 then 1    end) fv_to_part_nat_rank,    nat_incentive_count,    nat_incentive_bm,    nat_incentive,    nat_incentive / (select (case when max(nat_incentive) > 0 then max(nat_incentive) else 1 end)      from '+ @dlr_data_final_tbl +') nat_incentive_nat_rank,    total_courses,    completed_courses,    dspm_train,    dspm_train / (select (case when max(dspm_train) > 0 then max(dspm_train) else 1 end)      from '+ @dlr_data_final_tbl +') dspm_train_nat_rank   into '+ @dlr_rank_tbl +'   from '+ @dlr_data_final_tbl +''     exec sp_utl_exec @sql, @debug     set @sql = '   ---------------------------------------------------------------------------   -- FINAL REPORT OUTPUT   ---------------------------------------------------------------------------   INSERT INTO [dbo].[dspm_monthlyreport]             ([country]             ,[DSPM]             ,[Region_Name]             ,[District]             ,[CSI]             ,[IC_Case_Info]             ,[Downtime_Inactivity]             ,[Dealer_Visits]             ,[DSPM_Training]             ,[District_Technical_Training]             ,[District_NonTechnical_Training]             ,[National_Incentives_Usage]             ,[FV_vs_OE_Parts_Purchasing]             ,[DSPM_Total_Score]       ,[Insert_Date]       ,[date_id])   SELECT    '''+@country+''' AS [country],    PARSENAME(REPLACE([dspm_name], '' '', ''.''), 1) AS [DSPM],    CASE      WHEN ''' + @country + ''' = ''USA'' AND [region] = 4 THEN ''Western''     WHEN ''' + @country + ''' = ''USA'' AND [region] = 3 THEN ''Southern''     WHEN ''' + @country + ''' = ''USA'' AND [region] = 2 THEN ''Northern''     WHEN ''' + @country + ''' = ''CAN'' AND [region] = 3 THEN ''Region 3''     WHEN ''' + @country + ''' = ''CAN'' AND [region] = 2 THEN ''Region 2''     WHEN ''' + @country + ''' = ''CAN'' AND [region] = 1 THEN ''Region 1''     ELSE ''UNKNOWN''     END AS [Region_Name],    RIGHT([district1], 1) AS [District],      CAST(ROUND(AVG([csi_nat_rank]) * 10, 1) AS DECIMAL(3,1)) AS [CSI],    CAST(ROUND(AVG([nat_case_info_rank]) * 10, 1) AS DECIMAL(3,1)) AS [IC Case Info],      CASE SUM([inactive])     WHEN 0 THEN 10.0     WHEN 1 THEN 9.0     WHEN 2 THEN 8.0     WHEN 3 THEN 7.0     WHEN 4 THEN 6.0     WHEN 5 THEN 5.0     WHEN 6 THEN 4.0     WHEN 7 THEN 3.0     WHEN 8 THEN 2.0     WHEN 9 THEN 1.0     ELSE 0.0    END AS [Downtime Inactivity],      CASE      WHEN SUM([dealer_visits]) >= 12 THEN 10.0     WHEN SUM([dealer_visits]) >= 10 THEN 9.0     WHEN SUM([dealer_visits]) >= 8  THEN 8.0     WHEN SUM([dealer_visits]) >= 7  THEN 7.0     WHEN SUM([dealer_visits]) >= 6  THEN 6.0     WHEN SUM([dealer_visits]) >= 5  THEN 5.0     WHEN SUM([dealer_visits]) >= 4  THEN 4.0     WHEN SUM([dealer_visits]) >= 3  THEN 3.0     WHEN SUM([dealer_visits]) >= 2  THEN 2.0     WHEN SUM([dealer_visits]) >= 1  THEN 1.0     ELSE 0.0    END AS [Dealer Visits],      CAST(ROUND(AVG([dspm_train_nat_rank]) * 10, 1) AS DECIMAL(3,1)) AS [DSPM Training],    CAST(ROUND(AVG([tech_train_nat_rank]) * 10, 1) AS DECIMAL(3,1)) AS [District Technical Training],    CAST(ROUND(AVG([non_tech_train_nat_rank]) * 10, 1) AS DECIMAL(3,1)) AS [District Non-Technical Training],      CASE      WHEN SUM([nat_incentive]) * 1.0 / NULLIF(COUNT([nat_incentive]), 0) >= 0.70 THEN 10     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.63 THEN 9     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.56 THEN 8     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.49 THEN 7     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.42 THEN 6     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.35 THEN 5     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.28 THEN 4     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.21 THEN 3     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.14 THEN 2     WHEN SUM([nat_incentive]) * 1.0 / COUNT([nat_incentive]) >= 0.07 THEN 1     ELSE 0    END AS [National Incentives Usage],      CAST(ROUND(AVG([fv_to_part_nat_rank]) * 10, 1) AS DECIMAL(3,1)) AS [FV vs OE Parts Purchasing],      ROUND(AVG((     [nat_dealer_visits_rank] * 10 +     [nat_inactive_rank] * 10 +     [nat_case_info_rank] * 10 +     [csi_nat_rank] * 10 +     [tech_train_nat_rank] * 10 +     [non_tech_train_nat_rank] * 10 +     [fv_to_part_nat_rank] * 10 +     [nat_incentive_nat_rank] * 10 +     [dspm_train_nat_rank] * 10     )), 1) AS [DSPM Total Score],    getdate() AS [Insert_Date],    ' + CAST(@date_id AS VARCHAR) + ' AS [date_id]   FROM '+ @dlr_rank_tbl +'   WHERE [location_id] IN (   SELECT DISTINCT [a].[location_id]   FROM [dim_location] [a]   JOIN [geo_geo] [b] ON [a].[geo_id] = [b].[geo_id]   WHERE [a].[location_id] <> 0   )   GROUP BY PARSENAME(REPLACE([dspm_name], '' '', ''.''), 1),   CASE      WHEN ''' + @country + ''' = ''USA'' AND [region] = 4 THEN ''Western''     WHEN ''' + @country + ''' = ''USA'' AND [region] = 3 THEN ''Southern''     WHEN ''' + @country + ''' = ''USA'' AND [region] = 2 THEN ''Northern''     WHEN ''' + @country + ''' = ''CAN'' AND [region] = 3 THEN ''Region 3''     WHEN ''' + @country + ''' = ''CAN'' AND [region] = 2 THEN ''Region 2''     WHEN ''' + @country + ''' = ''CAN'' AND [region] = 1 THEN ''Region 1''     ELSE ''UNKNOWN''     END,   RIGHT([district1], 1)'     exec sp_utl_exec @sql, @debug     -- LOGGING VARIABLES   -- Build dynamic SQL to count rows in destination table   SET @sql = N'SELECT @cnt = COUNT(*) FROM ' + QUOTENAME(@dst_table) + ';';     EXEC sp_executesql       @sql,      N'@cnt INT OUTPUT',      @cnt = @dst_cnt OUTPUT;    SET @start_date = CONVERT(VARCHAR(100), GETDATE(), 120);  insert into app_load_log(process_name,msg,src_table,dst_table,dst_cnt,src_cnt,incr_cnt,start_date)  values(@process_name, 'SUCCESS','',@dst_table,@dst_cnt,0,0,@start_date)   -- END LOGGING VARIABLES     /*   EXEC [dbo].[sp_load_dspm_monthlyreport] 'y'   */  END  
    sp_rpt_csi_appeal_form SQL_STORED_PROCEDURE create procedure [dbo].[sp_rpt_csi_appeal_form] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates report content for CSI appeal app.    Notes:  report_id = survey_id    Return data format based on format parm:  json (default)  xml  sql    History:  2022-06-22 bh initial development.  2023-03-09 bh update for move of data csi part into dwx schema.  2023-03-16 bh update to handle for country ref.  2023-03-25 bh update to handle no DSPM.  2023-03-30 bh update for editable fields (dealer contact/email).  2023-04-04 bh update to allow for nulls in csi calc.  2023-05-06 bh update to return "appeal" role.  2023-07-07 bh update to use formally defined CSI calcs from app_config.  2023-11-24 bh update to return additional CSI score.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @survey_id int,  @format varchar(100),    -- Query vars.  @sql varchar(4000),  @res varchar(100) = '##res'+replace(newid(),'-','_'),  @loc_id int,  @loc_code varchar(100),  @country varchar(100),  @region varchar(100),  @dist varchar(100),  @lcdate varchar(100),  @rodate varchar(100),  @dspm varchar(100),  @dspe varchar(100),  @dlrm varchar(100),@dlrm2 varchar(100),  @dlre varchar(100),@dlre2 varchar(100),  @lbme varchar(100),  @supe varchar(100),  @seq varchar(100),  @test varchar(100),  @vin varchar(100),  @m90 real, @m91 real, @m92 real, @m93 real, @tot real,  @csi_calc1 varchar(100),@csi_calc2 varchar(100),@csi_calc3 varchar(100),@csi_calc4 varchar(100),  @client varchar(100),  @role varchar(100),  @role2 varchar(100),  @pkg varchar(4000),  @lum varchar(100)  declare  @roles table(rolename varchar(100))    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @survey_id = @parms.value('/parms[1]/report_id[1]','int')  set @format = @parms.value('/parms[1]/format[1]','varchar(100)')    -- Get config parms.  set @country = (select parm_value from app_config where parm_name = 'country')    select @csi_calc1=substring(parm_value,5,50)  from app_config  where parm_name in('csi_metric_cat1')    select @csi_calc2=substring(parm_value,5,50)  from app_config  where parm_name in('csi_metric_cat2')    select @csi_calc3=substring(parm_value,5,50)  from app_config  where parm_name in('csi_metric_cat3')    select @csi_calc4=substring(parm_value,5,50)  from app_config  where parm_name in('csi_metric_cat4')    -- Return model (demo) report content for report designer.  -- N/A    -- Get format.  set @format = case   when @format = 'json' then 'for json path'   when @format = 'xml' then  'for xml path'   when @format = 'sql' then ''   else 'for json path'  end    -- Create form result table.  /*  f1 todays date  f2 Treatment (csi)  f3 Expectations (csi)  f4 Sched (csi)  f5 Total (csi)  f6 Ro date  f7 Survey rec date  f8 DSPM  f9 Dlr Name  f10 Dlr Code  f11 Dlr Contact (edit)  f12 Dlr Email (edit)  f13 Location_id  f14 DSPM (mgr1) email  f15 VIN  f16 user_id  f17 role  f18 LMB (mgr2) email  f19 Super (mgr3) email  f20 Approve seq (cnt)  f21 Time since last update (min)  f22 Appeal role (DSPM,LBM,Super)  f23 Doc (csi)  */  exec sp_utl_drop_table @res, @debug    set @sql = '  select *  into '+@res+'  from  rpt_tpl_csi_appeal_form'    exec sp_utl_exec @sql, @debug    -- CSI info.  select   @loc_id = location_id,  @lcdate = isnull(convert(char(10),cast(LastContactDate as smalldatetime),126),''),  @rodate = isnull(convert(char(10),cast([ro date] as smalldatetime),126),''),  @vin = isnull(vin,'')  from dwx.csi_part a  where rec_id = @survey_id    -- CSI scores.  declare @nsql nvarchar(1000),@nparm nvarchar(1000)    set @nsql = N'select   @p90='+@csi_calc1+'  @p91='+@csi_calc2+'  @p92='+@csi_calc3+'  @p93='+@csi_calc4+'  from fact_csi_part_all  where survey_id='+str(@survey_id)    set @nparm = N'@p90 real output,@p91 real output,@p92 real output,@p93 real output'      exec sp_executesql @nsql, @nparm, @p90=@m90 output, @p91=@m91 output,@p92=@m92 output,@p93=@m93 output    set @tot = isnull(dbo.fn_div_list(@m90,@m91,@m92,@m93,null),0)  set @m90=isnull(@m90,0)  set @m91=isnull(@m91,0)  set @m92=isnull(@m92,0)  set @m93=isnull(@m93,0)    -- DSPM.  select @region=region,@dist=left(region,1)+district2,@loc_code = location_code  from dim_location  where location_id = @loc_id    select @dspm = firstname+' '+lastname, @dspe = email  from dcn.district_mgr   where   country = @country  and iregion+idistrict = @dist   and role = 'District Service & Parts Manager'    --select *,region,left(region,1)+district2 from dim_location where location_id=1883 3 / 3  --select * from dwx.csi_part where rec_id=84289  --select * from dcn.district_mgr where country = 'can'    set @dspm = isnull(@dspm,'NODSPM')  set @dspe = isnull(@dspe,'NOE')    select @test = parm_value  from app_config a  where parm_name = 'csi_test_email1'    set @dspe = (case when len(@test) > 0 then @test else @dspe end)    -- LMB.  select @lbme = lookup_name  from geo_lookup  where entity_name = 'reglbm' and lookup_code = @region    --select * from geo_lookup where entity_name = 'reglbm'    select @test = parm_value  from app_config a  where parm_name = 'csi_test_email2'    set @lbme = (case when len(@test) > 0 then @test else @lbme end)  set @lbme = isnull(@lbme,'NOE')    -- Super.  select @supe = parm_value  from app_config a  where parm_name = 'csi_super_email'    select @test = parm_value  from app_config a  where parm_name = 'csi_test_email3'    set @supe = (case when len(@test) > 0 then @test else @supe end)    -- Dlr mgr.  select @dlrm=full_name,@dlre=email  from dcn.dealer_personnel  where   dealer = @loc_code  and (  (role = 'Dealer Executive Manager') or   (role = 'Dealer Principal') or   (role = 'Dealer Principal/Dealer Exec') or  (role = 'Dealer Principal/Sales Manager') or  (role = 'Service Manager')  )    set @dlrm = isnull(@dlrm,'NODM')  set @dlre = isnull(@dlre,'NOE')    select @pkg = items,@lum=datediff(mi,update_date,getdate())  from pkg.appeal_pkg  where pkg_id = @survey_id    select @dlrm2=value,@dlre2=data  from openjson(@pkg, '$')  with (name varchar(100) '$.name',      value varchar(100) '$.value',    data varchar(100) '$.data')  where name = 'contact'    set @dlrm = (case when len(@dlrm2) > 1 then @dlrm2 else @dlrm end)  set @dlre = (case when len(@dlre2) > 4 then @dlre2 else @dlre end)    select @test = parm_value  from app_config a  where parm_name = 'csi_test_email0'    set @dlre = (case when len(@test) > 0 then @test else @dlre end)    -- User.  set @client = (select parm_value from app_config where parm_name = 'client_initials')  insert into @roles(rolename) exec ASPNet.dbo.aspnet_UsersInRoles_GetRolesForUser @client, @user_id  set @role = (select top 1 rolename from @roles)  set @role = (case when @role is null or @user_id = 'test_dealer' then 'dealer' else @role end)    set @role2 = (case when dbo.fn_is_part_role(@role) > 0 or len(@role) = 2 then 'D' else null end)    if (@role2 is null)   set @role2 = (select top 1 'L'                 from geo_lookup a join vw_adm_user b on a.lookup_name = b.email                where entity_name='reglbm' and username = @user_id)     if (@role2 is null)   set @role2 = (case when charindex(@user_id,(select parm_value from app_config where parm_name = 'csi_super_email'),1) >0 then 'S' else '' end)    -- Appeal Seq.  select @seq = approve_seq  from pkg.appeal_pkg  where pkg_id = @survey_id    set @seq = isnull(@seq,0)    /*  select @survey_id,@m90,@m91,@m92,@tot  select @loc_id,@rodate,@lcdate,@dspm,@dlrm,@dlre,@loc_id,@dspe,@vin  select @user_id,@role,@role2,@lbme,@supe,@seq,@region  */    -- Apply info to result.  set @sql = '  update a set  id='+ltrim(str(@survey_id))+',  f01=convert(char(10),getdate(),126),  f02='+str(@m90,5,1)+',  f03='+str(@m91,5,1)+',  f04='+str(@m92,5,1)+',  f23='+str(@m93,5,1)+',  f05='+str(@tot,5,1)+',  f06='''+@rodate+''',  f07='''+@lcdate+''',  f08='''+@dspm+''',  f09=b.location_name,  f10=b.location_code,  f11='''+@dlrm+''',  f12='''+@dlre+''',  f13='+ltrim(str(@loc_id))+',  f14='''+@dspe+''',  f15='''+@vin+''',  f16='''+@user_id+''',  f17='''+@role+''',  f18='''+@lbme+''',  f19='''+@supe+''',  f20='''+@seq+''',  f21='+isnull(@lum,0)+',  f22='''+@role2+'''  from '+@res+' a cross join dim_location b  where b.location_id = '+str(@loc_id)    exec sp_utl_exec @sql, @debug    -- Return result.  set @sql = '  select *  from '+@res+' '+@format    exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0  
    sp_rpt_dcn_backorder_service SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_backorder_service] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: Backorders for Dealer Visit  Notes: this has no dates as of now and is showing all activitve back orders    History:  2024-04-12 DD Initial Development.  2024-08-15 bh update for schema level usd to cad conversion ONLY!!! for tables used in reports. Minor cleanup.  2026-03-31 mh use insert_date year for filtering  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    -- Query vars.  @sql varchar(4000),  @location_code varchar(6),  @sch varchar(100),    --table name  @back_order_table Varchar(max) = 'dwx.part_backorder',  @date_table varchar(max) = 'dim_date'    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    -- Build report query.  set @location_code = (select location_code from dim_location where location_id = @geo_value)  select @sch = isnull(parm0,'dwx') from rpt_report where report_id = @report_id  set @back_order_table = replace(@back_order_table,'dwx',@sch)    declare @year varchar(10)  select @year = [date_year] from dim_year where entity_id = 8 and date_year_id = @date_type_id        if @rpt_lvl = 1  begin   set @sql =    '    select  round(sum(dnp * boqty),0) ''total_back_orders''    from '+@back_order_table+'    where dlrcd = '''+@location_code+'''    and year(insert_date) = '''+@year+'''    '  end  else if @rpt_lvl = 2  begin   set @sql =   '   select    dlrcd   , dlrOrdNo   , orddte   , ordref   , ordpart   , fillcode   , boqty   , [desc]   , mac   , hof   , upgradeflag   , [dnp]   , [boremarks1]    , [boremarks2]   , [boremarks3]   , [cccrRemarks1]   , [cccrRemarks2]   , [cccrRemarks3]   , [cccrDate]   , [cccrTime]   from '+@back_order_table+'   where dlrcd = '''+@location_code+'''   and year(insert_date) = '''+@year+'''   '  end    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_backorder_Service] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 1  exec [sp_rpt_dcn_backorder_Service] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */  
    sp_rpt_dcn_ci_overview SQL_STORED_PROCEDURE CREATE Procedure [dbo].[sp_rpt_dcn_ci_overview] @parms xml = null,
