    /*  Purpose:    Notes:    History:  2023-12-15 DD initial development.  2026-03-18 taw added guard to ensure this does not fail when state is geography selected for report EV Readiness Dashboard  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),    --table name  @infotable varchar(max)      -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    -- Guard clause: management_overview is Dealer-only  IF @geo_type_id <> 1  BEGIN      SELECT geo_type_id = @geo_type_id;      RETURN;  END;    set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'location_id = '''+@geo_value+''''  set @infotable = 'dim_location_metric'    select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @sql =  '  select   coe_cert  , isuzu_connect  , cummins_cert  , allison_cert  from '+@infotable+'  where '+@dealer_filter+'  '    -- Execute.  exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)    end  return 0    --test parm  /*  exec [dbo].[sp_rpt_dcn_CI_overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'N'  */  
    sp_rpt_dcn_coe_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_coe_overview] @parms xml = null,
    @debug char(1) = 'n',
