    /*  Purpose: Backorders for Dealer Visit  Notes: this has no dates as of now and is showing all activitve back orders    History:  2024-04-12 DD Initial Development  2026-01-06 DD added a display flag column (if over 313 which is jan 2026 then no display for 0 and display for 1)  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),      --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_filter3 varchar(max),    --table name  @COE_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 0)  set @COE_table = 'ICTA_IDEAS_DWX.[dbo].[dlr_coe]'  set @date_table = 'dim_date'  set @date_filter = '(a.date_id between '+@date1+' and '+@date2+')'  set @date_filter2 = '(date_id between '+@date1+' and '+@date2+')'  set @date_filter3 = '(select max(date_id) from [dcn].[dlr_coe] where date_id <='+@date2+') between '+@date1+' and '+@date2+' '      if @rpt_lvl = 1  begin  set @sql =  '  select   location_name  , coe_flag  , case when '+@date2+' >= 313 then 0 else 1 end ''display_flag''  from '+@COE_table+'  where location_code = '''+@location_code+''' and date_id = (select max(date_id) from '+@COE_table+' where date_id between '''+@date1+''' and '''+@date2+''')  '  end  if @rpt_lvl = 2  begin     set @sql = '  select   *  , case when '+@date2+' >= 313 then 0 else 1 end ''display_flag''  from '+@COE_table+'  where location_code = '''+@location_code+''' and date_id = (select max(date_id) from '+@COE_table+' where date_id between '''+@date1+''' and '''+@date2+''')     '  end    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [dbo].[sp_rpt_dcn_COE_Overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */    
    sp_rpt_dcn_coop_trucks SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_coop_trucks] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-20 DD initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @year_filter varchar(max),    -- TABLE VARIABLE--  @coop_tbl varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')      select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    set @date_filter = 'year = '+@year_filter+''  set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @geo_filter = 'dealer = '''+@location_code+''''  set @coop_tbl = '[dwx].[sales_coop]'        set @sql =  '   select dealer   , year   , total_reward   , reward_used   , reward_remaining   , (case when left(valid_from,2) = ''01'' then concat(''Jan-Jun '', year) else concat(''Jul-Dec '', year) end) ''Period''   , valid_from   , valid_to    , (case when left(valid_from, 2) = ''01'' then 1 else 2 end)''ordered''   from '+@coop_tbl+'  where '+@geo_filter+' and '+@date_filter+'     GROUP BY dealer   , year   , total_reward   , reward_used   , reward_remaining   , valid_from   , valid_to     ORDER BY  ordered    '    -- Execute.  exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)    end  return 0    -- Test parm string  /*  exec [sp_rpt_dcn_Coop_trucks] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y'  */  
    sp_rpt_dcn_csi_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_csi_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates CSI Data for Dealer Contact Overview dashboard    Notes:    History:  2023-12-05 dd initial development (ICTA).    */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @date_type_id smallint,  @date_entity_type_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),      -- Query vars.  @sql varchar(4000),  @date_filter varchar(50),  @geo_filter varchar(100),  @geo_join_csi varchar(100),  @csi_calc1 varchar(100),  @csi_calc2 varchar(100),  @csi_calc3 varchar(100),  @csi_calc4 varchar(100),  @csi_filter varchar(100),  @geo_join varchar(100)      declare  @history_start varchar(4),  @current_csi varchar(4)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)      set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','smallint')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')    set @date_filter = dbo.fn_get_date_filter(@date_type_id,8)    -- Get config parms for CSI calcs.  select @csi_calc1=trim(',' from substring(parm_value,5,50))  from app_config  where parm_name in('csi_metric_cat1')    select @csi_calc2=trim(',' from substring(parm_value,5,50))  from app_config  where parm_name in('csi_metric_cat2')    select @csi_calc3=trim(',' from substring(parm_value,5,50))  from app_config  where parm_name in('csi_metric_cat3')    select @csi_calc4=trim(',' from substring(parm_value,5,50))  from app_config  where parm_name in('csi_metric_cat4')    set @sql = '  drop table if exists ##temp_csi_nat    select   a.location_id,  count(a.survey_id) ''total_survey'',  isnull(avg('+@csi_calc1+'),0) csi_cst_trt,  isnull(avg('+@csi_calc2+'),0) csi_rpr_exp,  isnull(avg('+@csi_calc3+'),0) csi_sch_tim,  isnull(avg('+@csi_calc4+'),0) csi_doc_chg      into ##temp_csi_nat  from  fact_csi_part a  where a.date_id is not null and '+@date_filter+'  group by a.location_id    select     a.location_id,  a.total_survey,  isnull(a.csi_cst_trt,0) csi_cst_trt,  isnull(a.csi_rpr_exp,0) csi_rpr_exp,  isnull(a.csi_sch_tim,0) csi_sch_tim,  isnull(a.csi_doc_chg,0) csi_doc_chg,  (a.csi_cst_trt+a.csi_rpr_exp+a.csi_sch_tim+a.csi_doc_chg)/((case when a.csi_cst_trt <> 0 then 1 else 0 end)+(case when a.csi_rpr_exp <> 0 then 1 else 0 end)+(case when a.csi_sch_tim <> 0 then 1 else 0 end)+(case when a.csi_doc_chg <> 0 then 1 else 0 end)) csi_overall,  b.csi_cst_trt_nat,  b.csi_rpr_exp_nat,  b.csi_sch_tim_nat,  b.csi_doc_chg_nat,  (b.csi_cst_trt_nat+b.csi_rpr_exp_nat+b.csi_sch_tim_nat+b.csi_doc_chg_nat)/4 csi_tot_nat    from dim_location d  left join (select * from ##temp_csi_nat where location_id = '+@geo_value+') a  on d.location_id = a.location_id  left join (select   '+@geo_value+' location_id,   avg(isnull(csi_cst_trt,0)) csi_cst_trt_nat,   avg(isnull(csi_rpr_exp,0)) csi_rpr_exp_nat,  avg(isnull(csi_sch_tim,0)) csi_sch_tim_nat,  avg(isnull(csi_doc_chg,0)) csi_doc_chg_nat  from ##temp_csi_nat) b  on d.location_id = b.location_id   where d.location_id = '+@geo_value+'  '    exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      /*  exec [sp_rpt_dcn_csi_overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */      
    sp_rpt_dcn_date_modifier SQL_STORED_PROCEDURE create procedure [dbo].[sp_rpt_dcn_date_modifier] @parms xml = null,
