    @rpt_lvl int = 1 as
    /*  Purpose: Inform reports of the date values when needed so our ssrs can be smarter  Notes: This is only inofrming ssrs of the min year and the max year    History:  2026-01-20 DD Initial Develpoment this returns a column with year so our sssrs can be informed use dim_date  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),      --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_filter3 varchar(max),    --table name  @COE_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 0)  set @COE_table = 'ICTA_IDEAS_DWX.[dbo].[dlr_coe]'  set @date_table = 'dim_date'    begin  set @sql =  '  select date_year, date_month  from '+@date_table+'  where date_id = '+@date1+' or date_id = '+@date2+'  '  end    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0        --test parm  /*  exec [dbo].[sp_rpt_dcn_date_modifier] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */    
    sp_rpt_dcn_dealer SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_dealer] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates report content for dealer contact.    Notes:  geo_value is used to pass pkg_id from which location_id is determined.    History:  2021-08-24 bh initial development.  2025-10-20 mh ensure only single dealer chosen  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @date_type_id smallint,  @geo_type_id smallint,  @geo_value varchar(100),  @pkg_id varchar(100),    -- Query vars.  @sql varchar(4000),  @code varchar(100),  @pkg_date  smalldatetime,  @pkg_user varchar(100)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  --set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(100)')  set @pkg_id = @parms.value('/parms[1]/geo_value[1]','varchar(100)')    -- Get config parms.  --set @country = (select parm_value from app_config where parm_name = 'country')    -- Return model (demo) report content for report designer.  if (@parms is null) begin   set @geo_value=8  end    -- Build query.  select @geo_value = location_id, @pkg_date=pkg_date, @pkg_user=insert_user_id  from pkg.contact_pkg  where pkg_id = @pkg_id    select @code=location_code  from dim_location  where location_id = @geo_value    set @sql = '  select n name,v value,1 type  from  (select top 1  dealer_name Dealer,  Address,  City,  State,  ZIP,  Country,  Region,  District  from dcn.dealer  where dealer = '''+@code+''') t  unpivot (v for n in (Dealer,Address,City,State,Zip,Country,Region,District)  ) as p  union all  select role,UPPER(full_name) ''full_name'',2 type  from dcn.dealer_mgr  where dealer = '''+@code+''''    -- Execute.  exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      /*  exec [dbo].[sp_rpt_dcn_dealer] '<parms><report_id>716</report_id><geo_type_id>1</geo_type_id><geo_value>3801</geo_value><geo_title>Dealer = KAYSER ISUZU TRUCK (64723)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2025YTD</time_title><request_id>1740437377152</request_id><_>1740437367838</_><user_id>ddaniel@sextantusa.com</user_id></parms>', 'y'  */    
    sp_rpt_dcn_demos_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_demos_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-16 DD initial development.  2025-01-31 DD add date filter  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @year_filter varchar(max),    --table name  @demotable varchar(max)      -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')      set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    set @date_filter = 'year = '+@year_filter+''  set @demotable = '[dwx].[sales_demo]'    select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @sql =  '   SELECT dealer   , program   , valid_from   , Valid_to   , n_demo_earned   , n_demo_paid   , n_demo_rem   , ftr_demo_earned   , ftr_demo_paid   , ftr_demo_rem   , insert_date   , rec_id   , (cast(n_demo_earned as int) + cast(ftr_demo_earned as int))''total_earned''   , ( cast(n_demo_paid as int) + cast(ftr_demo_paid as int))''total_paid''   , (cast(n_demo_rem as int) + cast(ftr_demo_rem as int) )''total_remaining''  FROM '+@demotable+'  WHERE '+@date_filter+' and '+@dealer_filter+'  '      exec sp_utl_exec @sql, @debug    end  return 0    --test parm  /*  exec [sp_rpt_dcn_Demos_overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y'  */  
    sp_rpt_dcn_ev_mobile_survey SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_ev_mobile_survey] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_level int = 1,
    @survey_id int = null as
    /*  Purpose: Generates Report Data for Dealer Visit EV Mobile Survey Report    Notes:    History:  2024-01-29 ak initial development  2024-05-03 ak updates for data structure changes  2024-10-21 mg bug fix to ev_personnel export (rpt_level = 4) to cast date as varchar  2024-10-29 mg bug fix to drill-through report (rpt_level = 5) to specific ev_survey  2024-11-21 taw added archive process for the two export files (@rpt_level = 3 and @rpt_level = 4)  2024-11-25 taw added email logic for (@rpt_level = 3)  2025-02-17 taw modified logic @rpt_level = 2 to get most recent expiration dates for report for cat_id 2 and union the other cat_ids.  2025-02-18 taw fixed issue with sending out empty emails for @rpt_level = 3  2025-03-14 taw fix header export for rpt_level = 4  2025-05-12 taw add column isuzu_connect_registered for rpt_level = 5  2025-05-13 taw add column isuzu_connect_registered for rpt_level = 3  2025-05-14 taw added 3 new columns [ev_cert], [whsl_pct] and [nnn_pct] for for rpt_level = 5   2025-05-20 taw added Isuzu_Connent_Registered column to email for (@rpt_level = 3)  2026-01-13 taw added logic for Sales/Service Charger Equipment - use the higher value of the two for certification calculations. (@rpt_level = 5)  2026-01-15 taw added two new @rpt_levels   -- @rpt_level = 6 - USED FOR dcn_dashboard_ev_drillthrough_box04.rdl - ASE xEV Level 1 & 2 Service Technician Training   -- @rpt_level = 7 - USED FOR dcn_dashboard_ev_drillthrough_box05.rdl - ASE xEV Level 1 Svc Mgr/Svc Adv & Part Mgr/Part Cntr Training   -- @rpt_level = 3 - 1969 Exports    -- Added columns [lvl_1_2_techs_training] and [svc_parts_training] to table [ICTA_DEALER_SURVEY_App].[dbo].[ev_readiness_export_history]    -- the new columns are added to the exports.    -- the new columns replace [lvl_1_2_techs], [xev_lvl_1_service] and [xev_lvl_1_parts] in the email notifications for ev certifications.  2026-02-02 taw Conversion from survey ID 1 to survey ID 4 (this was an update to [dbo].[rpt_report] changing parm1 from a 1 to a 4)   -- @rpt_level = 5 - remove [service_charge_equip] and [sales_charge_equip] replace with [charge_equip] - USED FOR dcn_dashboard_ev_drillthrough_box11.rdl  2026-02-09 taw  @rpt_level = 3 - 1969 Exports    -- Added column [charge_equip] to table [ICTA_DEALER_SURVEY_App].[dbo].[ev_readiness_export_history]    -- the new column is added to the EV Readiness export.    -- the new column replaces [service_charge_equip] and [sales_charge_equip] in the email notifications for ev certifications.  2026-02-13 taw  @rpt_level = 3 - 1969 Exports    -- REMOVED COLUMNS from the Export file for EV Readiness    -- lvl_1_2_techs    -- xev_lvl_1_service    -- xev_lvl_1_parts    -- sales_training    -- service_charge_equip    -- sales_charge_equip”.   2026-03-18 taw added guard to ensure this does not fail when state is geography selected for report EV Readiness Dashboard  */
    begin
declare @sproc varchar(100),
    @start_time smalldatetime,
    @end_time smalldatetime,
    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @date_type_id smallint,  @date_entity_type_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),    -- Query vars.  @sql varchar(8000),  @date_filter varchar(500),  @geo_filter varchar(100),  @survey_type_id int,  @survey_type_filter varchar(500),  @loc_type_id int,  @loc_type_join varchar(max),  @geo_alias varchar(10),  @geo_join varchar(100),  @db_reference varchar(100) = 'ICTA_DEALER_SURVEY_App.dbo.',  @test_db_reference varchar(100) = 'ICTA_DEALER_SURVEY_App.dbo.',  @img_reference varchar(100) = 'https://dealersurvey.sextantusa.com/uploads/',  @ev_img_reference varchar(100) = 'https://ev-readiness.sextantusa.com/uploads/',  -- Date vars  @date1 varchar(100),  @date2 varchar(100),  @use_day int,  @date_entity_id int = (select top 1 entity_id from dim_year where entity_name = 'service'),  @date_switch_id int,  -- definition tables  @survey_tbl varchar(100) = 'ev_surveys',  @category_tbl varchar(100) = 'ev_cats',  @topic_tbl varchar(100) = 'ev_topics',  @question_tbl varchar(100) = 'ev_questions',  @answer_tbl varchar(100) = 'ev_answers',  @files_tbl varchar(100) = 'ev_files',  --ev views  @structure_tbl varchar(100) = 'vw_ev_structure',  @survey_result_tbl varchar(100) = 'vw_ev_surveys',  @staff_result_tbl varchar(100) = 'vw_ev_answers_staff',  @tool_result_tbl varchar(100) = 'vw_ev_answers_ppe_tools',  @chgr_result_tbl varchar(100) = 'vw_ev_answers_chargers',  @loc_export_tbl varchar(100) = 'vw_ev_export_locations',  @loc_readiness_hst varchar(100) = 'ev_readiness_export_history',  @loc_personnel_hst varchar(100) = 'ev_personnel_export_history',  @ev_history_email_01 varchar(100) = 'vw_ev_readiness_export_history_email_01',  @ev_history_email_02 varchar(100) = 'vw_ev_readiness_export_history_email_02',  @ev_history_email_03 varchar(100) = 'vw_ev_readiness_export_history_email_03',    @topic_result_tbl varchar(100) = 'ev_result_topics',  @answer_result_tbl varchar(100) = 'ev_result_answers',  @export_tbl varchar(100) = concat('##ev_export_',replace(newid(),'-','_')),  @export_header_tbl varchar(100) = concat('##ev_export_header_',replace(newid(),'-','_')),  @export_final_tbl varchar(100) = concat('##ev_export_final_',replace(newid(),'-','_')),  @default_time varchar(100)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @date_switch_id = (select date_year_id from dim_year where year_name = 'Running 12m' and entity_id = @date_entity_id)  set @default_time = (select parm_value from app_config where parm_name = 'time_period_default_csi')    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @date_type_id = isnull(@parms.value('/parms[1]/date_type_id[1]','smallint'),@default_time)  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')    set @date1 = isnull(@parms.value('/parms[1]/date1[1]','varchar(100)'),'2022-01-01')  set @date2 = isnull(@parms.value('/parms[1]/date2[1]','varchar(100)'),(select CONVERT(varchar, date_sql, 23) from dim_date_day where date_sql = cast(getdate() as varchar(max))))    set @survey_type_id = (select parm1 from rpt_report where report_id = @report_id)    set @survey_type_filter = (case when @survey_type_id = 4 then 'a.survey_type_id = 4' else 'a.survey_type_id = 2' end)    set @use_day = (case when len(@date1) = 0 then 0 else 1 end)  set @date_filter = dbo.fn_get_datepick_filter(@date1,@date2,@use_day,@date_type_id,@date_entity_id)  set @date_filter = replace(@date_filter,'date_id','a.day_date_id')    select @geo_filter=geo_filter, @geo_join = geo_join  from dbo.fn_get_geo_parts('',@geo_type_id, @geo_value, 0)    set @geo_alias = (case when @geo_type_id = 7 then '' else 'c.' end)    set @loc_type_id = (select parm0 from rpt_report where report_id = @report_id)    set @loc_type_join = (case   when @loc_type_id = 0 then 'join (select * from dim_location where date_close is null and location_id > 0 union select * from ictc_ideas_app.dbo.dim_location where date_close is null and location_id > 0) b on a.dealer_code = b.location_code'   when @loc_type_id = 1 then 'join (select ''60492'' location_code, ''Corporate Training'' location_name, ''92806'' geo_id) b on a.dealer_code = b.location_code'  end)    set @db_reference = (case when @loc_type_id = 0 then @db_reference else @test_db_reference end)    set @img_reference = (case when @loc_type_id = 0 then @img_reference else @ev_img_reference end)    if @rpt_level = 1 begin   set @sql = '   -- Survey Summary Results   select   a.*,   c.*   from '+@db_reference+@survey_result_tbl+' a   '+@loc_type_join+'   left join geo_geo c   on b.geo_id = c.geo_id   where '+@geo_alias+@geo_filter+' and '+@date_filter+' and '+@survey_type_filter     exec sp_utl_exec @sql, @debug  end    if @rpt_level = 2 begin   set @sql = '    -- Survey Detail Results   ------ [lvl_1_lvl2_A] - gets the data for drill through: ASE xEV Level 1 & 2 Service Technician Training   ;with [lvl_1_lvl2_A] as (    select      b.[survey_type_id]     ,b.[survey_name]     ,b.[cat_id]     ,b.[cat_seq]     ,b.[cat]     ,b.[cat_status]     ,b.[topic_id]     ,b.[topic_seq]     ,b.[topic]     ,b.[qty_question]     ,b.[topic_noun]     ,c.[puid]     ,c.[staff_name]     ,c.[lvl_1_exp]     ,c.[lvl_2_exp]     ,c.[upload_1_user_file]     ,c.[upload_1_sys_file]     ,c.[upload_1_file_type]     ,c.[upload_2_user_file]     ,c.[upload_2_sys_file]     ,c.[upload_2_file_type]     ,c.[gloves_1]     ,c.[gloves_1_exp]     ,c.[gloves_2]     ,c.[gloves_2_exp]     ,d.[answer] [tool_answer]     ,d.[answer_text] [tool_answer_text]     ,e.[answer_text] [chgr_answer]     ,e.[user_file_name] [chgr_user_file]     ,e.[image_name] [chgr_sys_file]     ,e.[file_extension] [chgr_file_type]     ,row_number() over (partition by c.[puid] order by c.[lvl_1_exp] desc) AS [rn]    from '+@db_reference+@survey_result_tbl+' a    join '+@db_reference+@structure_tbl+' b on a.survey_type_id = b.survey_type_id    left join '+@db_reference+@staff_result_tbl+' c on a.survey_result_id = c.survey_result_id AND b.topic_id = c.topic_id    left join '+@db_reference+@tool_result_tbl+' d on a.survey_result_id = d.survey_result_id AND b.topic_id = d.topic_id    left join '+@db_reference+@chgr_result_tbl+' e on a.survey_result_id = e.survey_result_id AND b.topic_id = e.topic_id    where a.survey_result_id = '+ltrim(str(@survey_id))+   ' and b.cat_id = 2)   ------ [lvl_1_lvl2_B] - gets the data for drill through:    ------ ASE xEV Level 1 Svc Mgr/Svc Adv & Part Mgr/Part Cntr Training   ------ EV Special Service Tools & High Voltage PPE   ------ Sales Department Dedicated EV Charger   ------ Service Department Dedicated EV Charger   ,[lvl_1_lvl2_B] as (   select    b.[survey_type_id]   ,b.[survey_name]   ,b.[cat_id]   ,b.[cat_seq]   ,b.[cat]   ,b.[cat_status]   ,b.[topic_id]   ,b.[topic_seq]   ,b.[topic]   ,b.[qty_question]   ,b.[topic_noun]   ,c.[puid]   ,c.[staff_name]   ,c.[lvl_1_exp]   ,c.[lvl_2_exp]   ,c.[upload_1_user_file]   ,c.[upload_1_sys_file]   ,c.[upload_1_file_type]   ,c.[upload_2_user_file]   ,c.[upload_2_sys_file]   ,c.[upload_2_file_type]   ,c.[gloves_1]   ,c.[gloves_1_exp]   ,c.[gloves_2]   ,c.[gloves_2_exp]   ,d.answer tool_answer   ,d.answer_text tool_answer_text   ,e.[answer_text] chgr_answer   ,e.[user_file_name] chgr_user_file   ,e.[image_name] chgr_sys_file   ,e.[file_extension] chgr_file_type   FROM '+@db_reference+@survey_result_tbl+' a   join '+@db_reference+@structure_tbl+' b   on a.survey_type_id = b.survey_type_id   left join '+@db_reference+@staff_result_tbl+' c   on a.survey_result_id = c.survey_result_id and b.topic_id = c.topic_id   left join '+@db_reference+@tool_result_tbl+' d   on a.survey_result_id = d.survey_result_id and b.topic_id = d.topic_id   left join '+@db_reference+@chgr_result_tbl+' e   on a.survey_result_id = e.survey_result_id and b.topic_id = e.topic_id   where a.survey_result_id = '+ltrim(str(@survey_id))+   ' and b.cat_id <> 2)   select    [survey_type_id]   ,[survey_name]   ,[cat_id]   ,[cat_seq]   ,[cat]   ,[cat_status]   ,[topic_id]   ,[topic_seq]   ,[topic]   ,[qty_question]   ,[topic_noun]   ,[puid]   ,[staff_name]   ,[lvl_1_exp]   ,[lvl_2_exp]   ,[upload_1_user_file]   ,[upload_1_sys_file]   ,[upload_1_file_type]   ,[upload_2_user_file]   ,[upload_2_sys_file]   ,[upload_2_file_type]   ,[gloves_1]   ,[gloves_1_exp]   ,[gloves_2]   ,[gloves_2_exp]   ,[tool_answer]   ,[tool_answer_text]   ,[chgr_answer]   ,[chgr_user_file]   ,[chgr_sys_file]   ,[chgr_file_type]   from [lvl_1_lvl2_A]   where rn = 1   union    select    [survey_type_id]   ,[survey_name]   ,[cat_id]   ,[cat_seq]   ,[cat]   ,[cat_status]   ,[topic_id]   ,[topic_seq]   ,[topic]   ,[qty_question]   ,[topic_noun]   ,[puid]   ,[staff_name]   ,[lvl_1_exp]   ,[lvl_2_exp]   ,[upload_1_user_file]   ,[upload_1_sys_file]   ,[upload_1_file_type]   ,[upload_2_user_file]   ,[upload_2_sys_file]   ,[upload_2_file_type]   ,[gloves_1]   ,[gloves_1_exp]   ,[gloves_2]   ,[gloves_2_exp]   ,[tool_answer]   ,[tool_answer_text]   ,[chgr_answer]   ,[chgr_user_file]   ,[chgr_sys_file]   ,[chgr_file_type]   from [lvl_1_lvl2_B]   '   exec sp_utl_exec @sql, @debug  end  else if @rpt_level = 3 begin      exec sp_utl_drop_table @export_tbl,@debug   exec sp_utl_drop_table @export_header_tbl,@debug     set @sql = '   -- Location Level EV Export   select [location_code]    , [interest]    , [isuzu_connect]    , [isuzu_connect_registered]    , [tools_equip_ppe]    , [hv_handle_safety]    , [tech_training]    , [service_training]    , [parts_training]    , [lvl_1_2_techs_training]    , [svc_parts_training]     , [charge_equip]    into '+@export_tbl+'   from '+@db_reference+@loc_export_tbl   exec sp_utl_exec @sql, @debug   -----------------------------------------------------   -- ARCHIVE Location Level EV Export   -----------------------------------------------------   set @sql = '   -- Location Level EV Export History Archive   INSERT INTO '+@db_reference+@loc_readiness_hst+'             ([location_code]             ,[interest]             ,[isuzu_connect]       ,[isuzu_connect_registered]             ,[lvl_1_2_techs]             ,[tools_equip_ppe]             ,[hv_handle_safety]             ,[xev_lvl_1_service]             ,[xev_lvl_1_parts]             ,[tech_training]             ,[sales_training]             ,[service_charge_equip]             ,[sales_charge_equip]             ,[service_training]             ,[parts_training]       ,[lvl_1_2_techs_training]       ,[svc_parts_training]       ,[charge_equip]             ,[insert_date])      select [location_code]       ,[interest]       ,[isuzu_connect]       ,[isuzu_connect_registered]       ,0 as [lvl_1_2_techs]       ,[tools_equip_ppe]       ,[hv_handle_safety]       ,0 as [xev_lvl_1_service]       ,0 as [xev_lvl_1_parts]       ,[tech_training]       ,0 as [sales_training]       ,0 as [service_charge_equip]       ,0 as [sales_charge_equip]       ,[service_training]       ,[parts_training]       ,[lvl_1_2_techs_training]       ,[svc_parts_training]       ,[charge_equip]       ,getdate()   from '+@export_tbl   exec sp_utl_exec @sql, @debug      set @sql = '   declare @sql varchar(max),   @index int = 0     set @sql = ''select '';     -- fetch the column names and append them to the dynamic sql statement   select @sql = @sql + case when @index > 0 then '', '' else '''' end + '''''''' + name + '''''' as column'' + cast(@index as varchar(10)),   @index = @index + 1      from tempdb.sys.columns   where object_id = object_id(''tempdb..'+@export_tbl+''')   order by column_id;     set @sql = @sql + '' into '+@export_header_tbl+'''     exec sp_utl_exec @sql,''n'''     exec sp_utl_exec @sql,@debug     set @sql = 'exec xp_cmdshell ''bcp "select * from '+@export_header_tbl+' union select * from '+@export_tbl+'  order by column0 desc" queryout "D:\ICTA\EXPORT\ev_readiness_'+(select format(getdate(), 'yyyyMMdd'))+'.txt" -c -t"\t" -T -S localhost'''   exec sp_utl_exec @sql, @debug     /*-- see if email needs to be generated --*/   declare @sqlmax nvarchar(max)   declare @ev_intrest_cnt int   declare @ev_wholesale_ready_cnt int   declare @ev_certified_cnt int     set @sqlmax = ''   set @sqlmax = @sqlmax + '   select @ev_intrest_cnt = count(*) from '+@db_reference+@ev_history_email_01   exec sp_executesql @sqlmax, N'@ev_intrest_cnt int OUTPUT', @ev_intrest_cnt OUTPUT     set @sqlmax = ''   set @sqlmax = @sqlmax + '   select @ev_wholesale_ready_cnt = count(*) from '+@db_reference+@ev_history_email_02   exec sp_executesql @sqlmax, N'@ev_wholesale_ready_cnt int OUTPUT', @ev_wholesale_ready_cnt OUTPUT     set @sqlmax = ''   set @sqlmax = @sqlmax + '   select @ev_certified_cnt = count(*) from '+@db_reference+@ev_history_email_03   exec sp_executesql @sqlmax, N'@ev_certified_cnt int OUTPUT', @ev_certified_cnt OUTPUT     declare @email_profile  AS VARCHAR(50) = 'online'    declare @email_body_msg varchar(max) = NULL   declare @email_subject_msg_01 varchar(2000) = 'EV Status Change Email: Becoming EV Certified'   declare @email_subject_msg_02 varchar(2000) = 'EV Status Change Email: EV Wholesale Ready (Step 1)'   declare @email_subject_msg_03 varchar(2000) = 'EV Status Change Email: EV Certified (Step 1 & Step 2)'   declare @emailDistributionList varchar(2000) = (select [parm_value]                                                   from [dbo].[app_config]                                                   where [parm_name] = 'ev_status_email');      ---- generate email if > 0   if @ev_intrest_cnt > 0    begin    set @sql = ''    set @sql = @sql + '    select      [location_code],     [location_name],      [current_day],      [interest],      [isuzu_connect_registered],     [previous_day],      [p_interest],     [p_isuzu_connect_registered]    from '+@db_reference+@ev_history_email_01      ---- Execute the constructed SQL query and store the result in a variable    declare @result_01 table (        location_code varchar(50),        location_name varchar(100),        current_day date,        interest varchar(100),     registered varchar(100),        previous_day date,        p_interest varchar(100),     p_registered varchar(100)     );      insert into @result_01    exec sp_utl_exec @sql,@debug      declare @intrested varchar(5) = ''    declare @not_intrested varchar(5) = ''      set @intrested = (select 'Y' from @result_01 where interest = 1 and p_interest = 0)    set @not_intrested = (select 'N' from @result_01 where interest = 0 and p_interest = 1)      if @intrested = 'Y'    begin     -- Construct the HTML email body     set @email_body_msg = '<html><body>';     set @email_body_msg = @email_body_msg + '<h2>Becoming EV Certified</h2>';     set @email_body_msg = @email_body_msg + '<p></p>';     set @email_body_msg = @email_body_msg + '<p><b>==================================================================</b></p>';     set @email_body_msg = @email_body_msg + '<p></p>';     set @email_body_msg = @email_body_msg + '<p>Which dealer is now interesting in Becoming EV Certified</p>';     set @email_body_msg = @email_body_msg + '<table bordercolor="BLUE" border="1" cellpadding="5" cellspacing="0">';     set @email_body_msg = @email_body_msg + '<tr>                <th>Dealer Code</th>                <th>Dealer Name</th>                <th>Current Day</th>                <th>Becoming EV Certified</th>                <th>Isuzu Connect Registered</th>                <th>Previous Day</th>                <th>Becoming EV Certified</th>                <th>Isuzu Connect Registered</th>                </tr>';       declare @e1a_location_code varchar(50),       @e1a_location_name varchar(100),       @e1a_current_day date,       @e1a_interest varchar(100),       @e1a_registered varchar(100),       @e1a_previous_day date,       @e1a_p_interest varchar(100),       @e1a_p_registered varchar(100);       declare ev_history_email_01a cursor for     select location_code,       location_name,       current_day,       interest,       registered,      previous_day,       p_interest,      p_registered     from @result_01     where interest = 1 and p_interest = 0;       open ev_history_email_01a;     fetch next from ev_history_email_01a into        @e1a_location_code,        @e1a_location_name,        @e1a_current_day,        @e1a_interest,        @e1a_registered,       @e1a_previous_day,        @e1a_p_interest,       @e1a_p_registered;       while @@FETCH_STATUS = 0     begin      set @email_body_msg = @email_body_msg + '<tr>';      set @email_body_msg = @email_body_msg + '<td>' + @e1a_location_code + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + @e1a_location_name + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e1a_current_day, 101) + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + @e1a_interest + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + @e1a_registered + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e1a_previous_day, 101) + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + @e1a_p_interest + '</td>';      set @email_body_msg = @email_body_msg + '<td>' + @e1a_p_registered + '</td>';      set @email_body_msg = @email_body_msg + '</tr>';       fetch next from ev_history_email_01a into        @e1a_location_code,        @e1a_location_name,        @e1a_current_day,        @e1a_interest,        @e1a_registered,       @e1a_previous_day,        @e1a_p_interest,       @e1a_p_registered;     end;       close ev_history_email_01a;     deallocate ev_history_email_01a;       set @email_body_msg = @email_body_msg + '</table>';    end      if @not_intrested = 'N'    begin     if @email_body_msg is NULL     begin      set @email_body_msg = '<html><body>';      set @email_body_msg = @email_body_msg + '<h2>Not Becoming EV Certified</h2>';      set @email_body_msg = @email_body_msg + '<p></p>';     end      else     begin      set @email_body_msg = @email_body_msg + '<p></p>';      set @email_body_msg = @email_body_msg + '<p><b>==================================================================</b></p>';      set @email_body_msg = @email_body_msg + '<p></p>';      set @email_body_msg = @email_body_msg + '<p>Which dealer is now no longer interested in Becoming EV Certified</p>';      set @email_body_msg = @email_body_msg + '<p></p>';      set @email_body_msg = @email_body_msg + '<table bordercolor="BLUE" border="1" cellpadding="5" cellspacing="0">';      set @email_body_msg = @email_body_msg + '<tr>                 <th>Dealer Code</th>                 <th>Dealer Name</th>                 <th>Current Day</th>                 <th>Becoming EV Certified</th>                 <th>Isuzu Connect Registered</th>                 <th>Previous Day</th>                 <th>Becoming EV Certified</th>                 <th>Isuzu Connect Registered</th>                 </tr>';        declare @e1b_location_code varchar(50),        @e1b_location_name varchar(100),        @e1b_current_day date,        @e1b_interest varchar(100),        @e1b_registered varchar(100),        @e1b_previous_day date,        @e1b_p_interest varchar(100),        @e1b_p_registered varchar(100);        declare ev_history_email_01b cursor for      select location_code,        location_name,        current_day,        interest,        registered,       previous_day,        p_interest,       p_registered      from @result_01      where interest = 0 and p_interest = 1;        open ev_history_email_01b;      fetch next from ev_history_email_01b into         @e1b_location_code,         @e1b_location_name,         @e1b_current_day,         @e1b_interest,         @e1b_registered,        @e1b_previous_day,         @e1b_p_interest,        @e1b_p_registered;        while @@FETCH_STATUS = 0      begin       set @email_body_msg = @email_body_msg + '<tr>';       set @email_body_msg = @email_body_msg + '<td>' + @e1b_location_code + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e1b_location_name + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e1b_current_day, 101) + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e1b_interest + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e1b_registered + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e1b_previous_day, 101) + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e1b_p_interest + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e1b_p_registered + '</td>';       set @email_body_msg = @email_body_msg + '</tr>';        fetch next from ev_history_email_01b into         @e1b_location_code,         @e1b_location_name,         @e1b_current_day,         @e1b_interest,         @e1b_registered,        @e1b_previous_day,         @e1b_p_interest,        @e1b_p_registered;      end;        close ev_history_email_01b;      deallocate ev_history_email_01b;        set @email_body_msg = @email_body_msg + '</table>';     end    end      if @email_body_msg is not NULL    begin     set @email_body_msg = @email_body_msg + '</body></html>';       EXEC msdb.dbo.sp_send_dbmail @profile_name = @email_profile,       @recipients = @emailDistributionList,       @subject = @email_subject_msg_01,       @body = @email_body_msg,       @body_format = 'HTML';        set @email_body_msg = NULL;    end   end      ----generate email if > 0   if @ev_wholesale_ready_cnt > 0     begin     set @sql = ''     set @sql = @sql + '     select       [location_code],       [location_name],       [current_day],       [interest],       [isuzu_connect_registered],      [isuzu_connect],      --[lvl_1_2_techs],       [tools_equip_ppe],       [hv_handle_safety],       --[xev_lvl_1_service],       --[xev_lvl_1_parts],       [lvl_1_2_techs_training],      [svc_parts_training],      [previous_day],       [p_interest],       [p_isuzu_connect_registered],      [p_isuzu_connect],      --[p_lvl_1_2_techs],       [p_tools_equip_ppe],       [p_hv_handle_safety],       --[p_xev_lvl_1_service],       --[p_xev_lvl_1_parts],      [lvl_1_2_techs_training],      [svc_parts_training]     from '+@db_reference+@ev_history_email_02        ---- Execute the constructed SQL query and store the result in a variable     declare @result_02 table (         location_code varchar(50),         location_name varchar(100),         current_day date,         interest varchar(100),      isuzu_connect_registered varchar(100),      isuzu_connect varchar(100),      --lvl_1_2_techs varchar(100),       tools_equip_ppe varchar(100),       hv_handle_safety varchar(100),       --xev_lvl_1_service varchar(100),      --xev_lvl_1_parts varchar(100),       lvl_1_2_techs_training varchar(100),      svc_parts_training varchar(100),         previous_day date,         p_interest varchar(10),      p_isuzu_connect_registered varchar(100),      p_isuzu_connect varchar(100),      --p_lvl_1_2_techs varchar(100),       p_tools_equip_ppe varchar(100),       p_hv_handle_safety varchar(100),       --p_xev_lvl_1_service varchar(100),      --p_xev_lvl_1_parts varchar(100),      p_lvl_1_2_techs_training varchar(100),      p_svc_parts_training varchar(100)      );       insert into @result_02     exec sp_utl_exec @sql,@debug       --declare @wholesale_ready varchar(5) = ''     --declare @wholesale_not_ready varchar(5) = ''       declare @wholesale_ready int = 0     declare @wholesale_not_ready int = 0       set @wholesale_ready = (     --select 'Y'     select count(*)     from @result_02     where      -- CURRENT DAY      (interest +       isuzu_connect +       --lvl_1_2_techs +       lvl_1_2_techs_training +      tools_equip_ppe +       hv_handle_safety +       --xev_lvl_1_service +       --xev_lvl_1_parts) = ('11100100100100100')      svc_parts_training) = ('11100100100100')      and      -- PRIOR DAY      (p_interest +       p_isuzu_connect +       --p_lvl_1_2_techs +       p_lvl_1_2_techs_training +      p_tools_equip_ppe +       p_hv_handle_safety +       --p_xev_lvl_1_service +       --p_xev_lvl_1_parts) <> '11100100100100100'      p_svc_parts_training) <> '11100100100100'     );       set @wholesale_not_ready = (     --select 'N'     select count(*)     from @result_02     where      -- PRIOR DAY      (p_interest +       p_isuzu_connect +       --p_lvl_1_2_techs +       p_lvl_1_2_techs_training +      p_tools_equip_ppe +       p_hv_handle_safety +       --p_xev_lvl_1_service +       --p_xev_lvl_1_parts) <> '11100100100100100'      p_svc_parts_training) <> '11100100100100'      and      -- CURRENT DAY      (interest +       isuzu_connect +       --lvl_1_2_techs +       lvl_1_2_techs_training +      tools_equip_ppe +       hv_handle_safety +       --xev_lvl_1_service +       --xev_lvl_1_parts) = ('11100100100100100')      svc_parts_training) = ('11100100100100')     );              --if @wholesale_ready = 'Y'     if @wholesale_ready > 0     begin      ---- Construct the HTML email body      set @email_body_msg = '<html><body>';      set @email_body_msg = @email_body_msg + '<h2>EV Wholesale Ready (Step 1)</h2>';      set @email_body_msg = @email_body_msg + '<p></p>';      set @email_body_msg = @email_body_msg + '<p>Which dealer is now EV Wholesale ready (or a change in status of becoming ready)</p>';      set @email_body_msg = @email_body_msg + '<table bordercolor="BLUE" border="1" cellpadding="5" cellspacing="0">';      set @email_body_msg = @email_body_msg + '<tr>                 <th>Dealer Code</th>                 <th>Dealer Name</th>                 <th>Date</th>                 <th>Becoming EV Certified</th>                 <th>Isuzu Connect Registered</th>                 <th>Using Isuzu Connect</th>                 <th>High Voltage Vehicle Awareness Service Technician Training</th>                  <th>EV Special Service Tools & High Voltage PPE</th>                  <th>High Voltage Vehicle Awareness Training</th>                  <th>High Voltage Vehicle Awareness Svc Mgr/Svc Adv & Part Mgr/Part Cntr Training</th>                  </tr>';      declare @e2a_location_code varchar(50),        @e2a_location_name varchar(100),        @e2a_current_day date,        @e2a_interest varchar(100),        @e2a_isuzu_connect_registered varchar(100),        @e2a_isuzu_connect varchar(100),        --@e2a_lvl_1_2_techs varchar(100),         @e2a_lvl_1_2_techs_training varchar(100),        @e2a_tools_equip_ppe varchar(100),         @e2a_hv_handle_safety varchar(100),         --@e2a_xev_lvl_1_service varchar(100),        --@e2a_xev_lvl_1_parts varchar(100),         @e2a_svc_parts_training varchar(100),        @e2a_previous_day date,        @e2a_p_interest varchar(100),        @e2a_p_isuzu_connect_registered varchar(100),        @e2a_p_isuzu_connect varchar(100),        --@e2a_p_lvl_1_2_techs varchar(100),         @e2a_p_lvl_1_2_techs_training varchar(100),        @e2a_p_tools_equip_ppe varchar(100),         @e2a_p_hv_handle_safety varchar(100),         --@e2a_p_xev_lvl_1_service varchar(100),        --@e2a_p_xev_lvl_1_parts varchar(100)        @e2a_p_svc_parts_training varchar(100)        declare ev_history_email_02a cursor for      select location_code,       location_name,       current_day,       interest,       isuzu_connect_registered,       isuzu_connect,       --lvl_1_2_techs,        lvl_1_2_techs_training,       tools_equip_ppe,        hv_handle_safety,        --xev_lvl_1_service,       --xev_lvl_1_parts,        svc_parts_training,       previous_day,       p_interest,       p_isuzu_connect_registered,       p_isuzu_connect,       --p_lvl_1_2_techs,        p_lvl_1_2_techs_training,       p_tools_equip_ppe,        p_hv_handle_safety,        --p_xev_lvl_1_service,       --p_xev_lvl_1_parts       p_svc_parts_training      from @result_02      where       -- CURRENT DAY      (interest +       isuzu_connect +       --lvl_1_2_techs +       lvl_1_2_techs_training +       tools_equip_ppe +       hv_handle_safety +       --xev_lvl_1_service +       --xev_lvl_1_parts) = ('11100100100100100')      svc_parts_training) = ('11100100100100')      and       -- PRIOR DAY      (p_interest +       p_isuzu_connect +       --p_lvl_1_2_techs +       p_lvl_1_2_techs_training +       p_tools_equip_ppe +       p_hv_handle_safety +       --p_xev_lvl_1_service +       --p_xev_lvl_1_parts) <> '11100100100100100'      p_svc_parts_training) <> '11100100100100'        open ev_history_email_02a;      fetch next from ev_history_email_02a into         @e2a_location_code,        @e2a_location_name,        @e2a_current_day,        @e2a_interest,        @e2a_isuzu_connect_registered,        @e2a_isuzu_connect,        --@e2a_lvl_1_2_techs,         @e2a_lvl_1_2_techs_training,        @e2a_tools_equip_ppe,         @e2a_hv_handle_safety,         --@e2a_xev_lvl_1_service,        --@e2a_xev_lvl_1_parts,         @e2a_svc_parts_training,        @e2a_previous_day,        @e2a_p_interest,        @e2a_p_isuzu_connect_registered,        @e2a_p_isuzu_connect,        --@e2a_p_lvl_1_2_techs,         @e2a_p_lvl_1_2_techs_training,        @e2a_p_tools_equip_ppe,         @e2a_p_hv_handle_safety,         --@e2a_p_xev_lvl_1_service,        --@e2a_p_xev_lvl_1_parts        @e2a_p_svc_parts_training        while @@FETCH_STATUS = 0      begin       set @email_body_msg = @email_body_msg + '<tr>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_location_code + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_location_name + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e2a_current_day, 101) + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_interest + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_isuzu_connect_registered + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_isuzu_connect + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e2a_lvl_1_2_techs + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_lvl_1_2_techs_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_tools_equip_ppe + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_hv_handle_safety + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e2a_xev_lvl_1_service + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e2a_xev_lvl_1_parts + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_svc_parts_training + '</td>';       set @email_body_msg = @email_body_msg + '</tr>';       set @email_body_msg = @email_body_msg + '<tr>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_location_code + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_location_name + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e2a_previous_day, 101) + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_interest + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_isuzu_connect_registered + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_isuzu_connect + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_lvl_1_2_techs + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_lvl_1_2_techs_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_tools_equip_ppe + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_hv_handle_safety + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_xev_lvl_1_service + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_xev_lvl_1_parts + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e2a_p_svc_parts_training + '</td>';       set @email_body_msg = @email_body_msg + '</tr>';        fetch next from ev_history_email_02a into         @e2a_location_code,        @e2a_location_name,        @e2a_current_day,        @e2a_interest,        @e2a_isuzu_connect_registered,        @e2a_isuzu_connect,        --@e2a_lvl_1_2_techs,         @e2a_lvl_1_2_techs_training,        @e2a_tools_equip_ppe,         @e2a_hv_handle_safety,         --@e2a_xev_lvl_1_service,        --@e2a_xev_lvl_1_parts,         @e2a_svc_parts_training,        @e2a_previous_day,        @e2a_p_interest,        @e2a_p_isuzu_connect_registered,        @e2a_p_isuzu_connect,        --@e2a_p_lvl_1_2_techs,         @e2a_p_lvl_1_2_techs_training,        @e2a_p_tools_equip_ppe,         @e2a_p_hv_handle_safety,         --@e2a_p_xev_lvl_1_service,        --@e2a_p_xev_lvl_1_parts        @e2a_p_svc_parts_training      end;        close ev_history_email_02a;      deallocate ev_history_email_02a;        set @email_body_msg = @email_body_msg + '</table>';       end       --if @wholesale_not_ready = 'N'     if @wholesale_not_ready > 0     begin      if @email_body_msg is NULL      begin       set @email_body_msg = '<html><body>';       set @email_body_msg = @email_body_msg + '<h2>EV Wholesale Ready (Step 1)</h2>';       set @email_body_msg = @email_body_msg + '<p></p>';      end       else      begin       set @email_body_msg = @email_body_msg + '<p></p>';       set @email_body_msg = @email_body_msg + '<p><b>==================================================================</b></p>';       set @email_body_msg = @email_body_msg + '<p></p>';       set @email_body_msg = @email_body_msg + '<p>Which dealer is now no longer Wholesale ready</p>';       set @email_body_msg = @email_body_msg + '<p></p>';       set @email_body_msg = @email_body_msg + '<table bordercolor="BLUE" border="1" cellpadding="5" cellspacing="0">';       set @email_body_msg = @email_body_msg + '<tr>                  <th>Dealer Code</th>                  <th>Dealer Name</th>                  <th>Date</th>                  <th>Becoming EV Certified</th>                  <th>Isuzu Connect Registered</th>                  <th>Using Isuzu Connect</th>                  <th>High Voltage Vehicle Awareness Service Technician Training</th>                   <th>EV Special Service Tools & High Voltage PPE</th>                   <th>High Voltage Vehicle Awareness Training</th>                   <th>High Voltage Vehicle Awareness Svc Mgr/Svc Adv & Part Mgr/Part Cntr Training</th>                   </tr>';         declare @e2b_location_code varchar(50),         @e2b_location_name varchar(100),         @e2b_current_day date,         @e2b_interest varchar(100),         @e2b_isuzu_connect_registered varchar(100),         @e2b_isuzu_connect varchar(100),         --@e2b_lvl_1_2_techs varchar(100),          @e2b_lvl_1_2_techs_training varchar(100),         @e2b_tools_equip_ppe varchar(100),          @e2b_hv_handle_safety varchar(100),          --@e2b_xev_lvl_1_service varchar(100),         --@e2b_xev_lvl_1_parts varchar(100),          @e2b_svc_parts_training varchar(100),         @e2b_previous_day date,         @e2b_p_interest varchar(100),         @e2b_p_isuzu_connect_registered varchar(100),         @e2b_p_isuzu_connect varchar(100),         --@e2b_p_lvl_1_2_techs varchar(100),          @e2b_p_lvl_1_2_techs_training varchar(100),         @e2b_p_tools_equip_ppe varchar(100),          @e2b_p_hv_handle_safety varchar(100),          --@e2b_p_xev_lvl_1_service varchar(100),         --@e2b_p_xev_lvl_1_parts varchar(100)         @e2b_p_svc_parts_training varchar(100)         declare ev_history_email_02b cursor for       select location_code,        location_name,        current_day,        interest,        isuzu_connect_registered,        isuzu_connect,        --lvl_1_2_techs,         lvl_1_2_techs_training,        tools_equip_ppe,         hv_handle_safety,         --xev_lvl_1_service,        --xev_lvl_1_parts,         svc_parts_training,        previous_day,        p_interest,        p_isuzu_connect_registered,        p_isuzu_connect,        --p_lvl_1_2_techs,         p_lvl_1_2_techs_training,        p_tools_equip_ppe,         p_hv_handle_safety,         --p_xev_lvl_1_service,        --p_xev_lvl_1_parts        p_svc_parts_training       from @result_02       where        -- PRIOR DAY       (p_interest +        p_isuzu_connect +        --p_lvl_1_2_techs +        p_lvl_1_2_techs_training +       p_tools_equip_ppe +        p_hv_handle_safety +        --p_xev_lvl_1_service +        --p_xev_lvl_1_parts) = '11100100100100100'       p_svc_parts_training) = '11100100100100'       and        -- CURRENT DAY       (interest +        isuzu_connect +        --lvl_1_2_techs +        lvl_1_2_techs_training +       tools_equip_ppe +        hv_handle_safety +        --xev_lvl_1_service +        --xev_lvl_1_parts) <> '11100100100100100'       svc_parts_training) <> '11100100100100'         open ev_history_email_02b;       fetch next from ev_history_email_02b into          @e2b_location_code,         @e2b_location_name,         @e2b_current_day,         @e2b_interest,         @e2b_isuzu_connect_registered,         @e2b_isuzu_connect,         --@e2b_lvl_1_2_techs,          @e2b_lvl_1_2_techs_training,         @e2b_tools_equip_ppe,          @e2b_hv_handle_safety,          --@e2b_xev_lvl_1_service,         --@e2b_xev_lvl_1_parts,          @e2b_svc_parts_training,         @e2b_previous_day,         @e2b_p_interest,         @e2b_p_isuzu_connect_registered,         @e2b_p_isuzu_connect,         --@e2b_p_lvl_1_2_techs,          @e2b_p_lvl_1_2_techs_training,         @e2b_p_tools_equip_ppe,          @e2b_p_hv_handle_safety,          --@e2b_p_xev_lvl_1_service,         --@e2b_p_xev_lvl_1_parts         @e2b_p_svc_parts_training         while @@FETCH_STATUS = 0       begin        set @email_body_msg = @email_body_msg + '<tr>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_location_code + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_location_name + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e2b_current_day, 101) + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_interest + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_isuzu_connect_registered + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_isuzu_connect + '</td>';        --set @email_body_msg = @email_body_msg + '<td>' + @e2b_lvl_1_2_techs + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_lvl_1_2_techs_training + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_tools_equip_ppe + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_hv_handle_safety + '</td>';        --set @email_body_msg = @email_body_msg + '<td>' + @e2b_xev_lvl_1_service + '</td>';        --set @email_body_msg = @email_body_msg + '<td>' + @e2b_xev_lvl_1_parts + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_svc_parts_training + '</td>';        set @email_body_msg = @email_body_msg + '</tr>';        set @email_body_msg = @email_body_msg + '<tr>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_location_code + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_location_name + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e2b_previous_day, 101) + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_interest + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_isuzu_connect_registered + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_isuzu_connect + '</td>';        --set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_lvl_1_2_techs + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_lvl_1_2_techs_training + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_tools_equip_ppe + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_hv_handle_safety + '</td>';        --set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_xev_lvl_1_service + '</td>';        --set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_xev_lvl_1_parts + '</td>';        set @email_body_msg = @email_body_msg + '<td>' + @e2b_p_svc_parts_training + '</td>';        set @email_body_msg = @email_body_msg + '</tr>';         fetch next from ev_history_email_02b into          @e2b_location_code,         @e2b_location_name,         @e2b_current_day,         @e2b_interest,         @e2b_isuzu_connect_registered,         @e2b_isuzu_connect,         --@e2b_lvl_1_2_techs,          @e2b_lvl_1_2_techs_training,         @e2b_tools_equip_ppe,          @e2b_hv_handle_safety,          --@e2b_xev_lvl_1_service,         --@e2b_xev_lvl_1_parts,          @e2b_svc_parts_training,         @e2b_previous_day,         @e2b_p_interest,         @e2b_p_isuzu_connect_registered,         @e2b_p_isuzu_connect,         --@e2b_p_lvl_1_2_techs,          @e2b_p_lvl_1_2_techs_training,         @e2b_p_tools_equip_ppe,          @e2b_p_hv_handle_safety,          --@e2b_p_xev_lvl_1_service,         --@e2b_p_xev_lvl_1_parts         @e2b_p_svc_parts_training       end;         close ev_history_email_02b;       deallocate ev_history_email_02b;         set @email_body_msg = @email_body_msg + '</table>';      end     end     if @email_body_msg is not NULL     begin      set @email_body_msg = @email_body_msg + '</body></html>';        EXEC msdb.dbo.sp_send_dbmail @profile_name = @email_profile,        @recipients = @emailDistributionList,        @subject = @email_subject_msg_02,        @body = @email_body_msg,        @body_format = 'HTML';         set @email_body_msg = NULL;     end    end      ----generate email if > 0   if @ev_certified_cnt > 0     begin     set @sql = ''     set @sql = @sql + '     select       [location_code],       [location_name],       [current_day],       [interest],       [isuzu_connect_registered],      [isuzu_connect],      --[lvl_1_2_techs],       [lvl_1_2_techs_training],      [tools_equip_ppe],       [hv_handle_safety],       --[xev_lvl_1_service],       --[xev_lvl_1_parts],       [svc_parts_training],      [tech_training],       [sales_training],       --[service_charge_equip],       --[sales_charge_equip],       [charge_equip],      [service_training],       [parts_training],       [previous_day],       [p_interest],       [p_isuzu_connect_registered],      [p_isuzu_connect],      --[p_lvl_1_2_techs],       [p_lvl_1_2_techs_training],      [p_tools_equip_ppe],       [p_hv_handle_safety],       --[p_xev_lvl_1_service],       --[p_xev_lvl_1_parts],       [p_svc_parts_training],      [p_tech_training],       [p_sales_training],       --[p_service_charge_equip],       --[p_sales_charge_equip],       [p_charge_equip],      [p_service_training],       [p_parts_training]     from '+@db_reference+@ev_history_email_03        ---- Execute the constructed SQL query and store the result in a variable     declare @result_03 table (      [location_code]     varchar(50),       [location_name]     varchar(100),       [current_day]     date,      [interest]      varchar(100),      [isuzu_connect_registered]  varchar(100),      [isuzu_connect]     varchar(100),      --[lvl_1_2_techs]     varchar(100),      [lvl_1_2_techs_training]  varchar(100),      [tools_equip_ppe]     varchar(100),      [hv_handle_safety]     varchar(100),      --[xev_lvl_1_service]    varchar(100),      --[xev_lvl_1_parts]     varchar(100),      [svc_parts_training]    varchar(100),      [tech_training]     varchar(100),      [sales_training]     varchar(100),      --[service_charge_equip]    varchar(100),      --[sales_charge_equip]    varchar(100),      [charge_equip]    varchar(100),      [service_training]     varchar(100),      [parts_training]     varchar(100),      [previous_day]      date,      [p_interest]      varchar(100),      [p_isuzu_connect_registered] varchar(100),      [p_isuzu_connect]     varchar(100),      --[p_lvl_1_2_techs]     varchar(100),      [p_lvl_1_2_techs_training]  varchar(100),      [p_tools_equip_ppe]    varchar(100),      [p_hv_handle_safety]    varchar(100),      --[p_xev_lvl_1_service]    varchar(100),      --[p_xev_lvl_1_parts]    varchar(100),      [p_svc_parts_training]    varchar(100),      [p_tech_training]     varchar(100),      [p_sales_training]     varchar(100),      --[p_service_charge_equip]   varchar(100),      --[p_sales_charge_equip]    varchar(100),      [p_charge_equip]    varchar(100),      [p_service_training]    varchar(100),      [p_parts_training]    varchar(100)      )       insert into @result_03     exec sp_utl_exec @sql,@debug       --declare @wholesale_ready_ev_cert varchar(5) = ''     --declare @wholesale_not_ready_ev_cert varchar(5) = ''       declare @wholesale_ready_ev_cert int = 0     declare @wholesale_not_ready_ev_cert int = 0       -- Became completly EV certified     set @wholesale_ready_ev_cert = (     --select 'Y'     select count(*)     from @result_03     where       --current day      ([interest] +       [isuzu_connect] +       --[lvl_1_2_techs] +       [lvl_1_2_techs_training] +       [tools_equip_ppe] +       [hv_handle_safety] +       --[xev_lvl_1_service] +       --[xev_lvl_1_parts]) = '11100100100100100'      [svc_parts_training]) = '11100100100100'      and      --current day      ([tech_training] +      [sales_training] +      --[service_charge_equip] +      --[sales_charge_equip] +      [charge_equip] +      [service_training] +      [parts_training]) = '100100100100100'      and      --prior day      (       ([p_interest] +         [p_isuzu_connect] +         --[p_lvl_1_2_techs] +         [p_lvl_1_2_techs_training] +        [p_tools_equip_ppe] +         [p_hv_handle_safety] +         --[p_xev_lvl_1_service] +         --[p_xev_lvl_1_parts]) <> '11100100100100100'        [p_svc_parts_training]) <> '11100100100100'      or       --prior day        ([p_tech_training] +        [p_sales_training] +        --[p_service_charge_equip] +        --[p_sales_charge_equip] +        [p_charge_equip] +        [p_service_training] +        [p_parts_training]) <> '100100100100100'      )     );          set @wholesale_not_ready_ev_cert = (     --select 'N'     select count(*)     from @result_03     where       --current day      (       ([interest] +         [isuzu_connect] +         --[lvl_1_2_techs] +         [lvl_1_2_techs_training] +         [tools_equip_ppe] +         [hv_handle_safety] +         --[xev_lvl_1_service] +         --[xev_lvl_1_parts]) <> '11100100100100100'        [svc_parts_training]) <> '11100100100100'       or       --current day        ([tech_training] +        [sales_training] +        --[service_charge_equip] +        --[sales_charge_equip] +        [charge_equip] +        [service_training] +        [parts_training]) <> '100100100100100'      )      and      --prior day      ([p_interest] +       [p_isuzu_connect] +       --[p_lvl_1_2_techs] +       [p_lvl_1_2_techs_training] +      [p_tools_equip_ppe] +       [p_hv_handle_safety] +       --[p_xev_lvl_1_service] +       --[p_xev_lvl_1_parts]) = '11100100100100100'      [p_svc_parts_training]) = '11100100100100'      and      --prior day      ([p_tech_training] +      [p_sales_training] +      --[p_service_charge_equip] +      --[p_sales_charge_equip] +      [p_charge_equip] +      [p_service_training] +      [p_parts_training]) = '100100100100100'     );       --if @wholesale_ready_ev_cert = 'Y'     if @wholesale_ready_ev_cert > 0     begin      ---- Construct the HTML email body      set @email_body_msg = '<html><body>';      set @email_body_msg = @email_body_msg + '<h2>EV Certified (Step 1 & Step 2)</h2>';      set @email_body_msg = @email_body_msg + '<p></p>';      set @email_body_msg = @email_body_msg + '<p>Which dealer is now EV Certified</p>';      set @email_body_msg = @email_body_msg + '<table bordercolor="BLUE" border="1" cellpadding="5" cellspacing="0">';      set @email_body_msg = @email_body_msg + '<tr>                 <th>Dealer Code</th>                 <th>Dealer Name</th>                 <th>Date</th>                 <th>Becoming EV Certified</th>                 <th>Isuzu Connect Registered</th>                 <th>Using Isuzu Connect</th>                 <th>High Voltage Vehicle Awareness Service Technician Training</th>                 <th>EV Special Service Tools & High Voltage PPE</th>                  <th>High Voltage Vehicle Awareness Training</th>                  <th>High Voltage Vehicle Awareness Svc Mgr/Svc Adv & Part Mgr/Part Cntr Training</th>                 <th>Instructor-led & Computer-based Service Technician Training</th>                  <th>Instructor-led & Computer-based Sales Training</th>                  <th>Dedicated EV Charger</th>                  <th>Instructor-led & Computer-based Svc Mgr/Svc Adv Training</th>                  <th>Instructor-led & Computer-based Part Mgr/Part Cntr Training</th>                 </tr>';      declare        @e3a_location_code    varchar(50),       @e3a_location_name    varchar(100),       @e3a_current_day    date,       @e3a_interest     varchar(100),       @e3a_isuzu_connect_registered varchar(100),       @e3a_isuzu_connect    varchar(100),       --@e3a_lvl_1_2_techs   varchar(100),        @e3a_lvl_1_2_techs_training  varchar(100),       @e3a_tools_equip_ppe   varchar(100),        @e3a_hv_handle_safety   varchar(100),        --@e3a_xev_lvl_1_service  varchar(100),       --@e3a_xev_lvl_1_parts   varchar(100),        @e3a_svc_parts_training   varchar(100),       @e3a_tech_training    varchar(100),        @e3a_sales_training    varchar(100),        --@e3a_service_charge_equip  varchar(100),        --@e3a_sales_charge_equip   varchar(100),       @e3a_charge_equip    varchar(100),       @e3a_service_training   varchar(100),        @e3a_parts_training    varchar(100),        @e3a_previous_day    date,       @e3a_p_interest     varchar(10),       @e3a_p_isuzu_connect_registered varchar(100),       @e3a_p_isuzu_connect   varchar(100),       --@e3a_p_lvl_1_2_techs   varchar(100),        @e3a_p_lvl_1_2_techs_training varchar(100),       @e3a_p_tools_equip_ppe   varchar(100),        @e3a_p_hv_handle_safety   varchar(100),        --@e3a_p_xev_lvl_1_service  varchar(100),       --@e3a_p_xev_lvl_1_parts  varchar(100),       @e3a_p_svc_parts_training  varchar(100),       @e3a_p_tech_training   varchar(100),        @e3a_p_sales_training   varchar(100),        --@e3a_p_service_charge_equip  varchar(100),        --@e3a_p_sales_charge_equip  varchar(100),       @e3a_p_charge_equip  varchar(100),       @e3a_p_service_training   varchar(100),       @e3a_p_parts_training   varchar(100)        declare ev_history_email_03a cursor for      select location_code,       location_name,       current_day,       interest,       isuzu_connect_registered,       isuzu_connect,       --lvl_1_2_techs,        lvl_1_2_techs_training,       tools_equip_ppe,        hv_handle_safety,        --xev_lvl_1_service,       --xev_lvl_1_parts,        svc_parts_training,       tech_training,        sales_training,        --service_charge_equip,        --sales_charge_equip,       charge_equip,       service_training,        parts_training,       previous_day,       p_interest,       p_isuzu_connect_registered,       p_isuzu_connect,       --p_lvl_1_2_techs,        p_lvl_1_2_techs_training,       p_tools_equip_ppe,        p_hv_handle_safety,        --p_xev_lvl_1_service,       --p_xev_lvl_1_parts,        p_svc_parts_training,       p_tech_training,        p_sales_training,        --p_service_charge_equip,        --p_sales_charge_equip,       p_charge_equip,       p_service_training,       p_parts_training      from @result_03      where       --current day      ([interest] +       [isuzu_connect] +       --[lvl_1_2_techs] +       [lvl_1_2_techs_training] +       [tools_equip_ppe] +       [hv_handle_safety] +       --[xev_lvl_1_service] +       --[xev_lvl_1_parts]) = '11100100100100100'      [svc_parts_training]) = '11100100100100'      and      --current day      ([tech_training] +      [sales_training] +      --[service_charge_equip] +      --[sales_charge_equip] +      [charge_equip] +      [service_training] +      [parts_training]) = '100100100100100'      and      --prior day      (       ([p_interest] +        [p_isuzu_connect] +        --[p_lvl_1_2_techs] +        [p_lvl_1_2_techs_training] +       [p_tools_equip_ppe] +        [p_hv_handle_safety] +        --[p_xev_lvl_1_service] +        --[p_xev_lvl_1_parts]) <> '11100100100100100'       [p_svc_parts_training]) <> '11100100100100'       or       --prior day       ([p_tech_training] +       [p_sales_training] +       --[p_service_charge_equip] +       --[p_sales_charge_equip] +       [p_charge_equip] +       [p_service_training] +       [p_parts_training]) <> '100100100100100'      )        open ev_history_email_03a;      fetch next from ev_history_email_03a into         @e3a_location_code,        @e3a_location_name,        @e3a_current_day,        @e3a_interest,        @e3a_isuzu_connect_registered,        @e3a_isuzu_connect,        --@e3a_lvl_1_2_techs,         @e3a_lvl_1_2_techs_training,        @e3a_tools_equip_ppe,         @e3a_hv_handle_safety,         --@e3a_xev_lvl_1_service,        --@e3a_xev_lvl_1_parts,         @e3a_svc_parts_training,        @e3a_tech_training,         @e3a_sales_training,         --@e3a_service_charge_equip,         --@e3a_sales_charge_equip,        @e3a_charge_equip,        @e3a_service_training,         @e3a_parts_training,        @e3a_previous_day,        @e3a_p_interest,        @e3a_p_isuzu_connect_registered,        @e3a_p_isuzu_connect,        --@e3a_p_lvl_1_2_techs,         @e3a_p_lvl_1_2_techs_training,        @e3a_p_tools_equip_ppe,         @e3a_p_hv_handle_safety,         --@e3a_p_xev_lvl_1_service,        --@e3a_p_xev_lvl_1_parts,        @e3a_p_svc_parts_training,        @e3a_p_tech_training,         @e3a_p_sales_training,          --@e3a_p_service_charge_equip,        --@e3a_p_sales_charge_equip,        @e3a_p_charge_equip,        @e3a_p_service_training,        @e3a_p_parts_training        while @@FETCH_STATUS = 0      begin       set @email_body_msg = @email_body_msg + '<tr>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_location_code + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_location_name + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e3a_current_day, 101) + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_interest + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_isuzu_connect_registered + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_isuzu_connect + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_lvl_1_2_techs + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_lvl_1_2_techs_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_tools_equip_ppe + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_hv_handle_safety + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_xev_lvl_1_service + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_xev_lvl_1_parts + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_svc_parts_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_tech_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_sales_training + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_service_charge_equip + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_sales_charge_equip + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_charge_equip + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_service_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_parts_training + '</td>';       set @email_body_msg = @email_body_msg + '</tr>';       set @email_body_msg = @email_body_msg + '<tr>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_location_code + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_location_name + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + CONVERT(varchar, @e3a_previous_day, 101) + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_interest + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_isuzu_connect_registered + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_isuzu_connect + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_lvl_1_2_techs + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_lvl_1_2_techs_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_tools_equip_ppe + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_hv_handle_safety + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_xev_lvl_1_service + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_xev_lvl_1_parts + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_svc_parts_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_tech_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_sales_training + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_service_charge_equip + '</td>';       --set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_sales_charge_equip + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_charge_equip + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_service_training + '</td>';       set @email_body_msg = @email_body_msg + '<td>' + @e3a_p_parts_training + '</td>';       set @email_body_msg = @email_body_msg + '</tr>';        fetch next from ev_history_email_03a into         @e3a_location_code,        @e3a_location_name,        @e3a_current_day,        @e3a_interest,        @e3a_isuzu_connect_registered,        @e3a_isuzu_connect,        --@e3a_lvl_1_2_techs,         @e3a_lvl_1_2_techs_training,        @e3a_tools_equip_ppe,         @e3a_hv_handle_safety,         --@e3a_xev_lvl_1_service,        --@e3a_xev_lvl_1_parts,         @e3a_svc_parts_training,        @e3a_tech_training,         @e3a_sales_training,         --@e3a_service_charge_equip,         --@e3a_sales_charge_equip,        @e3a_charge_equip,        @e3a_service_training,         @e3a_parts_training,        @e3a_previous_day,        @e3a_p_interest,        @e3a_p_isuzu_connect_registered,        @e3a_p_isuzu_connect,        --@e3a_p_lvl_1_2_techs,         @e3a_p_lvl_1_2_techs_training,        @e3a_p_tools_equip_ppe,         @e3a_p_hv_handle_safety,         --@e3a_p_xev_lvl_1_service,        --@e3a_p_xev_lvl_1_parts,        @e3a_p_svc_parts_training,        @e3a_p_tech_training,         --@e3a_p_sales_training,          --@e3a_p_service_charge_equip,        @e3a_p_charge_equip,        @e3a_p_service_training,        @e3a_p_parts_training      end;        close ev_history_email_03a;      deallocate ev_history_email_03a;        set @email_body_msg = @email_body_msg + '</table>';       end       -- No longer EV certified     --if @wholesale_not_ready_ev_cert = 'N'     if @wholesale_not_ready_ev_cert > 0     begin      if @email_body_msg is NULL      begin       set @email_body_msg = '<html><body>';       set @email_body_msg = @email_body_msg + '<h2>EV Certified (Step 1 & Step 2)</h2>';       set @email_body_msg = @email_body_msg + '<p></p>';      end       else      begin       set @email_body_msg = @email_body_msg + '<p></p>';       set @email_body_msg = @email_body_msg + '<p><b>==================================================================</b></p>';       set @email_body_msg = @email_body_msg + '<p></p>';       set @email_body_msg = @email_body_msg + '<p>Which dealer is no longer EV Certified</p>';       set @email_body_msg = @email_body_msg + '<p></p>';       set @email_body_msg = @email_body_msg + '<table bordercolor="BLUE" border="1" cellpadding="5" cellspacing="0">';       set @email_body_msg = @email_body_msg + '<tr>                  <th>Dealer Code</th>                  <th>Dealer Name</th>                  <th>Date</th>                  <th>Becoming EV Certified</th>                  <th>Isuzu Connect Registered</th>                  <th>Using Isuzu Connect</th>                  <th>High Voltage Vehicle Awareness Service Technician Training</th>                   <th>EV Special Service Tools & High Voltage PPE</th>                   <th>High Voltage Vehicle Awareness Training</th>                   <th>High Voltage Vehicle Awareness Svc Mgr/Svc Adv & Part Mgr/Part Cntr Training</th>                  <th>Instructor-led & Computer-based Service Technician Training</th>                   <th>Instructor-led & Computer-based Sales Training</th>                   <th>Dedicated EV Charger</th>                   <th>Instructor-led & Computer-based Svc Mgr/Svc Adv Training</th>                   <th>Instructor-led & Computer-based Part Mgr/Part Cntr Training</th>                  </tr>';        declare         @e3b_location_code varchar(50),        @e3b_location_name varchar(100),        @e3b_current_day date,        @e3b_interest varchar(100),        @e3b_isuzu_connect_registered varchar(100),        @e3b_isuzu_connect varchar(100),        --@e3b_lvl_1_2_techs varchar(100),         @e3b_lvl_1_2_techs_training varchar(100),        @e3b_tools_equip_ppe varchar(100),         @e3b_hv_handle_safety varchar(100),         --@e3b_xev_lvl_1_service varchar(100),        --@e3b_xev_lvl_1_parts varchar(100),         @e3b_svc_parts_training varchar(100),        @e3b_tech_training varchar(100),         @e3b_sales_training varchar(100),         --@e3b_service_charge_equip varchar(100),         --@e3b_sales_charge_equip varchar(100),        @e3b_charge_equip varchar(100),        @e3b_service_training varchar(100),         @e3b_parts_training varchar(100),         @e3b_previous_day date,        @e3b_p_interest varchar(10),        @e3b_p_isuzu_connect_registered varchar(100),        @e3b_p_isuzu_connect varchar(100),        --@e3b_p_lvl_1_2_techs varchar(100),         @e3b_p_lvl_1_2_techs_training varchar(100),        @e3b_p_tools_equip_ppe varchar(100),         @e3b_p_hv_handle_safety varchar(100),         --@e3b_p_xev_lvl_1_service var
    sp_rpt_dcn_ev_training_ind SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_ev_training_ind] @parms xml = null,
    @debug char(1) = 'n',
    @userid varchar(max) = null,
    @personnel_group_id varchar(max) = null as
    /*  Purpose: To show a individual ev members online training completeion  Notes: No date filter required or coded as of last alteration    History:  2025-01-03 aw initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_year_id1 int,    --table name  @personnel_table varchar(max),  @date_table varchar(max),  @courses_table varchar(max)      -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @date_year_id1 = 12  select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_year_id1  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @geo_filter = cast(@geo_value as varchar)  set @date_filter = '(c.date_id >= '''+@date1+''') and (c.date_id <= '''+@date2+''')'  set @dealer_filter = 'dealer = '''+@location_code+''''  set @personnel_table = 'ICTA_IDEAS_DWX.dbo.act_train_nev_personnel'  set @courses_table = 'ICTA_IDEAS_DWX.dbo.act_train_nev_learning'    set @sql =  '  select   concat(dbo.fn_capitalize(a.first_name),'' '',dbo.fn_capitalize(a.last_name)) name,  a.user_id,  b.learning_type,  b.course_no,  b.course_name,  b.completion_flag,  cast(b.completion_date as varchar(max)) ''completion_date'',  b.ilt_date,  b.ilt_location,  concat(dbo.fn_capitalize(b.ilt_trainer_first_name),'' '',dbo.fn_capitalize(b.ilt_trainer_last_name)) trainer_name,  b.insert_date,  b.rec_id,  a.personnel_group_id  from '+@personnel_table+' a  join '+@courses_table+' b  on a.user_id = b.user_id and a.personnel_group_id = b.personnel_group_id  where b.personnel_group_id = '+@personnel_group_id+'  '    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0  /*  */  
