 Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_exec_message] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */  
    sp_rpt_dcn_fv_vs_total_parts SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_fv_vs_total_parts] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: To get the fv parts sales vs total parts sales    Notes:    History:  2023-11-30 DD initial development.  2024-08-15 bh update for schema level usd to cad conversion ONLY!!! for tables used in reports. Minor cleanup.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @geo_join varchar(max),  @date_year_id1 int,  @year_filter varchar(4),  @sch varchar(100),    --table name  @part_table varchar(max) = 'dbo.fact_part',  @date_table varchar(max) = 'dim_date'    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    -- Build report query.  set @date_year_id1 = 12  select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @date_filter = '(a.date_id >= '''+@date1+''') and (a.date_id <= '''+@date2+''')'    select @sch = isnull(parm0,'dbo') from rpt_report where report_id = @report_id  set @part_table = replace(@part_table,'dbo',@sch)    set @sql =   '  select a.location_id  , a.date_id  , sum(a.fleetvalue_amount) ''fleetvalue''  , sum(a.fleetval_amount) ''fleetval''  , sum(a.fleetoil_amount) ''fleetoil''  , sum(a.total_part_amount) ''total_parts''  , b.date_name_yy_mon ''year_month''  , (sum(a.fleetvalue_amount) / sum(a.total_part_amount)) ''percent parts/sales''    from '+@part_table+' as a    join '+@date_table+' as b  on a.date_id = b.date_id    where '+@geo_filter+' and '+@date_filter+'  group by a.location_id  , a.date_id  , b.date_name_yy_mon  order by a.location_id  , a.date_id  , b.date_name_yy_mon    '  exec sp_utl_exec @sql, @debug  -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_FV_vs_total_parts] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */  
    sp_rpt_dcn_ichiban_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_ichiban_overview] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: Backorders for Dealer Visit  Notes: this has no dates as of now and is showing all activitve back orders    History:  2024-04-12 DD Initial Development  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),      --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_filter3 varchar(max),    --table name  @Ichiban_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 8)  set @Ichiban_table = 'ICTA_IDEAS_DWX.[dbo].[dlr_ichiban]'  set @date_table = 'dim_date'  set @date_filter = '(a.date_id between '+@date1+' and '+@date2+')'  set @date_filter2 = '(date_id between '+@date1+' and '+@date2+')'  set @date_filter3 = '(select max(date_id) from [dcn].[dlr_ichiban] where date_id between '+@date1+' and '+@date2+') between '+@date1+' and '+@date2+' '        if @rpt_lvl = 1  begin  set @sql =  '  select   location_name  , (case when qualified = ''N'' then ''NO''     when qualified = ''Y'' then ''YES'' else ''No Data'' end) ''qualified''    from '+@Ichiban_table+'  where location_code = '''+@location_code+''' and date_id = (select max(date_id) from '+@Ichiban_table+' where date_id between '+@date1+' and '+@date2+')     '  end  if @rpt_lvl = 2  begin     set @sql = '  select   date_id  , location_id  , location_code  , location_name  , region  , district  , qualified  , sales_obj  , vehicle_points  , cast(replace(part_sales, '','','''') as int) ''part_sales''  , csi_cust_trt  , csi_cust_exp  , csi_sch_tim  , csi_doc_chg  , insert_date  , rec_id  from '+@Ichiban_table+'  where location_code = '''+@location_code+''' and date_id = (select max(date_id) from '+@Ichiban_table+' where date_id between '+@date1+' and '+@date2+')  '  end    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [dbo].[sp_rpt_dcn_Ichiban_Overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 1  */    
    sp_rpt_dcn_ind_shr SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_ind_shr] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Sales in a given year for a single dealer (not seperated by type)grouped by month    Notes:    History:  2023-12-19 MG initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),    @result_tbl1 varchar(100),  @result_tbl2 varchar(100),  @result_tbl3 varchar(100),    --table name  @industry_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 0)  set @industry_table = 'fact_industry'  set @date_table = 'dim_date'  set @date_filter = '(date_id between '+@date1+' and '+@date2+')'        --Get Results   set @sql = '    select a.date_id   ,a.date_name_yy_mon   ,b.make     ,b.model   ,b.class   ,b.cab   ,b.fuel    ,b.drive    ,b.fleet   ,isnull(b.units,0) units     from (select date_id, date_name_yy_mon   from '+@date_table+'   where '+@date_filter+'    ) a  left join (   select a.date_id     ,b.lookup_name make    ,c.lookup_name model     ,d.lookup_name class     ,e.lookup_name cab     ,f.lookup_name fuel      ,g.lookup_name drive    ,h.lookup_name fleet    ,sum(a.units) units    from '+@industry_table+' as a    join geo_geo as x    on a.geo_id = x.geo_id    join dim_lookup as b on a.make_id = b.lookup_id and b.entity_name = ''make''    join dim_lookup as c on a.model_id = c.lookup_id and c.entity_name = ''vehmodel''    join dim_lookup as d on a.class_id = d.lookup_id and d.entity_name = ''class''    join dim_lookup as e on a.cab_id = e.lookup_id and e.entity_name = ''cab''    join dim_lookup as f on a.fuel_id = f.lookup_id and f.entity_name = ''fuel''    join dim_lookup as g on a.wheel_id = g.lookup_id and g.entity_name = ''wheel''    join dim_lookup as h on a.fleet_id = h.lookup_id and h.entity_name = ''fleet''   where '+@date_filter+' and '+@geo_filter+'   group by a.date_id    ,b.lookup_name    ,c.lookup_name     ,d.lookup_name     ,e.lookup_name     ,f.lookup_name      ,g.lookup_name    ,h.lookup_name   ) b  on a.date_id = b.date_id  where make is not null'      exec sp_utl_exec @sql, @debug  -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_ind_shr] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>8</geo_value><geo_title>Dealer = TOMS Truck (60435)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */    
    sp_rpt_dcn_inven_type_sales SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_inven_type_sales] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: To Determine the Current Invenotry of a Dealer (not currenty scalable to larger geographies)    Notes:  RDL FILES:  dcn_dashboard_inven_sale.rdl    History:  2023-11-28 DD initial development.  2024-10-01 AW Modified set @inventory_table =     FROM '[ICTA_IDEAS_DWX].[dbo].[sales_inventory]'   TO '[ICTA_IDEAS_DWX].[dbo].[sales_inventory_by_vin]'  2024-10-07 mg update to exclude a date filter in the where clause in order to see all orders  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,  @date1 varchar(5),  @date2 varchar(5),  @year_filter int,      --@status_id smallint,  @dept_id smallint,  --@search varchar(100),    --table name  @inventory_table Varchar(max),  @date_table varchar(max),    -- Query vars.  @sql varchar(4000),  @location_code varchar(6),  @dealer_filter varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    set @location_code = (select location_code from dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  set @inventory_table = '[ICTA_IDEAS_DWX].[dbo].[sales_inventory_by_vin]'  select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id        if @rpt_lvl =  1   begin  --lvl 1 equals dashboard and lvl 2 is for drillthrough---   set @sql =   '    SELECT dealer    , series    , sum(cast(quantity as int)) ''inventory''    , date_id    FROM '+@inventory_table+'     WHERE '+@dealer_filter+'    and date_id = (select max(date_id) from '+@inventory_table+' where date_id between '''+@date1+''' and '''+@date2+''')    GROUP BY dealer    , series    , date_id    ORDER BY dealer    , series    , date_id   '  end  if @rpt_lvl =  2   begin  set @sql =   '    SELECT     [dealer],    left([model],4) [model_year],    right([model],3) [model],    [series],    [occ],    [vin],    [sales_order],    [sales_item],    [wholesale_date],    --(substring([wholesale_date],5,2)+''/''+substring([wholesale_date],7,2)+''/''+substring([wholesale_date],1,4)  [wholesale_date],    [ship_to],    [customer_name],    [inv_age]   FROM '+@inventory_table+'   WHERE  '+@dealer_filter+'    and date_id = (select max(date_id) from '+@inventory_table+' where date_id between '''+@date1+''' and '''+@date2+''')   '  end    exec sp_utl_exec @sql, @debug  -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_inven_type_sales] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */  
    sp_rpt_dcn_iris_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_iris_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-16 DD initial development.  2024-09-09 mg update YTD calculation to case ytd_net_utilization as a float   20250130 DD added date filter to incoming data (This is to help the Dashboard handle different years/date filters)  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @year_filter int,    --table name  @iris_table varchar(max),  @temp_table varchar(max)      -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')      set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  set @date_filter = dbo.fn_get_date_filter(@date_type_id, 8)  set @iris_table = '[ICTA_IDEAS_DWX].[dbo].[service_iris_partseye_perf]'  set @temp_table = '##temp_table' + replace(newid(),'-','_')      select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)      set @sql =  '    SELECT *   INTO '+@temp_table+'   FROM '+@iris_table+'   WHERE '+@dealer_filter+' and date_id = (select max(date_id) from '+@iris_table+' where date_id between '''+@date1+''' and '''+@date2+''')     alter table '+@temp_table+'  add [National_Avg] float    update '+@temp_table+'  set [National_Avg] =  (select AVG(cast(replace(ytd_net_utilization,'','','''') as float)) FROM '+@iris_table+')       select * from '+@temp_table+'      '  exec sp_utl_exec @sql, @debug  -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_Iris_overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y'  */       
    sp_rpt_dcn_iris_util_parts SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_iris_util_parts] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Utilization of the IRIS PartsEye    Notes:    History:  2023-11-30 DD initial development.  2025-03-03 DD updated date filter to respect the archived date_id's line 82  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),    --table name  @iris_table Varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 0)  set @iris_table = '[dwx].[service_iris_partseye_perf]'  set @date_filter = '(date_id between '+@date1+' and '+@date2+')'    set @sql =  '  select *  from '+@iris_table+'   where '+@dealer_filter+'  and  date_id = (select max(date_id) from '+@iris_table+' where date_id between '''+@date1+''' and '''+@date2+''')'    exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec ICTA_IDEAS_App.dbo.[sp_rpt_dcn_Iris_util_parts] '  <parms><report_id>715</report_id><geo_type_id>1</geo_type_id><geo_value>66</geo_value><geo_title>Dealer = TEC ISUZU TRUCK (70451)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2025YTD</time_title><request_id>1741030215006</request_id><_>1741030074811</_><user_id>ddaniel@sextantusa.com</user_id></parms>', 'y'  go    exec ICTC_IDEAS_App.dbo.[sp_rpt_dcn_Iris_util_parts] '  <parms>  <report_id>28</report_id  ><geo_type_id>1</geo_type_id>  <geo_value>1858</geo_value>  <geo_title>Dealer = Bannister Isuzu Truck (76004)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2023YTD</time_title>  <request_id>1699654671819</request_id>  <_>1699654658621</_>  <user_id>ddaniel@sextantusa.com</user_id>  <class_sale_id>1</class_sale_id>  </parms>', 'y'  go  */  
    sp_rpt_dcn_items SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_items] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates report content for dealer contact.    Notes:  1. geo_value is used to pass pkg_id from which location_id is determined.  2. An action items kpi notes is +2 in context of items ids.  3. Revisit: action item vs kpi / comments.    History:  2021-08-24 bh initial development.  2022-02-09 bh retrun pkg info.  2022-03-28 bh align action items & notes.  2022-04-07 bh inc item lengths.  2024-01-16 bh fix notes type.  2024-03-27 bh update for note id change and distinction between pkg notes and kpi notes.  2024-04-19 ak update for bug fix that was excluding KPI items in the Action Report  2024-04-25 ak update to handle single quotes in package messages  2026-01-30 mh just union on custom kpi or causes duplicates  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @date_type_id smallint,  @geo_type_id smallint,  @geo_value varchar(100),  @pkg_id varchar(100),    -- Query vars.  @sql varchar(4000),  @code varchar(100),  @pkg_date  smalldatetime,  @pkg_user varchar(100),  @pkg_items varchar(4000),  @pkg_msg varchar(4000),  @date char(10),  @t1 varchar(100) = '##t1'+replace(newid(),'-','_'),  @t2 varchar(100) = '##t2'+replace(newid(),'-','_'),  @t3 varchar(100) = '##t3'+replace(newid(),'-','_')    -- Constants.  declare @item_action varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'action')  declare @item_custom varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'custom')  declare @item_report varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'report')  declare @item_note varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'note')  declare @item_kpi varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'kpi')    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @pkg_id = @parms.value('/parms[1]/geo_value[1]','varchar(100)')    -- Get config parms.  --set @country = (select parm_value from app_config where parm_name = 'country')    -- Return model (demo) report content for report designer.  if (@parms is null) begin   set @pkg_id=2  end    -- Build query.  select @geo_value = location_id, @pkg_date=pkg_date, @pkg_user=insert_user_id,@pkg_items=items,@pkg_msg=replace(msg,'''','''''')  from pkg.contact_pkg  where pkg_id = @pkg_id    select @code=location_code  from dim_location  where location_id = @geo_value    set @date = CONVERT(CHAR(10),@pkg_date,126)    exec sp_utl_drop_table @t1, @debug  exec sp_utl_drop_table @t2, @debug  exec sp_utl_drop_table @t3, @debug    -- Items less notes.  set @sql = '  select name,value,type,data,id  into '+@t1+'  from openjson('''+replace(@pkg_items,'''','''''')+''', ''$'')  with (name varchar(100) ''$.name'',          value varchar(1000) ''$.value'',     type varchar(100) ''$.type'',     data varchar(1000) ''$.data'',     id varchar(100) ''$.id'')  where type in ('+@item_action+','+@item_custom+','+@item_report+')  order by type'    exec sp_utl_exec @sql, @debug    -- Notes.  set @sql = '  select name,value,type,data,id  into '+@t2+'  from openjson('''+replace(@pkg_items,'''','''''')+''', ''$'')  with (name varchar(100) ''$.name'',          value varchar(1000) ''$.value'',     type varchar(100) ''$.type'',     data varchar(1000) ''$.data'',     id varchar(100) ''$.id'')  where type in('+@item_note+')  order by type'    exec sp_utl_exec @sql, @debug    -- KPIs:  set @sql = '  select name,value,type,data,id  into '+@t3+'  from openjson('''+replace(@pkg_items,'''','''''')+''', ''$'')  with (name varchar(100) ''$.name'',          value varchar(1000) ''$.value'',     type varchar(100) ''$.type'',     data varchar(1000) ''$.data'',     id varchar(100) ''$.id'')  where type in('+@item_kpi+')  order by type'    exec sp_utl_exec @sql, @debug    -- Final result.  set @sql = '  select ''Info'' name,'''+@pkg_user+''' value, ''0'' type,'''+@date+''' data, 0 id, '''+@pkg_msg+''' data2, '''' data3, '''' data4, '''' data4_unit  union  select a.name,a.value,isnull(a.type,b.type) type,a.data,a.id,b.value data2,c.name data3,d.kpi data4,e.kpi_unit data4_unit  from '+@t1+' a   left join '+@t2+' b on a.id+2 = b.id  left join '+@t3+' c on a.id+1 = c.id  left join dcn.action_item_kpi d on c.value = d.kpi_id and d.pkg_id = '+ltrim(str(@pkg_id))+'  left join dcn.kpi e on d.kpi_id = e.kpi_id'    exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0  
    sp_rpt_dcn_loc_message SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_loc_message] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Get DCN location msg UI url.    Notes:    History:  2023-11-28 DD initial development.  2024-01-22 bh update for UI change and minor cleanup.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    -- Query vars.  @sql varchar(4000),  @msg_url varchar(100) = '/contact/update_loc_msg?id=',  @url varchar(1000)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')    select @url=parm_value+@msg_url+@geo_value  from app_config  where parm_name = 'site_url'    select *,@url url  from dcn.location_msg  where location_id = @geo_value    --exec sp_utl_exec @sql, @debug  -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0  
    sp_rpt_dcn_lvsd_theme SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_lvsd_theme] @parms xml = null,
    @LvsD int,
    @debug char(1) = 'n' as
    /*  Purpose: To Determine the Current R12 pump in numbers    Notes:    History:  2023-11-28 DD initial development.  2024-06-20 ak update to add comment dynamic visibility for dashboard printing  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),      --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_year_id1 int,  @msg_visibility int,    --table name  @customer_table varchar(max),  @geo_table varchar(max),  @date_table varchar(max),  @sale_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @customer_table = ' [ICTA_IDEAS_App].[dbo].dim_customer'  set @geo_table = '[dbo].geo_geo'  set @sale_table = '[dbo].fact_sale'   set @date_year_id1 = 12    set @msg_visibility = isnull((select parm2 from rpt_report where report_id = @report_id),0)    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 0 and date_year_id = @date_year_id1  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @geo_filter = cast(@geo_value as varchar)  set @date_filter = '(c.date_id >= '''+@date1+''') and (c.date_id <= '''+@date2+''')'  set @dealer_filter = 'b.location_id = '''+@geo_filter+''''      if @LvsD = 1 begin   set @sql =   '   select ''light'' theme, ''#ffffff'' background_color, ''#ff0000'' lines, ''#000000'' text, ''#000000'' Bars, ''#ff0000'' barchart_lines, ''#808080'' barchart_text, ''#808080'' bar_line, '+ltrim(str(@msg_visibility))+' msg_visibility   '  end  else begin   set @sql =   '   select ''dark'' theme, ''#474747'' background_color, ''#ff0000'' lines, ''#d3d3d3'' text, ''#d3d3d3'' Bars, ''#ff0000'' barchart_lines, ''#808080'' barchart_text, ''#808080'' bar_line, '+ltrim(str(@msg_visibility))+' msg_visibility   '  end    exec sp_utl_exec @sql, @debug      -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end      return 0       --test parm  /*  exec [sp_rpt_dcn_LvsD_theme] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 1, 'n'  */  
    sp_rpt_dcn_management_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_management_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-14 DD initial development.  2026-03-18 taw added guard to ensure this does not fail when state is geography selected for report EV Readiness Dashboard  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @tablename varchar(max),  @tablename2 varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')  set @tablename = '[ICTA_SURVEY].dbo.[personnel]'  set @tablename2 = 'dim_location'    -- Guard clause: management_overview is Dealer-only  IF @geo_type_id <> 1  BEGIN      SELECT geo_type_id = @geo_type_id;      RETURN;  END;    set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @geo_filter = 'dealer = '''+@location_code+''''      set @sql =  '  select   a.DealerCode,   (case when a.Role like ''%Executive Manager%'' then ''Executive Manager'' else a.Role end) ''Role'' ,  (UPPER(a.FirstName) + '' '' + UPPER(a.LastName)) ''Name'',  (case when a.Role like ''%Dealer Principal%'' then 1      when a.Role like ''%Executive Manager%'' then 2     when a.Role = ''Sales Manager'' then 3     when a.Role = ''Service Manager'' then 4     when a.Role = ''Parts Manager'' then 5     when a.Role = ''Warranty Manager'' then 6       else 40 end)''list order'',  (b.location_name + '' (''+ b.location_code+ '')'') ''location_name'',  c.lookup_name ''Region'',  right(d.district1, 1) ''Sales_District'',  d.district2 ''Service_District''  from '+@tablename+' as a    join vw_dim_location_wif as b  on a.DealerCode = b.location_code    join geo_lookup as c  on b.region = c.lookup_code and c.entity_name = ''Region''    join '+@tablename2+' as d  on d.location_code = a.DealerCode    where a.DealerCode = '''+@location_code+'''    group by a.DealerCode, a.role , a.FirstName, a.LastName, b.location_name, b.location_code, c.lookup_name, d.district1, d.district2    order by [list order]  '  exec sp_utl_exec @sql, @debug  -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    -- test parm  /*  exec sp_rpt_dcn_management_overview   '<parms>  <report_id>715</report_id>  <geo_type_id>4</geo_type_id>  <geo_value>8</geo_value>  <geo_title>Dealer = TOMS ISUZU TRUCK CTR-ORA (60435)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2025YTD</time_title>  <request_id>1742843232677</request_id>  <_>1742843208062</_><user_id>  awilson@sextantusa.com</user_id>  </parms>','y'  */    
    sp_rpt_dcn_package SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_package] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates report content for dealer contact packages.    History:  2021-09-24 bh initial development.  2022-03-21 bh update for national geo.  2023-10-18 bh update for new DCN changes.  2023-10-30 bh update to also handle KPI details.  2024-01-17 bh update for KPI comments.  2024-02-03 bh update for left join to kpi metrics.  2025-03-21 taw isnull logic for KPI Status  2025-12-04 mh expanded size of json variable in loop  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @geo_filter varchar(100),  --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(8000),  @filter varchar(500) = '1=1',  @result1 varchar(100) = '##dcnres1'+replace(newid(),'-','_'),  @result2 varchar(100) = '',  @use_kpi int,  @kpi_data varchar(1000) = '',  @kpi_list varchar(1000) = '',  @alias varchar(100) = 'b.'    -- Constants.  declare @item_action varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'action')  declare @item_kpi varchar(10) = (select lookup_id from dim_lookup where entity_name = 'pkg_item_type' and lookup_name= 'kpi')    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  --set @status_id = isnull(@parms.value('/parms[1]/status_id[1]','smallint'),0)  set @dept_id = isnull(@parms.value('/parms[1]/department_id[1]','smallint'),0)  set @date1 = @parms.value('/parms[1]/date1[1]','varchar(100)')  set @date2 = @parms.value('/parms[1]/date2[1]','varchar(100)')  --set @search = @parms.value('/parms[1]/search[1]','varchar(100)')    -- Get config parms.  --set @country = (select parm_value from app_config where parm_name = 'country')    -- Return model (demo) report content for report designer.  if (@parms is null) begin   --select * from rpt_tpl_dcn_package   return  end    -- Build query.  select @use_kpi=isnull(parm2,0)  from rpt_report  where report_id = @report_id    select @geo_filter=geo_filter  from dbo.fn_get_geo_parts('table',@geo_type_id, @geo_value, 0)    set @geo_filter = (case when left(@geo_filter,4) = 'dist' then replace(@geo_filter,'district','district1') else @geo_filter end)  set @alias = (case when @geo_filter = '1=1' then '' else @alias end)    --set @filter = @filter + case   --when @status_id > 0 then ' and a.status_id='+str(@status_id,2) else '' end    set @filter = @filter + case   when @dept_id > 0 then ' and a.dept_id='+str(@dept_id,2) else '' end    set @filter = @filter + case   when len(@date1) > 1 then ' and a.pkg_date>='+''''+@date1+'''' else '' end  set @filter = @filter + case   when len(@date2) > 1 then ' and a.pkg_date<='+''''+@date2+'''' else '' end    --set @filter = @filter + case   --when len(@search) > 0 then ' and a.items like ''%'+@search+'%''' else '' end    exec sp_utl_drop_table @result1, @debug    set @sql = '  select   a.pkg_id,  a.pkg_date,  a.insert_user_id,  a.update_date,  a.update_user_id,  b.location_code,  b.location_name,  c.lookup_name status_name,  (case when a.items like ''%report: bund%'' then ''Yes'' else ''No'' end) report_pkg,  ''DC''+location_code+''_''+CONVERT(CHAR(8),a.pkg_date,112)+str(a.dept_id,1) contact_pkg,  d.lookup_name dept_name,  e.lookup_name regdst1,  left(e.lookup_name,len(e.lookup_name)-1)+b.district2 regdst2,  a.items,  a.msg pkg_notes  into '+@result1+'  from   pkg.contact_pkg a  join   dim_location b on a.location_id = b.location_id  join  dim_lookup c on  a.status_id = c.lookup_id and c.entity_name = ''data_op'' and c.lookup_name <> ''delete''  join  dim_lookup d on a.dept_id = d.lookup_id and d.entity_name = ''department''  join  geo_lookup e on b.district1 = e.lookup_code and e.entity_name=''regdst''  where '+@alias+@geo_filter+' and '+@filter    exec sp_utl_exec @sql, @debug    --if (@use_kpi = 0) begin    --end    if (@use_kpi > 0) begin   set @result2=replace(@result1,'res1','res2')   exec sp_utl_drop_table @result2, @debug     set @sql = '   create table '+@result2+'(pkg_id int, n varchar(100), v varchar(1000), type int, d varchar(1000), id2 int)'     exec sp_utl_exec @sql, @debug     set @sql = '   declare @i int   declare @p varchar(8000)   declare c cursor for   select pkg_id,items    from '+@result1+'     open c   fetch next from c into @i, @p     while (@@fetch_status = 0)   begin    insert into '+@result2+'    select @i,name,value,type,data,id    from openjson(@p, ''$'')    with (name varchar(100) ''$.name'',         value varchar(1000) ''$.value'',       type varchar(100) ''$.type'',       data varchar(1000) ''$.data'',       id varchar(100) ''$.id'')    where type in('+@item_action+','+@item_kpi+')      fetch next from c into @i, @p   end   close c   deallocate c'     exec sp_utl_exec @sql, @debug     set @kpi_data = '   join '+@result2+' b on a.pkg_id=b.pkg_id   left join dcn.action_item_kpi_min c on b.pkg_id = c.pkg_id and b.type='+@item_kpi+' and b.v = c.kpi_id   left join dcn.action_item_kpi_max d on b.pkg_id = d.pkg_id and b.type='+@item_kpi+' and b.v = d.kpi_id   join '+@result2+' e on a.pkg_id=e.pkg_id and e.type='+@item_action+' and e.id2 = b.id2-1   left join dcn.kpi_msg f on a.pkg_id = f.pkg_id and e.v = f.action_id and b.v = f.kpi_id   left join dim_lookup g on f.kpi_status_id = g.lookup_id and g.entity_name = ''kpi_status_id''   left join dcn.kpi h on b.v = h.kpi_id'     set @kpi_list = '   ,b.n kpi_name,   cast(b.d as date) tgt_date,   c.kpi kpi1,   d.kpi kpi2,   e.v action_id,   b.v kpi_id,   f.msg,   g.lookup_id kpi_status,   h.kpi_unit   '  end      set @sql = '  select a.*'+@kpi_list+' from '+@result1+' a '+@kpi_data    exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0  
    sp_rpt_dcn_parts_coop_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_parts_coop_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-16 DD initial development.  2025-01-30 DD addd date_id filter (this is to address diferent time filter requirements)  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @year_filter varchar(max),    --table name  @coop_table varchar(max)      -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')      set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    set @date_filter = 'year = '+@year_filter+''  set @coop_table = '[dwx].[service_coop]'    select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @sql =    '   SELECT   (case when left(valid_from,2) = ''01'' then concat(''Jan-Jun '', year) else concat(''Jul-Dec '', year) end) ''period'',   total_reward,   reward_used,   reward_remaining,   (case when left(valid_from, 2) = ''01'' then 1 else 2 end)''ordered''  FROM '+@coop_table+'  WHERE '+@date_filter+' and '+@dealer_filter+'  '      exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_Parts_coop_overview] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y'  */  
    sp_rpt_dcn_parts_dppp SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_parts_dppp] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: Calculates the DPPP Accrual for the Serive & Parts DCN Dashboard    Notes:    History:  2024-07-24 ak initial development.  2024-08-13 bh update for schema level usd to cad conversion ONLY!!! for tables used in reports.  2025-03-03 taw Uncommented the variable @sch when running in ICTC we need the cad conversion.  2025-03-25 taw Dashboard Display Fix - If status = "claimed," "expired," "unavailable”. Show $0 on the dashboard.  2025-08-12 taw updated to use the @dppp_tbl in @rpt_lvl int = 1 this was causing Canada numbers to be off from the drill-through in @rpt_lvl int = 2  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @ch_start varchar(max),  @ch_end varchar(max),  @ph_start varchar(max),  @ph_end varchar(max),  @parts_filter varchar(max),  @dppp_tbl varchar(max) = 'dwx.part_dppp',  @sch varchar(100)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @geo_filter=geo_filter  from dbo.fn_get_geo_parts(@dppp_tbl,@geo_type_id, @geo_value, 0)    /*  dsx.part_dppp is a view accessed by this procedure  parm0 is NULL in ICTA_IDEAS_App  parm0 is dsx in ICTC_IDEAS_App - This is for the cad conversion  */  select @sch = isnull(parm0,'dwx') from rpt_report where report_id = @report_id  set @dppp_tbl = replace(@dppp_tbl,'dwx',@sch)    if @rpt_lvl = 1 begin    if @date_type_id = 12 BEGIN     set @sql = '        SELECT     a.PeriodEnding,    a.DealerCode,          a.dpppaccrual ''dppp_accrual'',           a.status,           b.date_id ''date_id'',          ROW_NUMBER() OVER (ORDER BY b.date_id DESC) AS rn      FROM '+@dppp_tbl+' as a   join dim_date as b   on right(left(a.periodending,5),3) = b.month_name_short and right(a.periodending,4) = cast(b.date_year as varchar(max))    join dim_location c   on a.[dealercode] = c.location_code   where  c.'+@geo_filter+' and date_id = (select date_id from dim_date where date_year= (year(getdate())-1)  and date_month = 12)   '   END  ELSE   BEGIN   set @sql = '      WITH RankedData AS (      SELECT     a.PeriodEnding,    a.DealerCode,          a.dpppaccrual,           a.status,           b.date_id ''date_id'',          ROW_NUMBER() OVER (ORDER BY b.date_id DESC) AS rn      FROM '+@dppp_tbl+' as a   join dim_date as b   on right(left(a.periodending,5),3) = b.month_name_short and right(a.periodending,4) = cast(b.date_year as varchar(max))    join dim_location c   on a.[dealercode] = c.location_code   where  c.'+@geo_filter+'  )    SELECT       CASE            WHEN (SELECT status FROM RankedData WHERE rn = 2) = ''Available''          THEN (SELECT DPPPAccrual FROM RankedData WHERE rn = 2)    ELSE (0)    --ELSE (SELECT dpppaccrual FROM RankedData WHERE rn = 1)      END AS dppp_accrual  FROM RankedData as a  where rn = 1;    '  END  end  else if @rpt_lvl= 2 begin   set @sql = '   select   c.date_sql period_end,   cast(replace(a.partspurchasesytd,char(13),'''') as float) part_purchase_ytd,   cast(replace(a.dpppaccrual,char(13),'''') as float) dppp_accrual,   cast(replace(a.mandatoryscrapamount,char(13),'''') as float) mandatory_scrap,   cast(replace(a.maximumcleaninventoryamount,char(13),'''') as float) max_clean_inv,   a.status,   d.date_sql credit_date,   a.creditmemonumber credit_memo_num,   cast(replace(a.claimamount,char(13),'''') as float) claim_amount   from '+@dppp_tbl+' a   join dim_location b   on a.[dealercode] = b.location_code   join dim_date_day c   on right(left(a.periodending,5),3) = c.month_name_short and right(a.periodending,4) = cast(c.date_year as varchar(max)) and cast(left(a.periodending,2) as int) = c.date_day   left join dim_date_day d   on right(left(a.creditdate,5),3) = d.month_name_short and right(a.creditdate,4) = cast(d.date_year as varchar(max)) and cast(left(a.creditdate,2) as int) = d.date_day      where '+@geo_filter  end    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec sp_rpt_dcn_parts_dppp   '<parms><report_id>715</report_id>  <geo_type_id>1</geo_type_id>  <geo_value>329</geo_value>  <geo_title>Dealer = BENTLEY ISUZU TRUCK (63663)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2025YTD</time_title>  <request_id>1742843232677</request_id>  <_>1742843208062</_><user_id>  awilson@sextantusa.com</user_id>  </parms>','y',1    exec sp_rpt_dcn_parts_dppp   '<parms><report_id>715</report_id>  <geo_type_id>1</geo_type_id>  <geo_value>329</geo_value>  <geo_title>Dealer = BENTLEY ISUZU TRUCK (63663)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2025YTD</time_title>  <request_id>1742843232677</request_id>  <_>1742843208062</_><user_id>  awilson@sextantusa.com</user_id>  </parms>','y',2  */    
    sp_rpt_dcn_parts_incentives SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_parts_incentives] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: Calculates the national incentive participation for each dealer for 1st/2nd half of year by personnel and incentive type    Notes:    History:  2024-05-03 ak initial development  2025-01-31 TAW Added date filters  2025-03-05 TAW Modifications for PARTS FILTERS @ch_parts_filter and @ph_parts_filter based on date_id  2025-03-17 TAW Modification to calculation total_payments - added ISNUMERIC to prevent error:Conversion failed when converting the varchar value '(-16)' to data type int.  2025-06-26 TAW Added new incentives for back half current year  2025-07-31 mh adding dummy row to details so report can display when no actual results  2025-12-31 MS Added new incentives for 2026 1st half programs  2026-01-07 MS Updated for 2026YTD - date_type_id 11=2026YTD, 12=2025, 13=2024  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    -- Query vars.  @sql varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @ch_start varchar(max),  @ch_end varchar(max),  @ph_start varchar(max),  @ph_end varchar(max),  @ch_parts_filter varchar(max),  @ph_parts_filter varchar(max),  @date1 int,  @date2 int,  @year_filter int,    --database references  @dwx_db varchar(max) = '[ICTA_IDEAS_DWX].[dbo].',  @incentive_tbl varchar(max) = '[part_incentives]',  @tmp_result varchar(max) = '##temp_'+replace(newid(),'-','_'),  @prl_tbl varchar(max) = '##temp_prl_'+replace(newid(),'-','_')    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    select @geo_filter=geo_filter  from dbo.fn_get_geo_parts(@incentive_tbl,@geo_type_id, @geo_value, 0)    if month(getdate()) <= 6 and @year_filter = year(getdate())  begin -- CURRENT YEAR (First Half) - 2026 H1   set @ch_parts_filter = '(''N/A'')'   set @ph_parts_filter = '(''MPTI1'',''CHECKIN1'',''FVDEF2'',''FVDPF2'',''FVTIRE26'',''FV80W90'',''FVBRAKES2'',''MAINT'')'   set @ch_start = 'ltrim(str(year(getdate())))+''0701'''   set @ch_end = 'ltrim(str(year(getdate())))+''1231'''   set @ph_start = 'ltrim(str(year(getdate())))+''0101'''   set @ph_end = 'ltrim(str(year(getdate())))+''0630'''   PRINT '----Entered CURRENT YEAR logic for first half of the year (2026 H1 vs 2026 H2)';   PRINT '----Month = ' + cast(month(getdate()) as varchar(10))   PRINT '----Year = ' + cast(@year_filter as varchar(10))   PRINT '----Report ID = ' + cast(@report_id as varchar(10))  end    if month(getdate()) >= 7 and @year_filter = year(getdate())  begin -- CURRENT YEAR (Second Half) - 2026 H2   set @ch_parts_filter = '(''N/A'')'   set @ph_parts_filter = '(''MPTI1'',''CHECKIN1'',''FVDEF2'',''FVDPF2'',''FVTIRE26'',''FV80W90'',''FVBRAKES2'',''MAINT'')'   set @ch_start = 'ltrim(str(year(getdate())))+''0701'''   set @ch_end = 'ltrim(str(year(getdate())))+''1231'''   set @ph_start = 'ltrim(str(year(getdate())))+''0101'''   set @ph_end = 'ltrim(str(year(getdate())))+''0630'''   PRINT '----Entered CURRENT YEAR logic for second half of the year (2026 H2 vs 2026 H1)';   PRINT '----Month = ' + cast(month(getdate()) as varchar(10))   PRINT '----Year = ' + cast(@year_filter as varchar(10))   PRINT '----Report ID = ' + cast(@report_id as varchar(10))  end    if @year_filter = year(getdate())-1  begin -- PRIOR YEAR - 2025   set @ph_parts_filter = '(''FVWIPER25'',''FVDEF'',''FVDPF'',''FVTIRE25'',''FVBRAKES'',''FVWHEELSIM'')'   set @ch_parts_filter = '(''FVDEF1'',''FVDPF1'',''FVTIRE1'',''FVBRAKES1'',''FVWHEELSIM1'',''FVOILSLS'',''CHECKIN'',''MPTI'')'   set @ch_start = 'ltrim(str(year(getdate())-1))+''0701'''   set @ch_end = 'ltrim(str(year(getdate())-1))+''1231'''   set @ph_start = 'ltrim(str(year(getdate())-1))+''0101'''   set @ph_end = 'ltrim(str(year(getdate())-1))+''0630'''   PRINT '----Entered PRIOR YEAR logic (2025 H1 vs 2025 H2)';   PRINT '----Month = ' + cast(month(getdate()) as varchar(10))   PRINT '----Year = ' + cast(@year_filter as varchar(10))   PRINT '----Report ID = ' + cast(@report_id as varchar(10))  end    if @year_filter = year(getdate())-2  begin -- 2024   set @ph_parts_filter = '(''FVWHEELSIM'',''FVSHOCKS'',''FVWIPER'')'   set @ch_parts_filter = '(''ACCESSORIES'',''DFSC'',''FVTIRE'',''FVWIPER'')'   set @ch_start = 'ltrim(str(year(getdate())-2))+''0701'''   set @ch_end = 'ltrim(str(year(getdate())-2))+''1231'''   set @ph_start = 'ltrim(str(year(getdate())-2))+''0101'''   set @ph_end = 'ltrim(str(year(getdate())-2))+''0630'''   PRINT '----Entered 2024 logic (2024 H1 vs 2024 H2)';   PRINT '----Month = ' + cast(month(getdate()) as varchar(10))   PRINT '----Year = ' + cast(@year_filter as varchar(10))   PRINT '----Report ID = ' + cast(@report_id as varchar(10))  end    if @rpt_lvl = 1 begin   if month(getdate()) <= 6 and @year_filter = year(getdate()) begin    set @ch_parts_filter = @ph_parts_filter    set @ch_start = @ph_start    set @ch_end = @ph_end   end     if @year_filter = year(getdate()) - 1 begin    set @ch_parts_filter = '(''FVDEF1'',''FVDPF1'',''FVTIRE1'',''FVBRAKES1'',''FVWHEELSIM1'',''FVOILSLS'',''CHECKIN'',''MPTI'',''FVWIPER25'',''FVDEF'',''FVDPF'',''FVTIRE25'',''FVBRAKES'',''FVWHEELSIM'')'    set @ch_start = 'ltrim(str(year(getdate())-1))+''0101'''   end      if @year_filter = year(getdate()) - 2 begin    set @ch_parts_filter = '(''FVWHEELSIM'',''FVSHOCKS'',''FVWIPER'',''ACCESSORIES'',''DFSC'',''FVTIRE'')'    set @ch_start = 'ltrim(str(year(getdate())-2))+''0101'''   end      set @sql = '   select   a.location_name,   a.location_code,   isnull(b.total_incentives,0) total_incentives   from dim_location a   left join (   select   b.location_code,   sum(case    when a.[Payment Code] = ''NPI'' and a.[Payment Reference] in '+@ch_parts_filter+'    then 1   else 0   end) total_incentives   from '+@dwx_db+@incentive_tbl+' a   join dim_location b   on a.[Primary Dealer Code] = b.location_code   join dim_date_day c   on cast(a.[payment date] as date) = c.date_sql   where '+@geo_filter+' and    c.date_id between '+@ch_start+' and '+@ch_end+'   and year(cast([payment date] as date)) = '+cast(@year_filter as varchar(10))+'   group by   b.location_code) b   on a.location_code = b.location_code   where '+@geo_filter   end  else if @rpt_lvl= 2 begin   set @sql = '   ---------------------------   -- DRILL THROUGH REPORT   ---------------------------     create table '+@prl_tbl+' (    payment_reference varchar(50),    display_name varchar(50)   )     insert into '+@prl_tbl+' values   -- 2024 Programs   (''ACCESSORIES'', ''Accessories''),   (''DFSC'', ''DFSC''),   (''FVTIRE'', ''FV Tire''),   (''FVWIPER'', ''FV Wiper''),   (''FVWHEELSIM'', ''FV Wheel Sim''),   (''FVSHOCKS'', ''FV Shocks''),   -- 2025 First Half Programs   (''FVBRAKES'', ''FV Brakes''),   (''FVDEF'', ''FV DEF''),   (''FVDPF'', ''FV DPF''),   (''FVTIRE25'', ''FV Tire 25''),   (''FVWHEELSIM'', ''FV Wheel Sim''),   (''FVWIPER25'', ''FV Wiper 25''),   -- 2025 Second Half Programs   (''FVBRAKES1'', ''FV Brakes 1''),   (''FVDEF1'', ''FV DEF 1''),   (''FVDPF1'', ''FV DPF 1''),   (''FVTIRE1'', ''FV Tire 1''),   (''FVWHEELSIM1'', ''FV Wheel Sim 1''),   (''FVOILSLS'', ''FV Oil SP''),   (''CHECKIN'', ''Svc Adv Checkin''),   (''MPTI'', ''Tech MPTI''),   -- 2026 First Half Programs   (''MPTI1'', ''Tech MPTI 1''),   (''CHECKIN1'', ''Svc Adv Checkin 1''),   (''FVDEF2'', ''FV DEF 2''),   (''FVDPF2'', ''FV DPF 2''),   (''FVTIRE26'', ''FV Tire 26''),   (''FV80W90'', ''FV 80W90 Gear Oil''),   (''FVBRAKES2'', ''FV Brakes 2''),   (''MAINT'', ''Maintenance'')     select    x.*   into '+@tmp_result+'   from (select * from   (select distinct   ''ch'' period,   '+@ch_start+' period_start,   '+@ch_end+' period_end,   location_name,   location_code,   concat([First Name],'' '',[Last Name]) personnel   from icta_ideas_dwx.dbo.part_incentives a   join dim_location b   on a.[Primary Dealer Code] = b.location_code   where '+@geo_filter+'   and [Payment Code] = ''NPI''   and ([Payment Reference] in '+@ch_parts_filter+'   or [Payment Reference] in '+@ph_parts_filter+')) a   cross join    (select distinct   [Payment Reference] payment_reference   from icta_ideas_dwx.dbo.part_incentives a   join dim_location b   on a.[Primary Dealer Code] = b.location_code   where  [Payment Code] = ''NPI'' and [Payment Reference] in '+@ch_parts_filter+') b   union select * from    (select distinct   ''ph'' period,   '+@ph_start+' period_start,   '+@ph_end+' period_end,   location_name,   location_code,   concat([First Name],'' '',[Last Name]) personnel   from icta_ideas_dwx.dbo.part_incentives a   join dim_location b   on a.[Primary Dealer Code] = b.location_code   where '+@geo_filter+'   and [Payment Code] = ''NPI''   and ([Payment Reference] in '+@ch_parts_filter+'   or [Payment Reference] in '+@ph_parts_filter+')) a   cross join    (select distinct   [Payment Reference] payment_reference   from icta_ideas_dwx.dbo.part_incentives a   join dim_location b   on a.[Primary Dealer Code] = b.location_code   where  [Payment Code] = ''NPI'' and [Payment Reference] in '+@ph_parts_filter+') b ) x     select   a.period,   cast(a.period_start as date) period_start,   cast(a.period_end as date) period_end,   a.location_code,   a.location_name,   a.personnel,   isnull(prl.display_name, a.payment_reference) as payment_reference,   isnull(b.total_incentives,0) total_incentives,   isnull(b.total_payments,0) total_payments     from '+@tmp_result+' a   left join '+@prl_tbl+' prl on a.payment_reference = prl.payment_reference   left join (select    b.location_code,   b.location_name,   '+@ch_start+' period_start,   '+@ch_end+' period_end,   concat([First Name],'' '',[Last Name]) personnel,   [Payment Reference] payment_reference,   count(*) total_incentives,   SUM(CASE               WHEN ISNUMERIC(REPLACE(REPLACE(REPLACE([payment amount], ''$'', ''''), ''.00'', ''''), '','', '''')) = 1               THEN CAST(REPLACE(REPLACE(REPLACE([payment amount], ''$'', ''''), ''.00'', ''''), '','', '''') AS INT)               ELSE 0     END) AS total_payments   from '+@dwx_db+@incentive_tbl+' a   join dim_location b   on a.[Primary Dealer Code] = b.location_code    join dim_date_day c   on cast(a.[payment date] as date) = c.date_sql   where '+@geo_filter+'   and c.date_id between '+@ch_start+' and '+@ch_end+'   group by   b.location_code,   b.location_name,   concat([First Name],'' '',[Last Name]),   [Payment Reference]     union     select    b.location_code,   b.location_name,   '+@ph_start+' period_start,   '+@ph_end+' period_end,   concat([First Name],'' '',[Last Name]) personnel,   [Payment Reference] payment_reference,   count(*) total_incentives,   SUM(CASE               WHEN ISNUMERIC(REPLACE(REPLACE(REPLACE([payment amount], ''$'', ''''), ''.00'', ''''), '','', '''')) = 1               THEN CAST(REPLACE(REPLACE(REPLACE([payment amount], ''$'', ''''), ''.00'', ''''), '','', '''') AS INT)               ELSE 0     END) AS total_payments   from '+@dwx_db+@incentive_tbl+' a   join dim_location b   on a.[Primary Dealer Code] = b.location_code    join dim_date_day c   on cast(a.[payment date] as date) = c.date_sql   where '+@geo_filter+'   and c.date_id between '+@ph_start+' and '+@ph_end+'   group by   b.location_code,   b.location_name,   concat([First Name],'' '',[Last Name]),   [Payment Reference]) b   on a.period_start = b.period_start and    a.period_end = b.period_end and    a.personnel = b.personnel and    a.location_code = b.location_code and   a.payment_reference = b.payment_reference     union    select   ''ch'' period,  cast('+@ch_start+' as date) period_start,  cast('+@ch_end+' as date) period_end,  (select top 1 location_code from dim_location where '+@geo_filter+') location_code,  (select top 1 location_name from dim_location where '+@geo_filter+') location_name,  ''No Personnel'' personnel,  isnull(prl.display_name, codes.payment_reference) as payment_reference,  0 total_incentives,  0 total_payments  from ('+REPLACE(REPLACE(REPLACE(@ch_parts_filter, '(''', 'select '''), ''',''', ''' payment_reference union select '''), ')', '')+' payment_reference  ) codes  left join '+@prl_tbl+' prl on codes.payment_reference = prl.payment_reference    union    -- Force ALL prior period incentive codes to appear    select   ''ph'' period,  cast('+@ph_start+' as date) period_start,  cast('+@ph_end+' as date) period_end,  (select top 1 location_code from dim_location where '+@geo_filter+') location_code,  (select top 1 location_name from dim_location where '+@geo_filter+') location_name,  ''No Personnel'' personnel,  isnull(prl.display_name, codes.payment_reference) as payment_reference,  0 total_incentives,  0 total_payments  from ('+REPLACE(REPLACE(REPLACE(@ph_parts_filter, '(''', 'select '''), ''',''', ''' payment_reference union select '''), ')', '')+' payment_reference  ) codes  left join '+@prl_tbl+' prl on codes.payment_reference = prl.payment_reference   '  end    exec sp_utl_exec @sql, @debug    exec sp_utl_drop_table @tmp_result, @debug  exec sp_utl_drop_table @prl_tbl, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    /*  DEBUG  --<report_id>715</report_id>  exec sp_rpt_dcn_parts_incentives  '<parms>    <report_id>715</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>326</geo_value>    <geo_title>Dealer = ALL AMERICAN ISUZUTRUCK O (62826)</geo_title>    <date_type_id>11</date_type_id>    <time_title>Time = 2026YTD</time_title>    <request_id>1741193814688</request_id>    <_>1741192656057</_>    <user_id>awilson@sextantusa.com</user_id>  </parms>','n',1    exec sp_rpt_dcn_parts_incentives  '<parms>    <report_id>715</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>193</geo_value>    <geo_title>Dealer = TRANSOURCE ISUZU TRUCK (63109)</geo_title>    <date_type_id>11</date_type_id>    <time_title>Time = 2026YTD</time_title>    <request_id>1741193814688</request_id>    <_>1741192656057</_>    <user_id>awilson@sextantusa.com</user_id>  </parms>','n',2    -- Test with 2025 (date_type_id=12)  exec sp_rpt_dcn_parts_incentives  '<parms>    <report_id>715</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>326</geo_value>    <date_type_id>12</date_type_id>    <time_title>Time = 2025</time_title>    <user_id>awilson@sextantusa.com</user_id>  </parms>','y',2    -- Test with 2024 (date_type_id=13)  exec sp_rpt_dcn_parts_incentives  '<parms>    <report_id>715</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>326</geo_value>    <date_type_id>13</date_type_id>    <time_title>Time = 2024</time_title>    <user_id>awilson@sextantusa.com</user_id>  </parms>','y',2  */    return 0
    sp_rpt_dcn_parts_pvo SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_parts_pvo] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: parts Sales in a given year for a single dealer (not seperated by type)grouped by month adn an objective per month    Notes:    History:  2023-11-29 DD initial development.  2024-04-10 DD add retail Part sales.  2024-08-15 bh update for schema level usd to cad conversion ONLY!!! for tables used in reports. Minor cleanup.  2024-11-21 mg update to add left join to parts objective subquery   */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @geo_join varchar(max),  @sch varchar(100),    --table name  @part_table Varchar(max) = 'dbo.fact_part',  @obj_table varchar(max) =' dbo.fact_objective' ,  @date_table varchar(max) = 'dim_date',  @retail_part_table varchar(max) = 'dwx.fact_part_retail'    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    -- Build report query.  select @sch = isnull(parm0,'') from rpt_report where report_id = @report_id  select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)  set @date_filter = '(a.date_id between '+@date1+' and '+@date2+')'    if (len(@sch) > 1) begin   set @part_table = replace(@part_table,'dbo',@sch)   set @obj_table = replace(@obj_table,'dbo',@sch)   set @retail_part_table = replace(@retail_part_table,'dwx',@sch)  end    if @rpt_lvl = 1  begin    set @sql =  '  select a.location_id  , sum(a.total_part_amount) ''total parts''  , a.date_id  , c.date_year   , c.date_month  , c.month_name_short  , b.amount ''Objective''  , c.date_name_yy_mon ''year_month''  , sum(a.captive_amount) ''captive_amount''  , sum(a.competitive_amount) ''competitive_amount''  , sum(a.fleetvalue_amount) ''fleetvalue_amount''  , sum(a.stock_amount) ''stock_amount''  , sum(a.daily_amount) ''daily_amount''  , sum(a.critical_amount) ''critical_amount''  , sum(a.warranty_amount) ''warranty_amount''  , isnull(sum(d.total_retail), 0) ''total_retail''  , isnull(sum(d.fv_retail), 0 ) ''fv_retail''  , isnull(sum(d.Captive_retail), 0 ) ''Captive_retail''  , isnull(sum(d.Competitive_retail), 0 ) ''Competitive_retail''  from (select    date_id  ,location_id  ,sum(total_part_amount) ''total_part_amount''  ,sum(captive_amount) ''captive_amount''  ,sum(competitive_amount)''competitive_amount''  ,sum(fleetvalue_amount) ''fleetvalue_amount''  ,sum(stock_amount)  ''stock_amount''  ,sum(daily_amount)  ''daily_amount''  ,sum(critical_amount) ''critical_amount''  ,sum(warranty_amount) ''warranty_amount''  from '+@part_table+'  group by date_id,location_id)as a     left join '+@obj_table+' as b  on a.date_id = b.date_id and a.location_id = b.location_id     join dim_date as c  on a.date_id = c.date_id     left join (select date_id,location_id       ,sum(qty*dlr_ext_dnp) ''total_retail''       ,sum(case when fv_flag = 1 then qty*dlr_ext_dnp else 0 end) ''fv_retail''       ,sum(case when captive_flag = 1 then qty*dlr_ext_dnp else 0 end) ''Captive_retail''       ,sum(case when captive_flag = 0 then qty*dlr_ext_dnp else 0 end) ''Competitive_retail''     from '+@retail_part_table+'     where location_id = '+@geo_value+'     group by location_id,date_id    ) as d  on a.date_id = d.date_id and a.location_id = d.location_id     where a.location_id = '+@geo_value+' and '+@date_filter+'     group by     a.location_id  , a. date_id  , b.amount  , c.date_name_yy_mon   , c.date_year   , c.date_month  , c.month_name_short     order by   a.location_id  , a. date_id  , b.amount  , c.date_name_yy_mon  '  end    else if @rpt_lvl = 2  begin  set @sql =  '  select a.location_id  , sum(a.total_part_amount) ''total parts''  , a.date_id  , c.date_year   , c.date_month  , c.month_name_short  , b.amount ''Objective''  , c.date_name_yy_mon ''year_month''  , sum(a.captive_amount) ''captive_amount''  , sum(a.competitive_amount) ''competitive_amount''  , sum(a.fleetvalue_amount) ''fleetvalue_amount''  , sum(a.fleetval_amount) ''fleetval_amount''  , sum(a.stock_amount) ''stock_amount''  , sum(a.daily_amount) ''daily_amount''  , sum(a.critical_amount) ''critical_amount''  , sum(a.warranty_amount) ''warranty_amount''  , isnull(sum(d.total_retail), 0) ''total_retail''  , isnull(sum(d.fv_retail), 0 ) ''fv_retail''  , isnull(sum(d.Captive_retail), 0 ) ''Captive_retail''  , isnull(sum(d.Competitive_retail), 0 ) ''Competitive_retail''  from (select    date_id  ,location_id  ,sum(total_part_amount) ''total_part_amount''  ,sum(captive_amount) ''captive_amount''  ,sum(competitive_amount)''competitive_amount''  ,sum(fleetvalue_amount) ''fleetvalue_amount''  ,sum(fleetval_amount) ''fleetval_amount''  ,sum(stock_amount)  ''stock_amount''  ,sum(daily_amount)  ''daily_amount''  ,sum(critical_amount) ''critical_amount''  ,sum(warranty_amount) ''warranty_amount''  from '+@part_table+'  group by date_id,location_id)as a     left join '+@obj_table+' as b  on a.date_id = b.date_id and a.location_id = b.location_id     join dim_date as c  on a.date_id = c.date_id     left join (select date_id,location_id       ,sum(qty*dlr_ext_dnp) ''total_retail''       ,sum(case when fv_flag = 1 then qty*dlr_ext_dnp else 0 end) ''fv_retail''       ,sum(case when captive_flag = 1 then qty*dlr_ext_dnp else 0 end) ''Captive_retail''       ,sum(case when captive_flag = 0 then qty*dlr_ext_dnp else 0 end) ''Competitive_retail''     from '+@retail_part_table+'     where location_id = '+@geo_value+'     group by location_id,date_id    ) as d  on a.date_id = d.date_id and a.location_id = d.location_id     where a.location_id = '+@geo_value+' and '+@date_filter+'     group by     a.location_id  , a. date_id  , b.amount  , c.date_name_yy_mon   , c.date_year   , c.date_month  , c.month_name_short     order by   a.location_id  , a. date_id  , b.amount  , c.date_name_yy_mon    '  end    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_parts_PVO] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */  
    sp_rpt_dcn_partsales_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_partsales_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-16 DD initial development.  2024-08-14 bh update for schema level usd to cad conversion ONLY!!! for tables used in reports.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @geo_join varchar(max),  @sch varchar(100),    --table name  @part_sale_table varchar(max) = 'dbo.fact_part',  @part_retail_table varchar(max) = 'dwx.fact_part_retail',  @obj_table varchar(max) = 'dbo.fact_objective'    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    --  Build report query.  set @date_filter = dbo.fn_get_date_filter(@date_type_id, 8)    select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    select @sch = isnull(parm0,'') from rpt_report where report_id = @report_id  if (len(@sch) > 1) begin   set @part_sale_table = replace(@part_sale_table,'dbo',@sch)   set @part_retail_table = replace(@part_retail_table,'dwx',@sch)   set @obj_table = replace(@obj_table,'dbo',@sch)  end    set @sql = '   SELECT sum(captive_amount)''Captive''   ,sum(competitive_amount)+sum(fleetval_amount) ''Competitive''   , sum(fleetvalue_amount) ''FV''   ,sum(total_part_amount) ''Total''    ,(SELECT sum(amount)    FROM '+@obj_table+' WHERE '+@date_filter+' and '+@geo_filter+') ''Objective''    , (select sum(dlr_ext_dnp * qty)    from '+@part_retail_table+' WHERE '+@date_filter+' and '+@geo_filter+') ''retail_total''   , (select sum(dlr_ext_dnp * qty) from '+@part_retail_table+' WHERE '+@date_filter+' and '+@geo_filter+' and fv_flag = 1) ''fv retail''   , (select sum(dlr_ext_dnp * qty) from '+@part_retail_table+' WHERE '+@date_filter+' and '+@geo_filter+' and captive_flag = 1) ''Captive retail''    , (select sum(dlr_ext_dnp * qty) from '+@part_retail_table+' WHERE '+@date_filter+' and '+@geo_filter+' and captive_flag = 0 ) ''Competitive retail''  FROM '+@part_sale_table+'  WHERE '+@date_filter+' and '+@geo_filter    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  --US - 2025YTD  exec [sp_rpt_dcn_PartSales_overview]   '<parms><report_id>28</report_id>  <geo_type_id>1</geo_type_id>  <geo_value>1615</geo_value>  <geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2023YTD</time_title>  <request_id>1699654671819</request_id>  <_>1699654658621</_>  <user_id>ddaniel@sextantusa.com</user_id>  <class_sale_id>1</class_sale_id>  </parms>', 'y'    --US - 2024  exec [sp_rpt_dcn_PartSales_overview]   '<parms><report_id>28</report_id>  <geo_type_id>1</geo_type_id>  <geo_value>1615</geo_value>  <geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title>  <date_type_id>12</date_type_id>  <time_title>Time = 2023YTD</time_title>  <request_id>1699654671819</request_id>  <_>1699654658621</_>  <user_id>ddaniel@sextantusa.com</user_id>  <class_sale_id>1</class_sale_id>  </parms>', 'y'    --CN - 2025YTD  exec [sp_rpt_dcn_PartSales_overview]  '<parms>    <report_id>578</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>1904</geo_value>    <geo_title>Dealer = Altruck Isuzu Truck (76419)</geo_title>    <date_type_id>11</date_type_id>    <time_title>Time = 2025YTD</time_title>    <request_id>1740764203482</request_id>    <_>1740763617424</_>    <user_id>awilson@sextantusa.com</user_id>  </parms>','y'    --CN - 2024  exec [sp_rpt_dcn_PartSales_overview]  '<parms>    <report_id>578</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>1904</geo_value>    <geo_title>Dealer = Altruck Isuzu Truck (76419)</geo_title>    <date_type_id>12</date_type_id>    <time_title>Time = 2025YTD</time_title>    <request_id>1740764203482</request_id>    <_>1740763617424</_>    <user_id>awilson@sextantusa.com</user_id>  </parms>','y'  */  
    sp_rpt_dcn_personel SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_personel] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose:    Notes:    History:  2024-01-12 DD initial development.  2024-04-10 DD Rebuilt all portions of sp to reflect the new data streams  2025-01-31 TAW Added date filters  2025-03-07 TAW update for schema level usd to cad conversion ONLY!!! for tables used in reports.  2025-08-22 DD add date filters for ICS and Warranty Administrators.  2025-09-30 taw added new column Qualifies for Service Manager Overview and Parts Manager Overview  2026-02-19 taw @rpt_level = 1 added @date_filter to left join on @tablename3 and removed from the WHERE CLAUSE   This was causing issue with the ICTC side of the report.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 int,  @date2 int,  @year_filter varchar(max),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @date_filter2 varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @tablename varchar(max),  @tablename2 varchar(max),  @tablename3 varchar(max),  @tablename4 varchar(max),  @tablename5 varchar(max),  @tablename6 varchar(max),  @sch varchar(100)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')  set @tablename = '[ICTA_IDEAS_DWX].[dbo].[sales_dealer_info]'  set @tablename2 = '[ICTA_IDEAS_DWX].[dbo].[sales_goisuzu_act_roles]'  set @tablename3 = '[ICTA_IDEAS_DWX].[dbo].[personnel_agg] '  set @tablename4 = '[ICTA_IDEAS_DWX].[dbo].[sales_dealer_managers]'  set @tablename5 = '[ICTA_IDEAS_DWX].[dbo].[personnel_dlr]'  set @tablename6 = '[dbo].[dim_location]'    set @location_code = (select location_code from [dim_location] where [location_id] = @geo_value)  set @geo_filter = 'r.location_code = '''+@location_code+''''  select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    set @date_filter = 'b.date_id between '+cast(@date1 as varchar(5))+' and '+cast(@date2 as varchar(5))  set @date_filter2 = 'date_id between '+cast(@date1 as varchar(5))+' and '+cast(@date2 as varchar(5))    /*  parm0 is NULL in ICTA_IDEAS_App  parm0 is dsx in ICTC_IDEAS_App - This is for the cad conversion  */  SELECT @sch = CASE                    WHEN parm0 IS NULL THEN NULL                    ELSE parm0                 END   FROM rpt_report   WHERE report_id = @report_id;  if @sch = 'dsx'  begin   set @tablename3 = replace(@tablename3,'[ICTA_IDEAS_DWX].[dbo]',@sch)  end    if  @rpt_lvl = 1  begin  set @sql =  '  select   r.location_code ''dealer'',  isnull(dbo.fn_capitalize(concat(a.first_name,'' '',a.last_name)),''No Data'') ''Warranty Administrator'',  b.personnel_type ''role'',  dbo.fn_capitalize(b.Person) ''Person'',  --dbo.fn_capitalize(d.[Dealer Principal]) ''dealer_principal'',  --dbo.fn_capitalize(d.[Dealer Executive Manager]) ''executive_manager'',  dbo.fn_capitalize(c.dealer_principal) ''dealer_principal'',  dbo.fn_capitalize(c.executive_manager) ''executive_manager'',  dbo.fn_capitalize(c.ics_admin) ''ics_admin'',  c.dealer ''dealer_c'',  b.total ''total'',  (case when b.[national rank] = ''n/a'' then 0 else b.[national rank] end) ''national_rank'',  (CASE WHEN  b.[current level] = ''BRONZE'' then 50 else 1 end)''current_lvl'',  b.[current level] ''crnt_lvl'',  (case when b.[PKE] = ''yes'' then 90 else 1 end) ''PKE'',  b.[PKE] ''PKE1'',  (case when b.[Training Workshop] = ''YES'' then 90 else 1 end) ''Training Workshop'',  b.[Training Workshop] ''Training2'',  upper(b.rank) ''rank'',  b.[Parts Group]''parts_group'',  b.[SM Primary Dealership]  from '+@tablename6+' as r  left join '+@tablename2+' as a  on r.location_code = a.dealer and a.role = ''WARRANTY ADMINISTRATOR'' and a.date_id = (select max(date_id)                           from [ICTA_IDEAS_DWX].[dbo].[sales_goisuzu_act_roles]                           where '+@date_filter2+')  left join '+@tablename3+' as b  on r.location_code = b.[Primary Dealership]  and '+@date_filter + '  left join '+@tablename+' as c  on r.location_code = c.dealer and c.date_id = (select max(date_id)                 from [ICTA_IDEAS_DWX].[dbo].[sales_dealer_info]                 where '+@date_filter2+' )  left join '+@tablename5+' as d  on r.location_code = d.[Dealer Code]  where '+@geo_filter  --+' and '+@date_filter  end  else if  @rpt_lvl = 2  begin  set @sql ='  select dbo.fn_capitalize(Person)''Person''  , [Primary Dealership] ''Primary_Dealership''  , [Current Level] ''Current_Level''  , [Rank]  , [Dealership Retail Sales] ''Dealership_Retail_Sales''  , dbo.fn_capitalize([Qualifies for SM Challenge]) ''Qualifies_for_SM_Challenge''  , cast([SM Start Date] as DATE) ''SM_Start_Date''  , dbo.fn_capitalize([SM Primary Dealership]) ''SM_Primary_Dealership''  , dbo.fn_capitalize([SM PKEs]) ''SM_PKEs''  , dbo.fn_capitalize([SM In-Person Class]) ''SM_In-Person_Class''  , [Videos Uploaded] ''Videos_Uploaded''  , [Trained SC] ''Trained_SC''  , [SC w/In-Person Training] ''SC_w/In-Person_Training''  , [SC w/PKEs] ''SC_w/PKEs''  , [Everconnects First Half] ''Everconnects_First_Half''  , [Everconnects Second Half] ''Everconnects_Second_Half''  , (case when personnel_type = ''sales_managers'' then ''Sales Manager Training'' else ''ERROR'' end) ''Type_Training''  from   '+@tablename3+'  where [Primary Dealership] = '''+@location_code+'''  and personnel_type = ''sales_managers''  and '+@date_filter2  end  else if  @rpt_lvl = 3  begin  set @sql ='  select  dbo.fn_capitalize(Person) ''Person'',  dbo.fn_capitalize([Current Level]) ''Current Level'',  dbo.fn_capitalize(PKE) PKE,  dbo.fn_capitalize([Training Workshop]) ''Training Workshop'',  [YTD Sales],  [YTD Retail Sales],  [YTD Fleet Sales],  [YTD Mega Sales],  [Rank],  dbo.fn_capitalize([WA Video]) ''WA Video''  ,(case when personnel_type = ''sales_consultants'' then ''Sales Training'' else ''ERROR'' end) ''Type Training''  from   '+@tablename3+'  where [Primary Dealership] = '''+@location_code+'''  and personnel_type = ''sales_consultants''  and '+@date_filter2  end  else if  @rpt_lvl = 4  begin  set @sql ='  select  UPPER(person) ''person''  ,[Primary Dealership] ''Primary_Dealership''  ,[Parts Group] ''Parts_Group''  ,cast([Objective] as float) ''Objective''   ,[Purchases YTD] ''Purchases_YTD''  ,[Purchases Projected] ''Purchases_Projected''  ,[YTD Parts Objective Met] ''YTD_Parts_Objective_Met''  ,[Qualifies] ''Qualifies''  ,[Proj  YE Parts Purchases > $150,000 00] ''Proj_YE_Parts_Purchases_>_150,000''  ,[Videos Uploaded] ''Videos_Uploaded''  ,[Parts Objective] ''Parts_Objective''  ,[Service Training] ''Service_Training''  ,[Service Parts EVERConnects 1st Half] ''Service_Parts_EVERConnects_1st_Half''  ,[Service Parts EVERConnects 2nd Half] ''Service_Parts_EVERConnects_2nd_Half''  ,[CSI]  ,[ATD Bonus] ''ATD_Bonus''  ,[Total]  ,[Rank]  ,[WA Video] ''WA_Video''  ,(case when personnel_type = ''svc_managers'' then ''Service Manager Training'' else ''ERROR'' end) ''Type_Training''  ,(case when personnel_type = ''svc_managers'' then ''Service Training'' else ''ERROR'' end) ''training_title''  from   '+@tablename3+'  where [Primary Dealership] = '''+@location_code+'''  and personnel_type = ''svc_managers''  and '+@date_filter2  end  else if  @rpt_lvl = 5  begin   set @sql ='  select  UPPER(person)''person''  ,[Primary Dealership] ''Primary_Dealership''  ,[Parts Group]''Parts_Group''  ,cast([Objective] as float) ''Objective''  ,[Purchases YTD] ''Purchases_YTD''  ,[Purchases Projected] ''Purchases_Projected''  ,[YTD Parts Objective Met] ''YTD_Parts_Objective_Met''  ,[Qualifies] ''Qualifies''  ,[Proj  YE Parts Purchases > $150,000 00] ''Proj_YE_Parts_Purchases_>_150,000''  ,[Parts Objective] ''Parts_Objective''  ,[Parts Training] ''Parts_Training''  ,[ATD Bonus] ''ATD_Bonus''  ,[WA Video] ''WA_Video''  ,[Service Parts EVERConnects 1st Half] ''Service_Parts_EVERConnects_1st_Half''  ,[Service Parts EVERConnects 2nd Half] ''Service_Parts_EVERConnects_2nd_Half''  ,[CSI]  ,[Total]  ,[Rank]  ,[National Rank] ''National_Rank''  from   '+@tablename3+'  where [Primary Dealership] = '''+@location_code+'''  and personnel_type = ''parts_managers''  and '+@date_filter2  end    exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    -- test parm  /*  exec [sp_rpt_dcn_personel] '<parms><report_id>716</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2025YTD</time_title><request_id>1740076082307</request_id><_>1740076077898</_><user_id>ddaniel@sextantusa.com</user_id></parms>', 'y', 2  */    
    sp_rpt_dcn_pumpin SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_pumpin] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: To Determine the Current R12 pump in numbers    Notes:    History:  2023-11-28 DD initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_year_id1 int,    --table name  @customer_table varchar(max),  @geo_table varchar(max),  @date_table varchar(max),  @sale_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @customer_table = ' [ICTA_IDEAS_App].[dbo].dim_customer'  set @geo_table = '[dbo].geo_geo'  set @sale_table = '[dbo].fact_sale'   set @date_year_id1 = 12    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 0 and date_year_id = @date_year_id1  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @geo_filter = cast(@geo_value as varchar)  set @date_filter = '(c.date_id >= '''+@date1+''') and (c.date_id <= '''+@date2+''')'  set @dealer_filter = 'b.location_id = '''+@geo_filter+''''    set @sql =   '  select b.location_id  , sum(case when c.location_id = '+@geo_filter+' then c.units else 0 end)''Sold by dealer''  , sum(units)''All Sales in Region''  , ((sum(case when c.location_id = '+@geo_filter+' then c.units else 0 end))/(sum(c.units)*1.00))''R12 Pump-in''  from '+@customer_table+' as a    join '+@geo_table+' as b  on b.geo_id = a.geo_id     join '+@sale_table+' as c  on c.customer_id = a.customer_id    where '+@dealer_filter+' and '+@date_filter+'    group by  b.location_id  order by  b.location_id  '  exec sp_utl_exec @sql, @debug  if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_Pumpin] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */  
