 b  on a.region = b.region_id    where a.location_id = '+@geo_filter+'     '    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_regn_message] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */  
    sp_rpt_dcn_report SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_report] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates report content for dealer contact reports.    Notes:  1. Returns different results based on report.    History:  2021-08-24 bh initial development.  2022-09-30 bh remove obsolete code.  2025-03-03 taw modified @sch selection  2025-03-26 taw added date id logic  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @date_type_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),    -- Query vars.  @sql varchar(4000),  @sch varchar(100),  @tbl varchar(100),  @geo_filter varchar(100),  @nogeo varchar(100),  @code varchar(100),  @country varchar(100),  @date int,  @date1 varchar(100),  @date2 varchar(100),  @year_filter int,  @date_filter varchar(1000)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','smallint')    -- Get config parms.  set @country = (select parm_value from app_config where parm_name = 'country')    -- Return model (demo) report content for report designer.  if (@parms is null) begin   select @report_id = parm_value, @geo_value=8   from app_config   where parm_name = 'report_design'  end    -- Build query.  select   @sch=isnull(parm0,'dwx')+'.',  @tbl=parm1,  @nogeo=parm4,  @date=time_control  from rpt_report  where report_id = @report_id    select @code=location_code  from dim_location  where location_id = @geo_value    set @geo_filter = (case when @nogeo is null then 'dealer='''+@code+'''' else '1=1' end)    select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year   from dim_year where entity_id = 8 and date_year_id = @date_type_id    if ((@report_id = 695 and @country = 'USA')    or (@report_id = 557 and @country = 'CAN')) -- THESE REPORTS DO NOT USE DATE_ID  begin   set @date_filter = '1=1'  end  else  begin   set @date_filter = 'insert_date = (select max(insert_date) from '+@sch+@tbl+'    where date_id between '''+@date1+''' and '''+@date2+''')'  end     set @sql = '  select *  from '+@sch+@tbl+'  where '+@geo_filter+' and '+@date_filter    -- Execute.  exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    /*  exec sp_rpt_dcn_report '  <parms>  <report_id>701</report_id>  <request_id/>  <geo_type_id>1</geo_type_id>  <geo_value>54</geo_value>  <date_type_id>12</date_type_id>  <_>1742838135518</_>  <geo_title/>  <user_id>awilson@sextantusa.com</user_id>  </parms>','y'  */  
    sp_rpt_dcn_report_hst SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_report_hst] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Generates report content for dealer contact hst reports'    Notes:    History:  2022-04-25 bh initial development.  2022-05-06 bh use R12 to trim down data.  2023-05-10 bh update to use schema from rpt_report & current_date_daily.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @date_type_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(100),  @sch varchar(100),  @tbl varchar(100),  @res varchar(100)  = '##res'+replace(newid(),'-','_'),  @d1 int, @d2 int    set nocount on    -- Get parms.  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')    -- Get config parms.  --set @country = (select parm_value from app_config where parm_name = 'country')    -- Return model (demo) report content for report designer.  if (@parms is null) begin   set @geo_value=8   set @report_id=567  end    -- Build query.  select   @sch=parm0+'.',  @tbl=parm1  from rpt_report   where report_id = @report_id    select @d2 = (select parm_value from app_config where parm_name = 'current_date_daily')  select @d1 = (select date_id from dim_date where date_year = year(getdate())-1 and date_month = 1)  select @date_filter = 'date_id between '+str(@d1)+' and '+str(@d2)    exec sp_utl_drop_table @res, @debug    set @sql = '  select   date_id,  date_name_yy_mon date_name,  0 units  into '+@res+'  from   dim_date a  where '+@date_filter    exec sp_utl_exec @sql, @debug    set @sql = '  select  a.date_id,  b.location_id,  (case when b.units > 0 then b.units else a.units end) units,  (case when b.units_cy > 0 then b.units_cy else a.units end) units_cy,  (case when b.units_py > 0 then b.units_py else a.units end) units_py,  (case when b.obj > 0 then b.obj else a.units end) obj,  a.date_name,  '+str(@d2-11)+' r12_start  from '+@res+' a left join '+@sch+@tbl+' b on a.date_id = b.date_id  and b.location_id='+@geo_value    exec sp_utl_exec @sql, @debug    -- Log usage.  set @end_time = GETDATE()    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0  
    sp_rpt_dcn_sale_training SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_sale_training] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose:    Notes:    History:  2024-01-12 DD initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),  @year_filter varchar(max),  --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @tablename varchar(max),  @tablename2 varchar(max),  @tablename3 varchar(max),  @tablename4 varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')  set @tablename = 'ICTA_IDEAS_DWX.dbo.sales_dealer_info '  set @tablename2 = 'ICTA_IDEAS_DWX.dbo.sales_goisuzu_act_roles'  set @tablename3 = '[ICTA_IDEAS_DWX].[dbo].[personnel_agg] '  set @tablename4 = '[ICTA_IDEAS_DWX].[dbo].sales_dealer_managers'    set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @geo_filter = 'a.dealer = '''+@location_code+''''    select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_type_id    set @date_filter = 'date_id between '+cast(@date1 as varchar(5))+' and '+cast(@date2 as varchar(5))      if  @rpt_lvl = 1  begin  set @sql ='  select  avg((case    when pke = ''yes'' and [Training Workshop] = ''yes'' then 1   when pke = ''yes'' and [Training Workshop] <> ''yes'' then 0.5   when pke <> ''yes'' and [Training Workshop] = ''yes'' then 0.5   else 0  end)) ''Average_dealer_score''  from '+@tablename3+'  where [primary dealership] = '''+@location_code+'''  and personnel_type = ''sales_consultants''  and '+@date_filter  end  else if  @rpt_lvl = 2  begin  set @sql ='  select  Person,  PKE,  [Training Workshop]  from   '+@tablename3+'  where [Primary Dealership] = '''+@location_code+'''  and personnel_type = ''sales_consultants''  and '+@date_filter  end    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    -- test parm  /*  exec [sp_rpt_dcn_sale_training] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>8</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */    
    sp_rpt_dcn_sales_total SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_sales_total] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: Sales in a given year for a single dealer (not seperated by type)grouped by month    Notes:  RDL FILES:  dcn_dashboard_f_trk_sale.rdl  dcn_dashboard_n_trk_sale.rdl  dcn_dashboard_trk_sale.rdl    History:  2023-11-28 DD initial development.  2024-09-30 AW Modified set @sale_table =     FROM '[dwx].[sales_rtl_series]'   TO '[ICTA_IDEAS_DWX].[dbo].[sales_rtl_by_vin]'   Modified the lvl1 and lvl2 dynamic queries  2025-02-13 DD Removed CTE from rpt lvl2  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),    @result_tbl1 varchar(100),  @result_tbl2 varchar(100),  @result_tbl3 varchar(100),    --table name  @sale_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 0)  set @sale_table = '[ICTA_IDEAS_DWX].[dbo].[sales_rtl_by_vin]'  set @date_table = '[dbo].[dim_date]'  set @date_filter = '(date_id between '+@date1+' and '+@date2+')'      if @rpt_lvl =  1   begin  --Get Results   set @sql =    '   select a.date_id    ,a.date_name_yy_mon    ,b.series    ,b.category    ,ISNULL(c.units,0) units     from (select date_id, date_name_yy_mon    from '+@date_table+'    where '+@date_filter+'     ) a   cross join (select distinct series    ,(case when LEFT(series,1) = ''N'' then ''N-Series''      when LEFT(series,1) = ''F'' then ''F-Series''      else series       end      ) ''category''    from  '+@sale_table+'     ) b   left join (select date_id, series, sum(cast(quantity as int)) units     from  '+@sale_table+'     inner join [dbo].[dim_location]    on [sales_rtl_by_vin].dealer = [dim_location].location_code    where '+@date_filter+' and '+@geo_filter+'    group by date_id, series    ) c   on a.date_id = c.date_id and b.series = c.series   '  end   else if @rpt_lvl = 2  begin   set @sql =    '    SELECT     [dealer],     left([model],4) [model_year],     right([model],3) [model],     [series],     [occ],     [vin],     substring(retail_sales_date,5,2)+''/''+substring(retail_sales_date,7,2)+''/''+substring(retail_sales_date,1,4) retail_sales_date,     [cust_bussiness_name],     [sales_person_name],     [customer_group],     cast([quantity] as int) quantity    FROM '+@sale_table+'     WHERE '+@dealer_filter+' and retail_sales_date not like ''%#%'' and '+@date_filter+'   '  end    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_sales_total] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n', 1  exec [sp_rpt_dcn_sales_total] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y', 2  */  
    sp_rpt_dcn_sales_total_subreport SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_sales_total_subreport] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Sales in a given year for a single dealer (not seperated by type)grouped by month    Notes:  RDL FILES:  dcn_dashboard_f_trk_sale_subreport.rdl  dcn_dashboard_n_trk_sale_subreport.rdl  dcn_dashboard_trk_sale_subreport.rdl    History:  2023-10-18 AW initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(max),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),    @result_tbl1 varchar(100),  @result_tbl2 varchar(100),  @result_tbl3 varchar(100),    --table name  @sale_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @dealer_filter = '[a].[dealer] = '''+@location_code+''''  set @sale_table = '[ICTA_IDEAS_DWX].[dbo].[sales_rtl_by_vin]'  set @date_table = '[dbo].[dim_date]'  set @date_filter = '([a].[date_id] between '+@date1+' and '+@date2+')'      --Get Results   set @sql = ''  set @sql =    '   declare @temp_data1 table (     [dealer] varchar(150)   , [date_year] varchar(150)   , [date_month] varchar(150)   , [month_name_short] varchar(150)   , [date_name_yy_mon] varchar(150)   , [N_Series_Gas] int   , [N_Series_Diesel] int   , [N_Series_EV] int   , [F_Series] int   , [units] int   );     with [data1] as (    select      [a].[dealer]     , [b].[date_year]     , [b].[date_month]     , [b].[month_name_short]     , [b].[date_name_yy_mon]     , 0 [N_Series_Gas]     , 0 [N_Series_Diesel]     , 0 [N_Series_EV]     , 0 [F_Series]     , 0 [units]    from  '+@sale_table+' [a]    inner join [dbo].[dim_date] [b] on [b].[date_id] = [a].[date_id]    where '+@date_filter+' and '+@dealer_filter+'    group by [a].[dealer]     , [b].[date_year]     , [b].[date_month]     , [b].[month_name_short]     , [b].[date_name_yy_mon]    )    insert into @temp_data1 select * from data1     declare @temp_data2 table (   [dealer] varchar(150)   , [date_year] varchar(150)   , [date_month] varchar(150)   , [month_name_short] varchar(150)   , [date_name_yy_mon] varchar(150)   , [series] varchar(150)   , [N_Series_Gas] int   , [N_Series_EV] int   , [F_Series] int   , [N_Series_Diesel] int   , [units] int   );     with [data2] as (    select      [a].[dealer]     , [b].[date_year]     , [b].[date_month]     , [b].[month_name_short]     , [b].[date_name_yy_mon]     , (case when left([a].[series], 1) = ''N'' and [a].[series] like ''%gas%''  then ''N_Series_Gas''         when left([a].[series], 1) = ''N'' and [a].[series] like ''%ev%''  then ''N_Series_EV''         when left([a].[series], 1) = ''F'' then ''F_Series''         when left([a].[series], 1) = ''N'' and ([a].series not like ''%gas%'' and [a].series not like ''%ev%'') then ''N_Series_Diesel''         else ''Unassigned''         end) ''series''     , (case when left([a].[series], 1) = ''N'' and [a].series like ''%gas%''  then sum(cast([a].[quantity] as int)) else 0 end) ''N_Series_Gas''     , (case when left([a].[series], 1) = ''N'' and [a].series like ''%ev%''  then sum(cast([a].[quantity] as int)) else 0 end) ''N_Series_EV''     , (case when left([a].[series], 1) = ''F'' then sum(cast([a].[quantity] as int)) else 0 end) ''F_Series''     , (case when left([a].[series], 1) = ''N'' and ([a].series not like ''%gas%'' and [a].series not like ''%ev%'') then sum(cast([a].[quantity] as int)) else 0 end) ''N_Series_Diesel''     , sum(cast([quantity] as int)) AS ''units''    from  '+@sale_table+' [a]    inner join [dbo].[dim_date] [b] on [b].[date_id] = [a].[date_id]    where '+@date_filter+' and '+@dealer_filter+'    group by [a].[dealer]     , [b].[date_year]     , [b].[date_month]     , [b].[month_name_short]     , [b].[date_name_yy_mon]     , [a].[series]     , (case when left([a].[series], 1) = ''N'' and [a].[series] like ''%gas%''  then ''N_Series_Gas''         when left([a].[series], 1) = ''N'' and [a].[series] like ''%ev%''  then ''N_Series_EV''         when left([a].[series], 1) = ''F'' then ''F_Series''         when left([a].[series], 1) = ''N'' and ([a].series not like ''%gas%'' and [a].series not like ''%ev%'') then ''N_Series_Diesel''         else ''Unassigned''         end)     )      insert into @temp_data2 select * from data2;     -- Consolidate data from @temp_data2   with ConsolidatedData as (      select           [dealer],          [date_year],          [date_month],          sum([N_Series_Gas]) AS Total_N_Series_Gas,          sum([N_Series_EV]) AS Total_N_Series_EV,          sum([F_Series]) AS Total_F_Series,          sum([N_Series_Diesel]) AS Total_N_Series_Diesel,          sum([units]) AS Total_units      from           @temp_data2      group by           [dealer],          [date_year],          [date_month]   )     -- Update @temp_data1 with consolidated data   update a   set     a.N_Series_Gas = isnull(cd.Total_N_Series_Gas, 0),    a.N_Series_EV = isnull(cd.Total_N_Series_EV, 0),    a.F_Series = isnull(cd.Total_F_Series, 0),    a.N_Series_Diesel = isnull(cd.Total_N_Series_Diesel, 0),    a.units = isnull(cd.Total_units, 0)   from     @temp_data1 a   inner join ConsolidatedData cd   on a.dealer = cd.dealer and a.date_year = cd.date_year and a.date_month = cd.date_month;     select      [dealer]   , [date_year]   , [date_month]   , [month_name_short]   , [date_name_yy_mon]   , [N_Series_Gas]   , [N_Series_Diesel]   , [N_Series_EV]   , [F_Series]   , [units]    from @temp_data1;   '  exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_sales_total_subreport] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = TOMS ISUZU TRUCK CTR-ORA (60435)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */    
    sp_rpt_dcn_sales_type SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_sales_type] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: Sales in a given year for a single dealer seperated by type for the year    Notes:    History:  2023-11-28 DD initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),    --table name  @sale_table Varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)  -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @dealer_filter = 'dealer = '''+@location_code+''''  --set @date_filter = dbo.fn_get_date_filter(@date_type_id, 0)  set @sale_table = ' [dwx].[fact_sale_aggr]'  set @date_table = 'dim_date'  set @date_filter = '(a.date_id between '+@date1+' and '+@date2+')'    set @sql =  '  select a.location_id  ,a.date_id   ,a.series  ,sum(a.units) ''Units''  ,b.date_year ''Year''  ,b.date_name_yy_mon ''month_year''  from '+@sale_table+' as a    join '+@date_table+' as b  on a.date_id = b.date_id    where '+@date_filter+' and '+@geo_filter+'  group by a.location_id  ,a.date_id  ,a.series  ,b.date_year  ,b.date_name_yy_mon       order by  a.date_id  ,a.series  ,Units  ,Year    '    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec [sp_rpt_dcn_sales_type] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n'  */  
