    sp_rpt_dcn_service_co_op SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_service_co_op] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose: To get the percentage of trainined employees and show a report on a dealer's service training readiness     Notes:    History:  2023-11-30 DD initial development.  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_year_id1 int,  @year_filter varchar(4),    --table name  @Co_Op_table varchar(max),  @date_table varchar(max)    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @date_year_id1 = @date_type_id  set @Co_Op_table = 'dwx.service_Coop'  select @date1 = start_date_id, @date2 = end_date_id, @year_filter = date_year from dim_year where entity_id = 8 and date_year_id = @date_year_id1  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @geo_filter = cast(@geo_value as varchar)  set @date_filter = '(c.date_id >= '''+@date1+''') and (c.date_id <= '''+@date2+''')'  set @dealer_filter = 'dealer = '''+@location_code+''''    set @sql =   '  select dealer  , (case when left(valid_from,2) = ''01'' then concat(''Jan-Jun '', year) else concat(''Jul-Dec '', year) end) ''part of year''  ,total_reward  ,reward_used  ,reward_remaining  , (case when (convert(float, replace(total_reward,'','',''''))) != 0 then  (convert(float, replace(reward_used, '','',''''))/ (convert(float, replace(total_reward,'','','''')) *1.00))  else null end)''reward_utilized''  , (case when month(GETDATE()) between month(valid_from) and month(valid_to) then ''yes'' else ''no'' end) ''current''  from '+@Co_Op_table+'  where '+@dealer_filter+' and year = '+@year_filter+'  '  exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_service_Co_Op] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'y'  */  
    sp_rpt_dcn_service_training SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_service_training] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 1 as
    /*  Purpose: To get the percentage of trainined employees and show a report on a dealer's service training readiness     Notes:    History:  2023-11-30 DD initial development.  2024-05-28 ak update to include all training types regardless of if dealer value present  2025-02-07 taw enable date filter  2025-03-14 taw removed HARDCODED DB from set @location_code - [ICTA_IDEAS_App].dbo.dim_location  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    --@status_id smallint,  @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    --@search varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_year_id1 int,    --table name  @training_table varchar(max),  @date_table varchar(max),  @res varchar(100)  = '##res'+replace(newid(),'-','_')      -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    --set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  set @location_code = (select location_code from dbo.dim_location where location_id = @geo_value)  set @training_table = 'dwx.service_training'  select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_type_id  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @geo_filter = cast(@geo_value as varchar)  set @date_filter = '(date_id >= '''+@date1+''') and (date_id <= '''+@date2+''')'  set @dealer_filter = 'dealer = '''+@location_code+''''    if @rpt_lvl = 1  begin  set @sql =   '  select *  from '+@training_table+'  where '+@dealer_filter+'  and date_id = (select max(date_id) from '+@training_table+' where date_id between '''+@date1+''' and '''+@date2+''')'    end  if @rpt_lvl = 2  begin  set @sql =   '  with   loc_tbl as (select '''+@location_code+''' dealer),    training_tbl as (select ''pcn_dlr_cert'' as training_code,''Dealer Certified'' training union all  select ''pcn_parts_cert'',''Parts Certified'' union all  select ''pcn_partsmgr_cert'',''Parts Manager Certified'' union all  select ''pcn_partsrep_cert'',''Parts Representitive Certified'' union all  select ''pcn_serv_cert'',''Service Certified'' union all  select ''pcn_servadv_cert'',''Service Advisor Certified'' union all  select ''pcn_servmgr_cert'',''Service Manager Certified'' union all  select ''pcn_tech_cert'',''Tech Certified'' union all  select ''pcn_wtyadmin_cert'',''Warranty Administration Certified''),    unpivot_tbl as (select   dealer,  percent_trained,  isnull(training,0) training  from dwx.service_training  UNPIVOT(  Percent_trained for training in (   pcn_dlr_cert  ,pcn_parts_cert  ,pcn_partsmgr_cert  ,pcn_partsrep_cert  ,pcn_serv_cert  ,pcn_servadv_cert  ,pcn_servmgr_cert  ,pcn_tech_cert  ,pcn_wtyadmin_cert)) unpvt  WHERE '+@dealer_filter+'  and date_id = (select max(date_id) from '+@training_table+' where date_id between '''+@date1+''' and '''+@date2+'''))  select   a.dealer,  isnull(c.percent_trained, 0) AS percent_trained,  b.training_code,  b.training  from loc_tbl a  cross join training_tbl b  left join unpivot_tbl c  on a.dealer = c.dealer and b.training_code = c.training'    end   exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*    -- US    exec ICTA_IDEAS_App.dbo.[sp_rpt_dcn_service_training]  '<parms>  <report_id>28</report_id>  <geo_type_id>1</geo_type_id>  <geo_value>1615</geo_value>  <geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2023YTD</time_title>  <request_id>1699654671819</request_id>  <_>1699654658621</_>  <user_id>ddaniel@sextantusa.com</user_id>  <class_sale_id>1</class_sale_id>  </parms>', 'y', 1    exec ICTA_IDEAS_App.dbo.[sp_rpt_dcn_service_training]  '<parms>  <report_id>28</report_id>  <geo_type_id>1</geo_type_id>  <geo_value>1615</geo_value>  <geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title>  <date_type_id>11</date_type_id>  <time_title>Time = 2023YTD</time_title>  <request_id>1699654671819</request_id>  <_>1699654658621</_>  <user_id>ddaniel@sextantusa.com</user_id>  <class_sale_id>1</class_sale_id>  </parms>', 'y', 2    -- CANADA    exec ICTC_IDEAS_App.dbo.sp_rpt_dcn_service_training  '<parms>    <report_id>577</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>1881</geo_value>    <geo_title>Dealer = Camions Isuzu Anjou (76505)</geo_title>    <date_type_id>11</date_type_id>    <time_title>Time = 2025YTD</time_title>    <request_id>1741957046476</request_id>    <_>1741957031845</_>    <user_id>awilson@sextantusa.com</user_id>  </parms>','y',1    exec ICTC_IDEAS_App.dbo.sp_rpt_dcn_service_training  '<parms>    <report_id>577</report_id>    <geo_type_id>1</geo_type_id>    <geo_value>1881</geo_value>    <geo_title>Dealer = Camions Isuzu Anjou (76505)</geo_title>    <date_type_id>11</date_type_id>    <time_title>Time = 2025YTD</time_title>    <request_id>1741957046476</request_id>    <_>1741957031845</_>    <user_id>awilson@sextantusa.com</user_id>  </parms>','y',2  */  
    sp_rpt_dcn_service_training_ind SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_service_training_ind] @parms xml = null,
    @debug char(1) = 'n',
    @rpt_lvl int = 3,
    @userid varchar(max) = null,
    @personnel_group_id varchar(max) = null as
    /*  Purpose: To show a individual service members online training completeion  Notes: No date filter required or coded as of last alteration    History:  2024-04-14 DD initial development.  2024-07-25 ak update for new data structure  2025-10-24 mh return primary or secondary role indication  2025_11_10 mh level 3 report linkage location/user -> training  */
    begin -- Admin vars.  declare  @sproc varchar(100),  @start_time smalldatetime,  @end_time smalldatetime,    -- Parm vars.  @user_id varchar(100),  @report_id smallint,  @geo_type_id smallint,  @geo_value varchar(10),  @date_type_id int,    @dept_id smallint,  @date1 varchar(100),  @date2 varchar(100),    -- Query vars.  @sql varchar(4000),  @date_filter varchar(max),  @geo_filter varchar(max),  @location_code varchar(6),  @dealer_filter varchar(max),  @geo_join varchar(max),  @date_filter2 varchar(max),  @date_year_id1 int,      --table name  @personnel_table varchar(max),  @users_table varchar(max),  @date_table varchar(max),  @courses_table varchar(max)    DECLARE @country varchar(3) = (select parm_value from app_config where parm_name = 'country' )    -- Get parms.  set nocount on  set @start_time = GETDATE()  set @sproc = OBJECT_NAME(@@procid)    -- Set parm values  set @user_id = @parms.value('/parms[1]/user_id[1]','varchar(100)')  set @report_id = @parms.value('/parms[1]/report_id[1]','int')  set @geo_type_id = @parms.value('/parms[1]/geo_type_id[1]','smallint')  set @geo_value = @parms.value('/parms[1]/geo_value[1]','varchar(10)')  set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')    --PRINT '@user_id = ' + @user_id    if @country = 'USA'  begin   set @location_code = (select location_code from [ICTA_IDEAS_App].dbo.dim_location where location_id = @geo_value)  end  else  begin   set @location_code = (select location_code from [ICTC_IDEAS_App].dbo.dim_location where location_id = @geo_value)  end    set @date_year_id1 = 12  select @date1 = start_date_id, @date2 = end_date_id from dim_year where entity_id = 8 and date_year_id = @date_year_id1  select @geo_join=geo_join,@geo_filter=geo_filter  from dbo.fn_get_geo_parts('fact_part',@geo_type_id, @geo_value, 0)    set @geo_filter = cast(@geo_value as varchar)  set @date_filter = '(c.date_id >= '''+@date1+''') and (c.date_id <= '''+@date2+''')'  set @dealer_filter = 'dealer = '''+@location_code+''''  set @personnel_table = 'ICTA_IDEAS_DWX.dbo.act_train_personnel'  set @courses_table = 'ICTA_IDEAS_DWX.dbo.act_train_learning'  set @users_table = 'ICTA_IDEAS_DWX.dbo.personnel_users'    if @rpt_lvl = 2  begin  set @sql =   '  select   dbo.fn_capitalize(a.first_name) first_name,  dbo.fn_capitalize(a.last_name) last_name,  a.primary_role,  case when a.primary_role = c.[Primary Role] then 1 else 0 end as is_primary,  a.user_id,  a.personnel_group_id,  count(case when b.completion_flag = ''Y'' then b.course_no end) courses_completed,  count(b.course_no) total_courses_available    from '+@personnel_table+' a  join '+@courses_table+' b   on a.user_id = b.user_id and a.personnel_group_id = b.personnel_group_id  join '+@users_table+' c    on a.location_code = c.[Dealer Code] and a.user_email = c.Email    where a.location_code = '''+@location_code+'''  group by a.user_id,a.first_name,a.last_name,a.personnel_group_id,a.primary_role, c.[Primary Role]     /*  select   UPPER(b.first_name) ''first_name''  , UPPER(b.last_name) ''last_name''  ,b.primary_role  , a.[user_id]  , count(distinct (case when a.completion_flag = ''Y'' then a.course_no end)) ''Courses_Completed''    , count(distinct a.course_no) ''total_courses_available''  from '+@courses_table+' as a    join  '+@personnel_table+' as b  on b.[user_id] = a.[user_id]    where a.[user_id] in (select [user_id] from '+@personnel_table+' where location_code = '''+@location_code+''')    group by a.[user_id], b.first_name, b.last_name,b.primary_role  order by b.last_name  */  '  end  if @rpt_lvl = 3  begin   set @sql =  '  select   concat(dbo.fn_capitalize(a.first_name),'' '',dbo.fn_capitalize(a.last_name)) name,  a.user_id,  b.learning_type,  b.template_id,  b.course_no,  b.course_name,  b.completion_flag,  cast(b.completion_date as varchar(max)) ''completion_date'',  b.ilt_date,  b.ilt_location,  b.ilt_trainer_first_name,  b.ilt_trainer_last_name,  b.insert_date,  b.rec_id    from ICTA_IDEAS_DWX.dbo.act_train_personnel a  join ICTA_IDEAS_DWX.dbo.act_train_learning b  on a.user_id = b.user_id and a.personnel_group_id = b.personnel_group_id    where a.location_code = '''+@location_code+'''   and a.[user_id] = '+@userid+'   and a.personnel_group_id = '+@personnel_group_id+'      '  end    if @rpt_lvl = 1  begin  set @sql =   '  select   concat (UPPER(b.first_name), '' '', UPPER(b.last_name)) ''Name''  , a.user_id  , a.learning_type  , a.template_id  , a.course_no  , a.course_name  , a.completion_flag  , cast(a.completion_date as varchar(max)) ''completion_date''  , a.ilt_date  , a.ilt_location  , a.ilt_trainer_first_name  , a.ilt_trainer_last_name  , a.insert_date  , a.rec_id   from '+@courses_table+' as a    join  '+@personnel_table+' as b  on b.[user_id] = a.[user_id]    where a.[user_id] in (select [user_id] from '+@personnel_table+' where location_code = '''+@location_code+''')    group by UPPER(b.first_name)   , UPPER(b.last_name)   , a.user_id  , a.learning_type  , a.template_id  , a.course_no  , a.course_name  , a.completion_flag  , a.completion_date  , a.ilt_date  , a.ilt_location  , a.ilt_trainer_first_name  , a.ilt_trainer_last_name  , a.insert_date  , a.rec_id     order by UPPER(b.first_name)  , UPPER(b.last_name)  , a.user_id  , a.learning_type  , a.template_id  , a.course_no  , a.course_name  , a.completion_flag  , a.completion_date  , a.ilt_date  , a.ilt_location  , a.ilt_trainer_first_name  , a.ilt_trainer_last_name  , a.insert_date  , a.rec_id   '  end  exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0      --test parm  /*  exec [sp_rpt_dcn_service_training_ind] '<parms><report_id>28</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2023YTD</time_title><request_id>1699654671819</request_id><_>1699654658621</_><user_id>ddaniel@sextantusa.com</user_id><class_sale_id>1</class_sale_id></parms>', 'n' ,'1', 2973  */  
    sp_rpt_dcn_truck_sales_objectives SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_truck_sales_objectives] @parms xml = null,
    @debug char(1) = 'n' as
    /*    Purpose : Truck Sales Objectives panel for the DCN Overview report (Tablix9).              Returns one row per series (N-Series, F-Series, Total) with:                  series        varchar(20)   N-Series | F-Series | Total                sales         int           YTD retail sales (non-Mega)                objective     int           Full-year objective from dim_location_metric                pct_achieved  decimal(10,4) sales / objective    Notes:      * Dealer-level only (geo_type_id = 1)      * Excludes Mega Fleets (mega_id = 0)      * The 2026 Objective = n_local_obj + n_pumpout_obj (full year local + pump-out combined)      History:      2026-04-19  rewritten using confirmed objectives and sales logic from sp_rpt_sale_objective_v2  */
    begin
set nocount on
declare @sproc varchar(100) = OBJECT_NAME(@@procid),
    @start_time smalldatetime = GETDATE(),
    @user_id varchar(100),
    @report_id smallint,
    @geo_type_id smallint,
    @geo_value varchar(10),
    @date_type_id int,
    @ytd_date1 varchar(6),
    @ytd_date2 varchar(6),
    @geo_filter varchar(200),
    @geo_col varchar(50),
    @geo_join_sale varchar(500),
    @sale_filter varchar(200),
    @uid varchar(40),
    @t_sales varchar(100),
    @sql varchar(max) -- ── parse parms ───────────────────────────────────────────────────────      set @user_id      = @parms.value('/parms[1]/user_id[1]',     'varchar(100)')      set @report_id    = @parms.value('/parms[1]/report_id[1]',   'int')      set @geo_type_id  = @parms.value('/parms[1]/geo_type_id[1]', 'smallint')      set @geo_value    = @parms.value('/parms[1]/geo_value[1]',   'varchar(10)')      set @date_type_id = @parms.value('/parms[1]/date_type_id[1]','int')        -- force non-Mega retail      if @parms.exist('/parms[1]/mega_id') = 0          set @parms.modify('insert <mega_id>1</mega_id> into /parms[1]')        -- ── YTD dates ─────────────────────────────────────────────────────────      select          @ytd_date1 = cast(start_date_id as varchar(6)),          @ytd_date2 = cast(end_date_id   as varchar(6))      from dim_year      where entity_id     = 0        and date_year_id  = @date_type_id        -- ── geo / sale filter ─────────────────────────────────────────────────      select          @geo_join_sale = geo_join,          @geo_filter    = geo_filter,          @geo_col       = geo_col      from dbo.fn_get_geo_parts('fact_sale', @geo_type_id, @geo_value, 0)        set @sale_filter = dbo.fn_get_sale_filter(@parms)        -- prefix geo_filter for geo_geo alias      if @geo_filter <> '1=1'          set @geo_filter = 'b.' + @geo_filter        -- ── unique temp table ─────────────────────────────────────────────────      set @uid     = replace(convert(varchar(36), newid()), '-', '')      set @t_sales = '##sales_obj_' + @uid        -- ════════════════════════════════════════════════════════════════════      -- YTD retail sales (local + pump-out combined = total retail)      -- Scoped to dealer via geo_geo exists check      -- ════════════════════════════════════════════════════════════════════      set @sql = '      select          case a.class_id when 2 then ''F-Series'' else ''N-Series'' end  as series,          sum(a.units)                                                    as sales      into ' + @t_sales + '      from vw_fact_sale_geo a      where a.date_id  between ' + @ytd_date1 + ' and ' + @ytd_date2 + '        and a.class_id in (1, 2)        and ' + @sale_filter + '        and exists (            select 1 from geo_geo b            where b.location_id = a.location_id              and ' + @geo_filter + '        )      group by          case a.class_id when 2 then ''F-Series'' else ''N-Series'' end      '      exec sp_utl_exec @sql, @debug        -- ════════════════════════════════════════════════════════════════════      -- Final output: join sales to objectives, add Total row      -- Objectives = full-year (local obj + pumpout obj) from dim_location_metric      -- ════════════════════════════════════════════════════════════════════      set @sql = '      select          s.series,          isnull(s.sales,  0)                                             as sales,          case s.series              when ''N-Series'' then isnull(m.n_local_obj, 0) + isnull(m.n_pumpout_obj, 0)              when ''F-Series'' then isnull(m.f_local_obj, 0) + isnull(m.f_pumpout_obj, 0)              else 0          end                                                             as objective,          case              when (case s.series                        when ''N-Series'' then isnull(m.n_local_obj, 0) + isnull(m.n_pumpout_obj, 0)                        when ''F-Series'' then isnull(m.f_local_obj, 0) + isnull(m.f_pumpout_obj, 0)                        else 0                    end) > 0              then cast(isnull(s.sales, 0) as decimal(10,4))                 / (case s.series                        when ''N-Series'' then isnull(m.n_local_obj, 0) + isnull(m.n_pumpout_obj, 0)                        when ''F-Series'' then isnull(m.f_local_obj, 0) + isnull(m.f_pumpout_obj, 0)                        else 0                    end)              else null          end                                                             as pct_achieved      from ' + @t_sales + ' s      cross join ICTA_IDEAS_App.dbo.dim_location_metric m      where m.location_id = ' + @geo_value + '        union all        -- Total row      select          ''Total''                                                        as series,          isnull(sum(s.sales), 0)                                         as sales,          isnull(m.n_local_obj,   0) + isnull(m.n_pumpout_obj, 0)        + isnull(m.f_local_obj,   0) + isnull(m.f_pumpout_obj, 0)        as objective,          case              when isnull(m.n_local_obj,   0) + isnull(m.n_pumpout_obj, 0)                 + isnull(m.f_local_obj,   0) + isnull(m.f_pumpout_obj, 0) > 0              then cast(isnull(sum(s.sales), 0) as decimal(10,4))                 / (isnull(m.n_local_obj,   0) + isnull(m.n_pumpout_obj, 0)                  + isnull(m.f_local_obj,   0) + isnull(m.f_pumpout_obj, 0))              else null          end                                                             as pct_achieved      from ' + @t_sales + ' s      cross join ICTA_IDEAS_App.dbo.dim_location_metric m      where m.location_id = ' + @geo_value + '      group by          m.n_local_obj, m.n_pumpout_obj,          m.f_local_obj, m.f_pumpout_obj      '        set @sql = 'select * from (' + @sql + ') x      order by case series when ''N-Series'' then 1 when ''F-Series'' then 2 else 3 end'        exec sp_utl_exec @sql, @debug        -- ── cleanup ───────────────────────────────────────────────────────────      exec sp_utl_drop_table @t_sales        if (@debug = 'n')          insert into app_usage(user_id, sproc, parms, start_time, end_time)          values(@user_id, @sproc, @parms, @start_time, GETDATE())    end  return 0
    sp_rpt_dcn_vehicleinfo_overview SQL_STORED_PROCEDURE CREATE procedure [dbo].[sp_rpt_dcn_vehicleinfo_overview] @parms xml = null,
    @debug char(1) = 'n' as
    /*  Purpose:    Notes:    History:  2023-11-20 DD initial development.  2024-10-15 AW Modified to use tables from database [ICTA_IDEAS_DWX]      set @whlsale = '[ICTA_IDEAS_DWX].[dbo].[sales_whl_by_vin]'      set @rtlsale = '[ICTA_IDEAS_DWX].[dbo].[sales_rtl_by_vin]'      set @Inventory = '[ICTA_IDEAS_DWX].[dbo].[sales_inventory_by_vin]'      set @on_order = '[ICTA_IDEAS_DWX].[dbo].[sales_ord_by_vin]'  20250130 DD added date filters to all incoming data (This is to help the Dashboard handle different years/date filters)  2025-02-10 AW Modified to include dummy sales type when data is not yet available  */
