ies like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end) ''series''   , COUNT(*) AS ''units''  FROM '+@whlsale+'  where '+@dealer_filter+' and '+@date_filter+'  GROUP BY dealer, (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end)   union  select   dealer   , (''Retail'') ''type sale''   , (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end) ''series''   , sum(cast([quantity] as int)) AS ''units''  FROM '+@rtlsale+'  where '+@dealer_filter+' and '+@date_filter+'  GROUP BY dealer, (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end)   union  select   dealer   , (''Inventory'') ''type sale''   , (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end) ''series''    , sum(cast(quantity as int)) AS ''units''   from '+@Inventory+'  where '+@dealer_filter+' and '+@date_filter+'  group by dealer   , (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end)   union   SELECT dealer   , (''Orders'') ''type sale''   , (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end) ''series''   , sum(cast([quantity] as int)) AS ''units''  FROM '+@on_order+'  WHERE  '+@dealer_filter+' and '+@date_filter+'  GROUP BY dealer, (case when left(series, 1) = ''N'' and series like ''%gas%''  then ''N-Gas''     when left(series, 1) = ''N'' and series like ''%ev%''  then ''N-EV''     when left(series, 1) = ''F'' then ''F-Series''     when left(series, 1) = ''N'' then ''N-Diesel''     else ''Unassigned''     end)   ) x  '  */    set @sql =  '  WITH [wholesale] AS (      SELECT           dealer,          ''Wholesale'' AS [type sale],          CASE               WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''              WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''              WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''              WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''              ELSE ''Unassigned''          END AS [series],          COUNT(*) AS [units]      FROM '+@whlsale+'   where '+@dealer_filter+' and '+@date_filter+'      GROUP BY dealer,                CASE                    WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''                   WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''                   WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''                   WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''                   ELSE ''Unassigned''               END  ),  [retail] AS (      SELECT           dealer,          ''Retail'' AS [type sale],          CASE               WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''              WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''              WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''              WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''              ELSE ''Unassigned''          END AS [series],          SUM(CAST([quantity] AS INT)) AS [units]      FROM '+@rtlsale+'   where '+@dealer_filter+' and '+@date_filter+'      GROUP BY dealer,                CASE                    WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''                   WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''                   WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''                   WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''                   ELSE ''Unassigned''               END  ),  [inventory] AS (      SELECT           dealer,          ''Inventory'' AS [type sale],          CASE               WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''              WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''              WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''              WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''              ELSE ''Unassigned''          END AS [series],          SUM(CAST(quantity AS INT)) AS [units]      from '+@Inventory+'   where '+@dealer_filter+' and date_id = (select max(date_id) from '+@inventory+' where date_id between '''+@date1+''' and '''+@date2+''')      GROUP BY dealer,                CASE                    WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''                   WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''                   WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''                   WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''                   ELSE ''Unassigned''               END  ),  [orders] AS (      SELECT           dealer,          ''Orders'' AS [type sale],          CASE               WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''              WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''              WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''              WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''              ELSE ''Unassigned''          END AS [series],          SUM(CAST([quantity] AS INT)) AS [units]      FROM '+@on_order+'   WHERE  '+@dealer_filter+' and date_id = (select max(date_id) from '+@on_order+' where date_id between '''+@date1+''' and '''+@date2+''')      GROUP BY dealer,                CASE                    WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%gas%'' THEN ''N-Gas''                   WHEN LEFT(series, 1) = ''N'' AND series LIKE ''%ev%'' THEN ''N-EV''                   WHEN LEFT(series, 1) = ''F'' THEN ''F-Series''                   WHEN LEFT(series, 1) = ''N'' THEN ''N-Diesel''                   ELSE ''Unassigned''               END  ),  combined AS (      SELECT * FROM wholesale      UNION ALL      SELECT * FROM retail      UNION ALL      SELECT * FROM inventory      UNION ALL      SELECT * FROM orders  )    SELECT * FROM combined    UNION ALL    -- Add a dummy row for each missing "type sale"  SELECT '''+@location_code+''' AS dealer, ''Wholesale'' AS [type sale], ''F-Series'' AS [series], 0 AS [units]  WHERE NOT EXISTS (SELECT 1 FROM [wholesale])    UNION ALL    SELECT '''+@location_code+''' AS dealer, ''Retail'' AS [type sale], ''F-Series'' AS [series], 0 AS [units]  WHERE NOT EXISTS (SELECT 1 FROM [retail])    UNION ALL    SELECT '''+@location_code+''' AS dealer, ''Inventory'' AS [type sale], ''F-Series'' AS [series], 0 AS [units]  WHERE NOT EXISTS (SELECT 1 FROM [inventory])    UNION ALL    SELECT '''+@location_code+''' AS dealer, ''Orders'' AS [type sale], ''F-Series'' AS [series], 0 AS [units]  WHERE NOT EXISTS (SELECT 1 FROM [orders]);  '    exec sp_utl_exec @sql, @debug    if (@debug = 'n')   insert into app_usage(user_id,sproc,parms,start_time,end_time)   values(@user_id,@sproc,@parms,@start_time,@end_time)  end    return 0    --test parm  /*  exec sp_rpt_dcn_vehicleinfo_overview '<parms><report_id>716</report_id><geo_type_id>1</geo_type_id><geo_value>1615</geo_value><geo_title>Dealer = AKRON ISUZU TRUCKS (63331)</geo_title><date_type_id>11</date_type_id><time_title>Time = 2025YTD</time_title><request_id>1739559597953</request_id><_>1739559594842</_><user_id>ddaniel@sextantusa.com</user_id></parms>','n'  */  
